-- Poems batch 245
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('bfc5dc7a-870e-4885-9ea2-758d42431ba2','真青麻頭','賈似道','宋','宋诗','song-poetry','','[]','線項麻頭紋理明，蜻蜓頭翅項渾青。',32,'全唐诗/poet.song.221000.json','["線項麻頭紋理明，蜻蜓頭翅項渾青。", "側生身分高而厚，鬭著交鋒速便贏。"]'),
('473cc91c-bd59-49e5-b08c-04b69ce826bd','白麻頭','賈似道','宋','宋诗','song-poetry','','[]','黄色輝光耀似金，棗紅牙齒利如針。',32,'全唐诗/poet.song.221000.json','["黄色輝光耀似金，棗紅牙齒利如針。", "更有葡萄毛肉體，日交三度也還贏。"]'),
('91a81208-e998-436f-9dca-5d557b7f3fd5','白牙青','賈似道','宋','宋诗','song-poetry','','[]','紫頭銀線項青毛，銀牙白脚絕倫高。',32,'全唐诗/poet.song.221000.json','["紫頭銀線項青毛，銀牙白脚絕倫高。", "可柰秋風消索處，自然勇力不相饒。"]'),
('3ed0a9ab-2a0e-4415-a374-a416e9b34244','拖肚黄','賈似道','宋','宋诗','song-poetry','','[]','頭項焦黄身黑粗，更兼腿大及臀拖。',32,'全唐诗/poet.song.221000.json','["頭項焦黄身黑粗，更兼腿大及臀拖。", "若還牙齒尖而厚，日鬭數番也不多。"]'),
('7dc8a83f-f285-4a3a-aeb7-cbb47e90f8e6','紅頭','賈似道','宋','宋诗','song-poetry','','[]','紅如血點項硃砂，入手觀來一朵花。',32,'全唐诗/poet.song.221000.json','["紅如血點項硃砂，入手觀來一朵花。", "一朝二廣交鋒勝，到底終須不戀家。"]'),
('c6bfe763-7d14-4441-a4d1-9f9b7d9bb80e','真青','賈似道','宋','宋诗','song-poetry','','[]','青色頭如菩提子，項上毛青靛染成。',32,'全唐诗/poet.song.221000.json','["青色頭如菩提子，項上毛青靛染成。", "牙鈴更得芝麻白，任君儘鬭足歡情。"]'),
('15f8b4bf-ebac-4b7c-9a18-6154302e8c9b','紫青','賈似道','宋','宋诗','song-poetry','','[]','琥珀頭尖項紫青，翅如蘇葉肉還青。',32,'全唐诗/poet.song.221000.json','["琥珀頭尖項紫青，翅如蘇葉肉還青。", "天生一付牙紅紫，交鋒一口立黄金。"]'),
('834276e8-96ee-44fc-aa28-41b3abff1284','淡青','賈似道','宋','宋诗','song-poetry','','[]','淡青生來牙要紅，頭麻項闊翅玲瓏。',32,'全唐诗/poet.song.221000.json','["淡青生來牙要紅，頭麻項闊翅玲瓏。", "更生肉肚如雪白，贏盡秋蟲獨奏功。"]'),
('d91f3fad-513a-421e-a89f-d8505688a74a','黑青','賈似道','宋','宋诗','song-poetry','','[]','黑者須當黑似漆，仔細看來無別色。',32,'全唐诗/poet.song.221000.json','["黑者須當黑似漆，仔細看來無別色。", "更兼牙肚白如銀，名號將軍爲第一。"]'),
('2848c6be-a874-49bc-99da-bfa036556d21','蝦青','賈似道','宋','宋诗','song-poetry','','[]','麻頭青項翅如金，肉腿生來白似銀。',32,'全唐诗/poet.song.221000.json','["麻頭青項翅如金，肉腿生來白似銀。", "鉗更細長蘇木色，此蟲名號是蝦青。"]'),
('b26042b6-8b2d-4229-9904-ffa283829669','蟹青','賈似道','宋','宋诗','song-poetry','','[]','此蟲名稱湖蟹青，腿脚班黄翅不金。',32,'全唐诗/poet.song.221000.json','["此蟲名稱湖蟹青，腿脚班黄翅不金。", "不看牙鉗紅與白，須觀項上有毛丁。"]'),
('510a61b7-23d8-44bf-881d-2ca277f817d9','青麻','賈似道','宋','宋诗','song-poetry','','[]','麻頭青項有毛丁，翅縐肉白腿脚長。',32,'全唐诗/poet.song.221000.json','["麻頭青項有毛丁，翅縐肉白腿脚長。", "更生一付牙鉗黑，三秋得勝喜非常。"]'),
('fa7db261-4c6d-401c-b9c8-6d827a871fd7','青金翅','賈似道','宋','宋诗','song-poetry','','[]','麻頭青項翅如金，肉腿如同銀打成。',32,'全唐诗/poet.song.221000.json','["麻頭青項翅如金，肉腿如同銀打成。", "牙鉗更生如漆黑，贏盡諸人匣內金。"]'),
('105ed267-e23c-4abc-8ea0-5fec9d505a7e','真黄','賈似道','宋','宋诗','song-poetry','','[]','天生金色遍身黄，肉腿如同金箔裝。',32,'全唐诗/poet.song.221000.json','["天生金色遍身黄，肉腿如同金箔裝。", "更生一付烏牙齒，敵盡諸蟲不可當。"]'),
('2e838763-3a81-4274-9d78-c1c58021a78d','紅黄','賈似道','宋','宋诗','song-poetry','','[]','頭似珊瑚項班紅，翅如金箔肉带黄。',32,'全唐诗/poet.song.221000.json','["頭似珊瑚項班紅，翅如金箔肉带黄。", "腿脚𪢬長如玉色，秋蟲見了自慌張。"]'),
('cbaf0366-1fb4-4fa0-9626-b6102a65a4a6','紫黄','賈似道','宋','宋诗','song-poetry','','[]','頭似櫻珠項似金，肉脚如同金裹成。',32,'全唐诗/poet.song.221000.json','["頭似櫻珠項似金，肉脚如同金裹成。", "牙鉗不問何顔色，諸蟲咬著便昏沉。"]'),
('d54174e7-f072-423f-95bb-65fa22951e06','深黄','賈似道','宋','宋诗','song-poetry','','[]','黄者生來金箔黄，腿脚班黄腰𪢬長。',32,'全唐诗/poet.song.221000.json','["黄者生來金箔黄，腿脚班黄腰𪢬長。", "若生一付烏牙齒，三秋饒大莫商量。"]'),
('70723034-73cd-4773-9580-fbe31345af32','淡黄','賈似道','宋','宋诗','song-poetry','','[]','淡黄生來腿脚白，三樣頭尖如琥珀。',32,'全唐诗/poet.song.221000.json','["淡黄生來腿脚白，三樣頭尖如琥珀。", "初秋鬭間最迷癡，末後逢强絕口敵。"]'),
('663a8c3b-0261-4bbb-9301-bad037961b70','狗蠅黄','賈似道','宋','宋诗','song-poetry','','[]','麻頭黄項翅鋪金，腿脚班黄肉蜜色。',32,'全唐诗/poet.song.221000.json','["麻頭黄項翅鋪金，腿脚班黄肉蜜色。", "牙鉗若是黑如灰，敵盡場中爲第一。"]'),
('094c4b29-b1d8-4c01-a421-f1ef3bfdc0e9','真紫','賈似道','宋','宋诗','song-poetry','','[]','紫者如同著紫袍，頭濃剛性項如毛。',32,'全唐诗/poet.song.221000.json','["紫者如同著紫袍，頭濃剛性項如毛。", "鉗更細長如血色，獨占場中第一豪。"]'),
('87567c84-52a2-4aec-a658-b04b3de5de45','紅頭紫','賈似道','宋','宋诗','song-poetry','','[]','紅頭紫勇敵剛强，項赤紅班腿𪢬長。',32,'全唐诗/poet.song.221000.json','["紅頭紫勇敵剛强，項赤紅班腿𪢬長。", "翅紫牙灣如桑剪，此蟲名號促織王。"]'),
('5c91326a-bdea-4088-ad95-f314d76e5228','純紅','賈似道','宋','宋诗','song-poetry','','[]','眼如椒核遍身紅，尾項如硃腿亦同。',32,'全唐诗/poet.song.221000.json','["眼如椒核遍身紅，尾項如硃腿亦同。", "若逢敵手君休怕，數番咬死又成功。"]'),
('c0e22f9e-8237-420b-987b-b3b9d4743682','深紫','賈似道','宋','宋诗','song-poetry','','[]','紫者當頭要紫濃，更兼翅脇與身同。',32,'全唐诗/poet.song.221000.json','["紫者當頭要紫濃，更兼翅脇與身同。", "頭紅項闊陰陽翅，贏盡場中有大功。"]'),
('00e6879f-e8b3-4ff0-8e18-08e9697be800','黑紫','賈似道','宋','宋诗','song-poetry','','[]','黑紫生來似茄皮，腿脚兼黄赤肚皮。',32,'全唐诗/poet.song.221000.json','["黑紫生來似茄皮，腿脚兼黄赤肚皮。", "鉗若生來紫黑色，早秋贏到雪花飛。"]'),
('f7dc82a1-48e1-4ddd-bafb-afbf6528e2b7','淡紫','賈似道','宋','宋诗','song-poetry','','[]','名爲淡紫遍身明，項如青靛齒紫紅。',32,'全唐诗/poet.song.221000.json','["名爲淡紫遍身明，項如青靛齒紫紅。", "頭上三尖腰要闊，戰得場中不敢逢。"]'),
('f9ac41be-49ee-4b66-abd3-fa2b8b814613','紫麻','賈似道','宋','宋诗','song-poetry','','[]','頭麻項路透金絲，項毛翅縐腿班狸。',32,'全唐诗/poet.song.221000.json','["頭麻項路透金絲，項毛翅縐腿班狸。", "四脚兼黄肉带赤，秋蟲見影不相持。"]'),
('1621817d-b96f-49c7-af3c-4672923cb064','紫金翅','賈似道','宋','宋诗','song-poetry','','[]','紫頭青項翅如金，腿脚兼黄肉带蜜。',32,'全唐诗/poet.song.221000.json','["紫頭青項翅如金，腿脚兼黄肉带蜜。", "必須生有紫黑鉗，咬殺秋蟲人失色。"]'),
('7a94bf04-d6c9-49b2-aaed-2ab241f70cea','純白','賈似道','宋','宋诗','song-poetry','','[]','白頭白項白絲攢，翅似鋪銀肉似霜。',32,'全唐诗/poet.song.221000.json','["白頭白項白絲攢，翅似鋪銀肉似霜。", "烏牙黑臉肚如粉，此物正是促織王。"]'),
('faea9dad-6b84-4653-b63e-4c5e76cb702d','淡白','賈似道','宋','宋诗','song-poetry','','[]','白頭白項翅鋪銀，入手觀來却似冰。',32,'全唐诗/poet.song.221000.json','["白頭白項翅鋪銀，入手觀來却似冰。", "此蟲異衆稱奇白，總無顔色是將軍。"]'),
('82f0aeb6-a0b6-4650-91d2-84e079f72842','白麻頭','賈似道','宋','宋诗','song-poetry','','[]','麻頭白面白如銀，細絲透頂根根明。',32,'全唐诗/poet.song.221000.json','["麻頭白面白如銀，細絲透頂根根明。", "更加青項長肥腿，戰鬭之時必定贏。"]'),
('e7fc47f4-7d7e-4573-a1c0-7f025ff467c6','烏青','賈似道','宋','宋诗','song-poetry','','[]','烏青生來似定墨，腿脚班狸肉带黑。',32,'全唐诗/poet.song.221000.json','["烏青生來似定墨，腿脚班狸肉带黑。", "鉗若細長似血紅，合戰交鋒如霹靂。"]'),
('eb427370-762a-4abb-8adf-c1bb37f09c18','烏麻','賈似道','宋','宋诗','song-poetry','','[]','烏麻頭路透銀絲，項闊毛班肉带黑。',32,'全唐诗/poet.song.221000.json','["烏麻頭路透銀絲，項闊毛班肉带黑。", "更若翅烏牙鉗赤，得遇此蟲真有益。"]'),
('da5e8a0e-590d-41a4-9001-4796cebf5d4e','烏頭金翅','賈似道','宋','宋诗','song-poetry','','[]','烏頭青項翅金黄，腿脚班狸肉带蒼。',32,'全唐诗/poet.song.221000.json','["烏頭青項翅金黄，腿脚班狸肉带蒼。", "牙鉗更生烏紫色，諸蟲見了豈能當。"]'),
('af3dad1e-728a-4a0d-adf9-2765e679c3ae','紅麻頭','賈似道','宋','宋诗','song-poetry','','[]','紅麻秉性敵剛强，赤項紅班脚𪢬長。',32,'全唐诗/poet.song.221000.json','["紅麻秉性敵剛强，赤項紅班脚𪢬長。", "翅紫牙灣如桑剪，諸蟲交口便難當。"]'),
('d1d8366e-e3cb-4c29-80f0-d9b23d675fbe','黄麻頭','賈似道','宋','宋诗','song-poetry','','[]','麻頭黄項翅金色，腿脚班黄肉带蜜。',32,'全唐诗/poet.song.221000.json','["麻頭黄項翅金色，腿脚班黄肉带蜜。", "牙鉗若是炭樣烏，鬭勝叫鳴聞四壁。"]'),
('8b06e161-8db7-4a99-9de9-a16018ccee8e','紫麻頭','賈似道','宋','宋诗','song-poetry','','[]','麻頭項上透金絲，項毛翅縐腿班貍。',32,'全唐诗/poet.song.221000.json','["麻頭項上透金絲，項毛翅縐腿班貍。", "脚亦微黄肉带赤，秋蟲見了怎支持。"]'),
('4669753c-6ac9-4ca1-b7ee-890386c4cac3','烏麻頭','賈似道','宋','宋诗','song-poetry','','[]','烏麻頭路透銀絲，項闊毛臊肉带梨。',32,'全唐诗/poet.song.221000.json','["烏麻頭路透銀絲，項闊毛臊肉带梨。", "更若翅烏牙鉗赤，得遇此蟲真是奇。"]'),
('967bf0eb-8652-4d34-afd9-0a8c351f0ed3','錦簑衣','賈似道','宋','宋诗','song-poetry','','[]','翅寬翅急最爲低，識者當場便敢欺。',32,'全唐诗/poet.song.221000.json','["翅寬翅急最爲低，識者當場便敢欺。", "生得兩邊如鳥翅，名傳天下錦蓑衣。"]'),
('8aa3576b-036b-4159-a015-4c446e1fd61f','玉鋤頭','賈似道','宋','宋诗','song-poetry','','[]','黑牙黑面不堪收，此等蟲兒莫去求。',32,'全唐诗/poet.song.221000.json','["黑牙黑面不堪收，此等蟲兒莫去求。", "若得面肥頭脚大，杜家名號玉鋤頭。"]'),
('0788cb23-36ee-4ade-8252-d30eba3dfc5a','金束带','賈似道','宋','宋诗','song-poetry','','[]','十個紅鈴九個敗，脫却紅鈴休賭賽。',32,'全唐诗/poet.song.221000.json','["十個紅鈴九個敗，脫却紅鈴休賭賽。", "紅鈴若得滿腰生，常勝號爲金束带。"]'),
('f9cd980f-a78d-4c38-874f-42d17f7af1da','齊膂翅','賈似道','宋','宋诗','song-poetry','','[]','中秋齊膂最爲英，頭項寬舒翅皺文。',32,'全唐诗/poet.song.221000.json','["中秋齊膂最爲英，頭項寬舒翅皺文。", "敦厚牙長兼脚大，金風纔動不堪聞。"]'),
('1b60de74-68ec-4d63-b84a-8c6b13e19679','梅花翅  其一','賈似道','宋','宋诗','song-poetry','','[]','翅似梅花口似刀，番來覆去咬千交。',32,'全唐诗/poet.song.221000.json','["翅似梅花口似刀，番來覆去咬千交。", "總然贏得他每者，只好看盆無二遭。"]'),
('dd82d0e4-e26b-4f92-9227-384dfea000b8','梅花翅  其二','賈似道','宋','宋诗','song-poetry','','[]','翅似梅花蜘蛛形，身上如同梅花片。',32,'全唐诗/poet.song.221000.json','["翅似梅花蜘蛛形，身上如同梅花片。", "如此之蟲亦怪哉，滿場鬭勝真堪羨。"]'),
('e73bc760-c497-4fcf-b0c7-a3a8c2405bc4','琵琶翅  其一','賈似道','宋','宋诗','song-poetry','','[]','殻翅琵琶不用青，若還紫色也相應。',32,'全唐诗/poet.song.221000.json','["殻翅琵琶不用青，若還紫色也相應。", "要知鬭處關張勇，頭小牙長体似金。"]'),
('e16b4550-0568-4af8-9eff-b36d6dd00d15','琵琶翅  其二','賈似道','宋','宋诗','song-poetry','','[]','琵琶項上带銷金，又看鬚長六足明。',32,'全唐诗/poet.song.221000.json','["琵琶項上带銷金，又看鬚長六足明。", "若是黑青全沒用，腿長肉厚滿場贏。"]'),
('9638baed-52f1-4c9a-b977-4645a8ae2d45','琵琶翅  其三','賈似道','宋','宋诗','song-poetry','','[]','哂哂連叫兩三聲，此蟲便是竈雞形。',32,'全唐诗/poet.song.221000.json','["哂哂連叫兩三聲，此蟲便是竈雞形。", "玉腿白牙贏到底，黄牙項細是輸名。"]'),
('79862cd5-0d5d-44ea-987c-719fd23106b0','長衣','賈似道','宋','宋诗','song-poetry','','[]','長衣須養青金翅，腿脚玲瓏尾要齊。',32,'全唐诗/poet.song.221000.json','["長衣須養青金翅，腿脚玲瓏尾要齊。", "總然口似青鋒劍，只宜口快不宜遲。"]'),
('db9adfcf-9167-4f2b-a36e-4087d1aa40cb','噉色頭','賈似道','宋','宋诗','song-poetry','','[]','黑頭紅項背身跎，更兼大腿及捶拖。',32,'全唐诗/poet.song.221000.json','["黑頭紅項背身跎，更兼大腿及捶拖。", "牙齒赤紅如鉗樣，連贏數陣不爲多。"]'),
('c76620aa-2be4-4102-b882-7db721b0d436','青黄二色  其一','賈似道','宋','宋诗','song-poetry','','[]','黄頭青項銷金翅，二色俱全便爲最。',32,'全唐诗/poet.song.221000.json','["黄頭青項銷金翅，二色俱全便爲最。", "若還三件一齊生，鬭到秋深絕無對。"]'),
('c354ac4c-d45c-4c81-b845-a29c3d5eec8d','青黄二色  其二','賈似道','宋','宋诗','song-poetry','','[]','青黄二色翅項明，此等生來何處尋。',32,'全唐诗/poet.song.221000.json','["青黄二色翅項明，此等生來何處尋。", "初秋鬭到深秋後，百度交鋒百度贏。"]'),
('43fd3212-1946-4ec7-9612-e5a97e755a2d','油紙燈  其一','賈似道','宋','宋诗','song-poetry','','[]','頭圓腿壯遍身黄，翅滑如油肉带蒼。',32,'全唐诗/poet.song.221000.json','["頭圓腿壯遍身黄，翅滑如油肉带蒼。", "牙鉗一對如紅色，此物蟲中是霸王。"]'),
('e310aeb8-6b08-4b6a-aa73-ef643a9200bd','油紙燈  其二','賈似道','宋','宋诗','song-poetry','','[]','頭混腿脚一身黄，翅滑牙紅促織王。',32,'全唐诗/poet.song.221000.json','["頭混腿脚一身黄，翅滑牙紅促織王。", "易名叫做油莉撻，賭花管取滿頭裝。"]'),
('b2a60734-7443-41f7-a934-26d1128c6827','陰陽牙','賈似道','宋','宋诗','song-poetry','','[]','此蟲生來兩個牙，一紅一白實堪誇。',32,'全唐诗/poet.song.221000.json','["此蟲生來兩個牙，一紅一白實堪誇。", "不拘五色麻頭者，一見諸蟲不怕他。"]'),
('fd911247-c22b-4818-9940-8c198ff91a48','真三段','賈似道','宋','宋诗','song-poetry','','[]','紫頭青項有毛長，金翅生來肉带蒼。',32,'全唐诗/poet.song.221000.json','["紫頭青項有毛長，金翅生來肉带蒼。", "兩腿圓長班白色，紅牙一對沒人當。"]'),
('05b56cb0-8a33-4ee8-b5f3-c35d24e25108','草三段  其一','賈似道','宋','宋诗','song-poetry','','[]','麻頭青項白毛丁，金翅縐縐肉带青。',32,'全唐诗/poet.song.221000.json','["麻頭青項白毛丁，金翅縐縐肉带青。", "腿脚班黄牙似炭，當場健戰衆皆驚。"]'),
('c74020a3-c00b-4d83-bd39-15511af6007a','草三段  其二','賈似道','宋','宋诗','song-poetry','','[]','滿頭白粉紫葡萄，並無紋理項青毛。',32,'全唐诗/poet.song.221000.json','["滿頭白粉紫葡萄，並無紋理項青毛。", "更兼淡薄輕銀翅，三段之名亦似高。"]'),
('886a4058-62b4-466b-b8e8-3531b60293dd','三段錦','賈似道','宋','宋诗','song-poetry','','[]','麻頭青項翅銷金，体白牙長六足明。',32,'全唐诗/poet.song.221000.json','["麻頭青項翅銷金，体白牙長六足明。", "更有異常腰背闊，蜀川三段錦花名。"]'),
('00a4be2c-bcb8-487e-8c54-af0c526df82f','兩頭鎗','賈似道','宋','宋诗','song-poetry','','[]','鬚無尾短最堪傷，蟲大終須不是强。',32,'全唐诗/poet.song.221000.json','["鬚無尾短最堪傷，蟲大終須不是强。", "兩尾腿長還倒插，聞名盡說兩頭鎗。"]'),
('099649e2-677c-4ddc-a3bf-28595a35897e','綉花針','賈似道','宋','宋诗','song-poetry','','[]','小能敵大果然强，蟲小贏多必是良。',32,'全唐诗/poet.song.221000.json','["小能敵大果然强，蟲小贏多必是良。", "累勝上肩魁大者，這般蟲小也非常。"]'),
('27025b10-9f30-46f9-9ede-a887b509fd1b','紅頭額','賈似道','宋','宋诗','song-poetry','','[]','紅頭雖然似花枝，早秋雖勝未爲奇。',32,'全唐诗/poet.song.221000.json','["紅頭雖然似花枝，早秋雖勝未爲奇。", "再來得勝亦不可，勝少輸多何必疑。"]'),
('e80c049c-2f2d-45a6-b3ca-c4dd2755f20f','紅鈴月頭額','賈似道','宋','宋诗','song-poetry','','[]','蟲名月額及紅鈴，來往交鋒暫或贏。',32,'全唐诗/poet.song.221000.json','["蟲名月額及紅鈴，來往交鋒暫或贏。", "縱然得勝終難久，贏得錢來不可行。"]'),
('f1a7520c-db22-4025-8ba1-738b5ac9397a','香師{月肩}鈴','賈似道','宋','宋诗','song-poetry','','[]','香師紅額共{月肩}鈴，只好三番兩次贏。',35,'全唐诗/poet.song.221000.json','["香師紅額共{月肩}鈴，只好三番兩次贏。", "卸却紅鈴難保久，總然贏得也無情。"]'),
('579923bc-0499-4ccf-8aae-6405ba7f63b7','月頭線額','賈似道','宋','宋诗','song-poetry','','[]','線額空紋彩更良，月頭堪惜不久長。',32,'全唐诗/poet.song.221000.json','["線額空紋彩更良，月頭堪惜不久長。", "應是腿寒終不耐，柰何脚小便尋常。"]'),
('8b826f05-99f4-4515-ac68-93cc8527c68c','紅鈴  其一','賈似道','宋','宋诗','song-poetry','','[]','紅肩紅脇不爲奇，連連贏得也防虞。',32,'全唐诗/poet.song.221000.json','["紅肩紅脇不爲奇，連連贏得也防虞。", "今鈴落了終難復，無情去鬭却成灰。"]'),
('06be288c-a406-4fe3-b2ad-83b4f4b419b4','紅鈴  其二','賈似道','宋','宋诗','song-poetry','','[]','紅肩紅肋及紅鈴，止有三場兩次贏。',32,'全唐诗/poet.song.221000.json','["紅肩紅肋及紅鈴，止有三場兩次贏。", "脫下紅鈴休要鬭，總然贏得也無名。"]'),
('49241e41-4d66-4e89-a299-985fbfd1e9e7','闊翅','賈似道','宋','宋诗','song-poetry','','[]','闊翅之蟲識亦難，臀長匾薄也應凡。',32,'全唐诗/poet.song.221000.json','["闊翅之蟲識亦難，臀長匾薄也應凡。", "要知才貌青黄色，頭小牙長兩腿班。"]'),
('2aa32fde-5ad6-4c1f-a9f9-65ad688bd1b7','獨脚','賈似道','宋','宋诗','song-poetry','','[]','獨脚全憑綽菆功，助幫其拐可成功。',32,'全唐诗/poet.song.221000.json','["獨脚全憑綽菆功，助幫其拐可成功。", "切須休要饒他大，兩腿俱全力不同。"]'),
('2f985917-53a5-404b-9fd1-57f1ba7d718a','殘疾','賈似道','宋','宋诗','song-poetry','','[]','不問青黄赤白黑，不拘大小與殘疾。',32,'全唐诗/poet.song.221000.json','["不問青黄赤白黑，不拘大小與殘疾。", "禿鬚禿尾小無爪，此物見之不足惜。"]'),
('52fb9524-edf7-49bd-8cae-f273247487eb','呆物  其一','賈似道','宋','宋诗','song-poetry','','[]','定知黑白全無用，須信青黄不可欺。',32,'全唐诗/poet.song.221000.json','["定知黑白全無用，須信青黄不可欺。", "若是狹長終有失，身形厚闊最迷癡。"]'),
('e85a65e5-8791-4dfa-a2fe-3df74098a7a0','呆物  其二','賈似道','宋','宋诗','song-poetry','','[]','頭昏項緊有何奇，腿脚花班黑肚皮。',32,'全唐诗/poet.song.221000.json','["頭昏項緊有何奇，腿脚花班黑肚皮。", "翅上更有膏藥積，只好將來去餵雞。"]'),
('da4a9fbe-cb8c-4258-8035-524fb3422bea','呆物  其三','賈似道','宋','宋诗','song-poetry','','[]','飛蟲能鬭體輕盈，拔翅成瘡鬭負疼。',32,'全唐诗/poet.song.221000.json','["飛蟲能鬭體輕盈，拔翅成瘡鬭負疼。", "可用剪刀裁內翅，自然百戰百番贏。"]'),
('2bdf7917-e64f-4ecb-bc0f-d86d22234772','促織論賦','賈似道','宋','宋诗','song-poetry','','[]','促織鬭時人要主，貪財饒大蟲辛苦。',32,'全唐诗/poet.song.221000.json','["促織鬭時人要主，貪財饒大蟲辛苦。", "總然贏得已著傷，當場必悞下鋒主。"]'),
('f6ec1e31-255a-42f3-9edb-3bc2a8280284','養法十二條  其一','賈似道','宋','宋诗','song-poetry','','[]','盆須用古不須新，盆熱天炎色要昏。',32,'全唐诗/poet.song.221000.json','["盆須用古不須新，盆熱天炎色要昏。", "養過重陽九月九，舊盆不用換新盆。"]'),
('a6608f1b-f664-4202-841d-89b62e6185e9','養法十二條  其二','賈似道','宋','宋诗','song-poetry','','[]','養到天寒霜降時，附子煎湯冷浴伊。',32,'全唐诗/poet.song.221000.json','["養到天寒霜降時，附子煎湯冷浴伊。", "常把盆中圍得密，此時方用水窩兒。"]'),
('c1751151-3c2f-4c88-a723-521c48837b4e','養法十二條  其三','賈似道','宋','宋诗','song-poetry','','[]','下食須當過日中，若還不准是場空。',32,'全唐诗/poet.song.221000.json','["下食須當過日中，若還不准是場空。", "水清無要如冰冷，須要安些蜀地銅。"]'),
('029a7bae-6477-4bf1-a797-9ec88bec5c5c','養法十二條  其四','賈似道','宋','宋诗','song-poetry','','[]','喂食還須只一件，莫信傍人教你換。',32,'全唐诗/poet.song.221000.json','["喂食還須只一件，莫信傍人教你換。", "雞荳菱肉盡非宜，不及朝朝黄米飯。"]'),
('a4d476ce-43a8-4e8b-b10c-eae07de3792b','配合  其一','賈似道','宋','宋诗','song-poetry','','[]','呼雌之法與君知，不貼之時便換雌。',32,'全唐诗/poet.song.221000.json','["呼雌之法與君知，不貼之時便換雌。", "一個不貼又一個，若還呼久太非宜。"]'),
('75fac202-446a-441e-890e-c61b9ee6e789','配合  其二','賈似道','宋','宋诗','song-poetry','','[]','蛩聲不發莫添雙，呼叫連綿情性狂。',32,'全唐诗/poet.song.221000.json','["蛩聲不發莫添雙，呼叫連綿情性狂。", "三尾黑頭須是小，剪鬚去爪正相當。"]'),
('3ff0e17b-7145-49ff-af6e-a8f56ba8760e','禁忌','賈似道','宋','宋诗','song-poetry','','[]','硫黄橘氣最難當，煎藥須教莫近傍。',32,'全唐诗/poet.song.221000.json','["硫黄橘氣最難當，煎藥須教莫近傍。", "頓處常教遮得暗，切須休露太陽光。"]'),
('0a222ba6-80b5-4c12-ad22-72cba18a10d3','養胎','賈似道','宋','宋诗','song-poetry','','[]','蟲腹懷胎號産魔，落胎全仗水蝦婆。',32,'全唐诗/poet.song.221000.json','["蟲腹懷胎號産魔，落胎全仗水蝦婆。", "切須養辦心休急，鬭者之時敗者多。"]'),
('3e24a55b-c273-4469-8c2f-acfd803fb4b8','浴雌','賈似道','宋','宋诗','song-poetry','','[]','喂食三尾時時鈴，免使蟲兒咬失傷。',32,'全唐诗/poet.song.221000.json','["喂食三尾時時鈴，免使蟲兒咬失傷。", "常將三尾頻頻浴，解使呼雌有彩光。"]'),
('bb45f749-ad60-4c0e-88d4-d9230e39d617','防微','賈似道','宋','宋诗','song-poetry','','[]','朝晨出宿看蟲形，須交提出鬭盆聽。',32,'全唐诗/poet.song.221000.json','["朝晨出宿看蟲形，須交提出鬭盆聽。", "撚聒叫聲觀喜怒，蛩喜如同虎嘯聲。"]'),
('59eb8480-88be-4180-ae78-57d7f5f5f3ab','辨蟲老嫩','賈似道','宋','宋诗','song-poetry','','[]','要知促織與蒼雛，秘訣分明在兩鬚。',64,'全唐诗/poet.song.221000.json','["要知促織與蒼雛，秘訣分明在兩鬚。", "貼齒老黄生日久，懸牙如玉離泥初。", "頭高必定無心鬭，埋首人稱老野狐。", "有此秘方勞記取，十場罕有一場輸。"]'),
('9eba261e-9681-497f-87c6-6d52dd5b65d4','積食不消化訣','賈似道','宋','宋诗','song-poetry','','[]','積食不化甚堪嗟，水畔紅蟲是可佳。',32,'全唐诗/poet.song.221000.json','["積食不化甚堪嗟，水畔紅蟲是可佳。", "研細任君分兩處，喂畢鬭勝是誰家。"]'),
('292ff116-f259-4a26-9540-1a6d534d7611','鬬法八條其一','賈似道','宋','宋诗','song-poetry','','[]','比頭比項比身材，若大分毫便拆開。',32,'全唐诗/poet.song.221000.json','["比頭比項比身材，若大分毫便拆開。", "尾短更兼鬚又禿，强將他鬭不擔財。"]'),
('9e2908ba-a7e3-46f2-9bc7-0d5f882816a0','其二防敵','賈似道','宋','宋诗','song-poetry','','[]','左右不離常夾撁，臨鬭之時多少變。',32,'全唐诗/poet.song.221000.json','["左右不離常夾撁，臨鬭之時多少變。", "他若回身撁捍遮，踢着之時必傷面。"]'),
('b1cf9d40-c43c-4c7c-adc4-37519b172da9','其三擇撁','賈似道','宋','宋诗','song-poetry','','[]','撁頭要長捍要直，落撁不要如弩力。',64,'全唐诗/poet.song.221000.json','["撁頭要長捍要直，落撁不要如弩力。", "撁頭急落柵兒中，便是青天遭霹靂。", "把撁猶如人把舵，舵若橫時舟受禍。", "撁頭須取白露前，好撁就中金寶貨。"]'),
('5f11cda6-7a7b-42f7-ab62-972433aed8f1','其四接力','賈似道','宋','宋诗','song-poetry','','[]','五日方容鬭一場，若還頻鬭損牙關。',32,'全唐诗/poet.song.221000.json','["五日方容鬭一場，若還頻鬭損牙關。", "蟲兒不食因何事，蛟損牙關服食難。"]'),
('7c103077-85fc-4192-bfda-fcba2e07aad4','其五六不鬬法','賈似道','宋','宋诗','song-poetry','','[]','盪胲無後芡，不食又延籠。',24,'全唐诗/poet.song.221000.json','["盪胲無後芡，不食又延籠。", "嚙牙併煉齒，終須落下鋒。"]'),
('364afd8a-fa1b-46b3-ae18-682d7892a59b','其六審勢','賈似道','宋','宋诗','song-poetry','','[]','他若無情休要鬭，分鬭開時向面點。',32,'全唐诗/poet.song.221000.json','["他若無情休要鬭，分鬭開時向面點。", "你若頻撚必酸牙，焰頭過了形多變。"]'),
('304ae9d3-7619-4149-9dd6-6e6ac099c47e','其七惜才','賈似道','宋','宋诗','song-poetry','','[]','雄師百戰百番贏，不可交他出陣頻。',32,'全唐诗/poet.song.221000.json','["雄師百戰百番贏，不可交他出陣頻。", "身弱難禁生力對，一時托大悞蟲身。"]'),
('a8a99021-6383-4037-a4d3-91bdec0cc05a','其八鬬敗','賈似道','宋','宋诗','song-poetry','','[]','此番不比尋常敗，飽食泥盆待一旬。',32,'全唐诗/poet.song.221000.json','["此番不比尋常敗，飽食泥盆待一旬。", "臨日带饑將出鬭，依然還做上將軍。"]'),
('c6576e88-80e2-4ed7-85fa-3934fa2376e5','用三尾貼法歌','賈似道','宋','宋诗','song-poetry','','[]','蛩吟三尾莫添雙，呼叫連綿怕性狂。',64,'全唐诗/poet.song.221000.json','["蛩吟三尾莫添雙，呼叫連綿怕性狂。", "三尾黑頭須用小，尖頭獨脚始相當。", "喂交三尾時常飽，免致蟲吟悞損傷。", "更將三尾頻頻浴，解使雌雄有彩光。"]'),
('d430267e-07c3-4784-b1c1-b31029eb5b0f','總言  其一','賈似道','宋','宋诗','song-poetry','','[]','莫言促織正奇能，養者須當耐性情。',64,'全唐诗/poet.song.221000.json','["莫言促織正奇能，養者須當耐性情。", "只宜漫鬭無疎失，不可忙忙去鬭頻。", "交鋒一口停三日，大鬭須還隔一旬。", "不依此法隨心好，撞了齊肩必定傾。"]'),
('38f89b11-058d-44a9-9e94-797f72ebf1b1','總言  其二','賈似道','宋','宋诗','song-poetry','','[]','其中奧妙細談推，依此之中必作魁。',32,'全唐诗/poet.song.221000.json','["其中奧妙細談推，依此之中必作魁。", "三分之中曉得一，常常得勝带花回。"]'),
('451abef2-deb7-4a5f-9a55-87cd65913c72','總言  其三','賈似道','宋','宋诗','song-poetry','','[]','蟲性分悲喜，世人難得知。',48,'全唐诗/poet.song.221000.json','["蟲性分悲喜，世人難得知。", "嚼牙能鬭口，鼓翅得贏時。", "須識蠅頭撁，傍危則自知。", "總然蟲禁齒，如病遇良醫。"]'),
('ab8f3f82-592c-4e16-858a-5179bb8d3c79','題促織  其一','賈似道','宋','宋诗','song-poetry','','[]','玉繩低轉過南樓，人在冰壺夜色幽。',64,'全唐诗/poet.song.221000.json','["玉繩低轉過南樓，人在冰壺夜色幽。", "湛湛露華凉似洗，啾啾蛩韻巧如謳。", "絮叨高下恣情訴，斷續悠揚不肯休。", "叫徹五更尋隠處，自封門戶共雌儔。"]'),
('c6631833-550d-4c28-a1fe-a5bd2b6593b1','題促織  其二','賈似道','宋','宋诗','song-poetry','','[]','玉罐金籠喂養頻，王孫珍愛日相親。',64,'全唐诗/poet.song.221000.json','["玉罐金籠喂養頻，王孫珍愛日相親。", "爭雄肯負東君意，决勝寧辭一芥身。", "鼓翼有聲如唱凱，洗□□□□生嗔。", "大哉天地生群物，羨爾區區志不倫。"]'),
('983d3ead-4ff2-46d2-8812-893ab0cd28a0','梅花  其一','賈似道','宋','宋诗','song-poetry','','[]','朔風吹雨正塵埃，忽見江梅驛使來。',32,'全唐诗/poet.song.221000.json','["朔風吹雨正塵埃，忽見江梅驛使來。", "憶著家山石橋畔，一枝冷落爲誰開。"]'),
('08474082-afd7-499a-91cc-d4d44f88fa72','梅花  其二','賈似道','宋','宋诗','song-poetry','','[]','山北山南雪半消，村村店店酒旗招。',32,'全唐诗/poet.song.221000.json','["山北山南雪半消，村村店店酒旗招。", "春風過處人行少，一樹疏花傍小橋。"]'),
('512a070c-4e42-4cec-b91e-635c48c82f82','梅花  其三','賈似道','宋','宋诗','song-poetry','','[]','塵外冰姿世外心，宜晴宜雨更宜陰。',32,'全唐诗/poet.song.221000.json','["塵外冰姿世外心，宜晴宜雨更宜陰。", "收回疏影月初墜，約住寒香雪正深。"]'),
('13ea3890-b19d-4f1e-b4d9-731d7294225d','芍藥  其一','賈似道','宋','宋诗','song-poetry','','[]','又是揚州芍藥時，花應笑我賦歸遲。',64,'全唐诗/poet.song.221000.json','["又是揚州芍藥時，花應笑我賦歸遲。", "滿堂留得春如畫，對酒何妨鬢似絲。", "玉立黄塵那可到，錦圍紅蠟最相宜。", "買山若就當移種，此際誰能杖履隨。"]'),
('f825f84f-a890-4270-aa77-e7dbde16c1f1','芍藥  其二','賈似道','宋','宋诗','song-poetry','','[]','溫溫玉立綠陰中，不犯芳菲逐萬紅。',64,'全唐诗/poet.song.221000.json','["溫溫玉立綠陰中，不犯芳菲逐萬紅。", "折盡長淮多暇日，簪聯四座足春風。", "應如慶曆梅花瑞，况有昌黎屬句工。", "問得君王乞身去，移根栽傍曲欄東。"]'),
('4b0061e1-e55f-4bdd-8e8e-db84e27cad67','芍藥  其三','賈似道','宋','宋诗','song-poetry','','[]','上了甘泉三捷書，長淮萬里一塵無。',64,'全唐诗/poet.song.221000.json','["上了甘泉三捷書，長淮萬里一塵無。", "清和時節如春在，紅藥精神與昔殊。", "叢玉生香歌可譜，圍金有客瑞重圖。", "公堂且盡今朝醉，已問君王乞鑑湖。"]'),
('a91bcae2-3f59-4a10-bd00-532eb1da2e93','瓊花','賈似道','宋','宋诗','song-poetry','','[]','寂寂蕃釐觀裏花，伊誰封殖得名嘉。',64,'全唐诗/poet.song.221000.json','["寂寂蕃釐觀裏花，伊誰封殖得名嘉。", "應知天下無他本，惟有揚州是爾家。", "種雪春溫團影密，攢冰香重壓枝斜。", "倚闌莫問榮枯事，付與東風管物華。"]'),
('ea7e54e0-f94a-4c47-902b-1e5d8a82175e','草','賈似道','宋','宋诗','song-poetry','','[]','草木起寒色，望來秋更清。',48,'全唐诗/poet.song.221000.json','["草木起寒色，望來秋更清。", "舟橫遥夜月，風度隔城更。", "避俗心雖在，休官疏未行。", "空慚舊吟侶，有句續唐聲。"]'),
('57a43e65-aa71-4e59-bd59-cf22bef3e5be','天竺通元菴分韻得閒字','賈似道','宋','宋诗','song-poetry','','[]','十里高松樹，松邊屋數間。',48,'全唐诗/poet.song.221000.json','["十里高松樹，松邊屋數間。", "客同終夜話，心是一般閒。", "燈色難禁雨，秋聲不離山。", "明朝分手後，俗事不相關。"]'),
('beba4806-1988-4832-b1e7-93e116456b68','松','賈似道','宋','宋诗','song-poetry','','[]','城中得此觀，不用遠尋幽。',24,'全唐诗/poet.song.221000.json','["城中得此觀，不用遠尋幽。", "松影半壇月，竹色一簾秋。"]'),
('74df6096-402a-473f-a4cb-bfdbe5d1fb97','竹','賈似道','宋','宋诗','song-poetry','','[]','松陰半壇日，竹聲一檻秋。',24,'全唐诗/poet.song.221000.json','["松陰半壇日，竹聲一檻秋。", "每番看鶴過，疑似有仙遊。"]'),
('2f38fd2c-600a-4070-b578-6e91205891fd','楊柳','賈似道','宋','宋诗','song-poetry','','[]','燕子樓邊柳色新，畫眉人去鏡生塵。',32,'全唐诗/poet.song.221000.json','["燕子樓邊柳色新，畫眉人去鏡生塵。", "來年羞結空牀夢，閑撥琵琶過一春。"]'),
('75ef7187-d6fc-4a5b-bd1f-eefe1ab3850c','天台石橋','賈似道','宋','宋诗','song-poetry','','[]','古路行終日，僧房出翠微。',48,'全唐诗/poet.song.221000.json','["古路行終日，僧房出翠微。", "瀑爲煎茗水，雲是坐禪衣。", "尊者難相遇，遊人又獨歸。", "一猿橋外急，却是不忘機。"]'),
('fe70222b-dddb-4aaa-b279-eb45aa558444','歸葛嶺舊居','賈似道','宋','宋诗','song-poetry','','[]','罷官歸舊宅，山水得頻過。',48,'全唐诗/poet.song.221000.json','["罷官歸舊宅，山水得頻過。", "息影隄邊樹，清心湖面波。", "勞無功可紀，頑有命相磨。", "見說連朝雨，田家正翦禾。"]'),
('02da824e-ed08-4546-8ac4-6f241b5e3ffb','咸淳三年生日口號','賈似道','宋','宋诗','song-poetry','','[]','君恩猶使居湖曲，年未爲高奈病何。',32,'全唐诗/poet.song.221000.json','["君恩猶使居湖曲，年未爲高奈病何。", "做却潞公官職了，較來謝事不爭多。"]'),
('8e87c92b-bb99-4ec3-bf34-108eda47c043','孤山','賈似道','宋','宋诗','song-poetry','','[]','半是樓臺換却村，幾回獨立更銷魂。',32,'全唐诗/poet.song.221000.json','["半是樓臺換却村，幾回獨立更銷魂。", "斷隄野水梅花宅，千古春風月一痕。"]'),
('c8619a06-566a-4174-aa43-d5a2f403b863','贈孤山周道士','賈似道','宋','宋诗','song-poetry','','[]','梅花和靖宅，此處住來清。',48,'全唐诗/poet.song.221000.json','["梅花和靖宅，此處住來清。", "肯以詩爲事，終於世有名。", "山空丹鶴老，湖浄白鷗明。", "時亦扶筇出，何曾踏帝城。"]'),
('82d487d6-099b-4b36-be4f-2f9c4330348f','崇恩演福禪寺偈','賈似道','宋','宋诗','song-poetry','','[]','靈山一別幾經春，今日重來喜見君。',32,'全唐诗/poet.song.221000.json','["靈山一別幾經春，今日重來喜見君。", "佛法一肩擔荷却，黄鶴樓前第一尊。"]'),
('410e81fc-5102-4788-8b7a-0ac65e53ada7','天竺山行','賈似道','宋','宋诗','song-poetry','','[]','山北山南雪半消，村村店店酒旗招。',32,'全唐诗/poet.song.221000.json','["山北山南雪半消，村村店店酒旗招。", "春風過處人行少，一樹疏花傍小橋。"]'),
('6fe65023-7476-45b2-8f40-986b5f0762ee','於潛道中','賈似道','宋','宋诗','song-poetry','','[]','數家烟火深村裏，幾處牛羊落日中。',32,'全唐诗/poet.song.221000.json','["數家烟火深村裏，幾處牛羊落日中。", "客久不歸心事遠，梧桐葉葉是秋風。"]'),
('bfc4698d-5434-4f8e-8eac-62402cb19475','昌化道中','賈似道','宋','宋诗','song-poetry','','[]','西風落葉路漫漫，衣袂微生旦暮寒。',32,'全唐诗/poet.song.221000.json','["西風落葉路漫漫，衣袂微生旦暮寒。", "只隔片雲家便到，遠山移入夢中看。"]'),
('3b0959e2-a795-43ba-be7d-01b788ca6367','與友人會宿城中','賈似道','宋','宋诗','song-poetry','','[]','江湖相隔久，不料宿京城。',48,'全唐诗/poet.song.221000.json','["江湖相隔久，不料宿京城。", "終夜同談笑，對牀如弟兄。", "溼螢飛復落，殘燭滅還明。", "此去仍多事，重期未必成。"]'),
('9975e063-5ea2-466d-b3b3-cd533f5f3fbc','咸淳庚午冬大雪遺安撫潛侍郎  其一','賈似道','宋','宋诗','song-poetry','','[]','臘前又放玉園林，一片花飛一片心。',64,'全唐诗/poet.song.221000.json','["臘前又放玉園林，一片花飛一片心。", "瀌奕端由人所召，燮調多愧病難任。", "乾坤浩浩無偏處，田野穰穰更自今。", "但得諸賢成此樂，擢舟我欲去山陰。"]'),
('10a780e5-7048-4986-8c85-bb53bc00ca6b','咸淳庚午冬大雪遺安撫潛侍郎  其二','賈似道','宋','宋诗','song-poetry','','[]','玉立堂堂君子林，由來彥聖好於心。',64,'全唐诗/poet.song.221000.json','["玉立堂堂君子林，由來彥聖好於心。", "時和定是占書歲，賢居奚須更難任。", "上瑞以人誇自昔，太平有象適當今。", "莫令一片花飛却，留取春光到綠蔭。"]'),
('4ec1be60-8bb8-4c7d-b0e0-a544c92dc0ee','咸淳庚午冬大雪遺安撫潛侍郎  其三','賈似道','宋','宋诗','song-poetry','','[]','窮年枯坐似禪林，爲喜祥霙寫我心。',64,'全唐诗/poet.song.221000.json','["窮年枯坐似禪林，爲喜祥霙寫我心。", "歸去來兮懷靖節，不能者止愧周任。", "西園佳話從知舊，東國諸賢復見今。", "滿斛明珠逾美瑞，定應摹刻徧碑蔭。"]'),
('3e60a9a0-d586-4cf6-8c17-ce7adee219cd','甲戌寒食','賈似道','宋','宋诗','song-poetry','','[]','寒食家家插柳枝，留春春亦不多時。',32,'全唐诗/poet.song.221000.json','["寒食家家插柳枝，留春春亦不多時。", "人生有酒須當醉，青塚兒孫幾箇悲。"]'),
('dce6341a-c50b-4d7d-a238-1a11edb666ea','杜鵑','賈似道','宋','宋诗','song-poetry','','[]','一年一番聽，無事亦低眉。',48,'全唐诗/poet.song.221000.json','["一年一番聽，無事亦低眉。", "催得人歸去，由來自不知。", "春山穿翠靄，月樹滴燕脂。", "遺恨因亡國，流傳似可疑。"]'),
('d784b84b-9a26-46dc-839b-178889603bf8','句  其一','賈似道','宋','宋诗','song-poetry','','[]','浦浦風來趁藕花。',8,'全唐诗/poet.song.221000.json','["浦浦風來趁藕花。"]'),
('f50a25a2-bbc4-4426-a1cb-486f55f54e39','句  其二','賈似道','宋','宋诗','song-poetry','','[]','輕袂楊花落，遥裝燕子隨。',12,'全唐诗/poet.song.221000.json','["輕袂楊花落，遥裝燕子隨。"]'),
('b09b31e2-ad18-41cd-9c3c-d001936bd496','句  其三','賈似道','宋','宋诗','song-poetry','','[]','飛花落絮滿長安，飲盡離杯度渺漫。',16,'全唐诗/poet.song.221000.json','["飛花落絮滿長安，飲盡離杯度渺漫。"]'),
('f58fd62a-391b-4224-a888-6599403c7311','句  其四','賈似道','宋','宋诗','song-poetry','','[]','稻花香滿路，菰葉亂蒼洲。',12,'全唐诗/poet.song.221000.json','["稻花香滿路，菰葉亂蒼洲。"]'),
('af5b7d01-6c73-468e-9825-266503f3bcb2','句  其五','賈似道','宋','宋诗','song-poetry','','[]','梅花見處多留句，諫草藏來定得名。',16,'全唐诗/poet.song.221000.json','["梅花見處多留句，諫草藏來定得名。"]'),
('758c350c-0bcc-4cd2-a6d2-8c5395aeb06d','刺賈似道','太學生','宋','宋诗','song-poetry','','[]','昨夜江頭長碧波，滿船都載相公醝。',32,'全唐诗/poet.song.221000.json','["昨夜江頭長碧波，滿船都載相公醝。", "雖知要作調羹用，未必調羹用許多。"]'),
('92ca36c2-751e-4363-a393-7d87e07c3d7e','嘲賈似道','理宗朝士人','宋','宋诗','song-poetry','','[]','三分天下二分亡，猶把山川寸寸量。',32,'全唐诗/poet.song.221000.json','["三分天下二分亡，猶把山川寸寸量。", "縱使一丘添一畝，也應不似舊封疆。"]'),
('9cbecf2b-2afc-4b70-9b7b-1926e1bd4a04','可惜','丁開','宋','宋诗','song-poetry','','[]','日者今何及，天乎有不平。',48,'全唐诗/poet.song.221000.json','["日者今何及，天乎有不平。", "功高人共嫉，事定我當烹。", "父老俱嗚咽，天王本聖明。", "不愁罹黨禍，携淚向孤城。"]'),
('5b9d84c8-2707-407d-a846-3f751c3b327f','漂泊岳陽遇張中行因汎舟洞庭晚宿君山聯句','丁開','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','元氣無根株，地脈有斷絕。',264,'全唐诗/poet.song.221000.json','["元氣無根株，地脈有斷絕。", "日月互吞吐，雲霧自生滅。", "楚妃結幽想，巴客答清吷。", "寧知莽蒼中，不假巨鼇力。", "勢閲南紀浮，思隨西風發。", "形影寄孤舟，吾道成鴃舌。", "笑談正凌傲，俯仰不偪側。", "每與景物會，未省歡娛畢。", "疊翠晚愔愔，墮黄秋的的。", "魚龍負贔贔，獨鳥去不息。", "曠原眇周抱，異境超慌惚。", "徑度萬頃空，忽得一拳碧。", "稍稍雞犬近，依依鐘梵夕。", "推門月微墮，煮茗香初歇。", "衣裳識霜信，瓶鉢了禪悅。", "事定心源清，夢回斗柄直。", "周游興欲盡，長往計未决。", "出門更回首，沙水盪虛白。", "美哉神禹功，已矣三苗國。", "山川長不朽，愚智俱可惜。", "神交正冥冥，指點空歷歷。", "慎勿語俗人，桃源恐相失。"]'),
('a274f1b0-42c7-4f7b-b526-cac2bf599048','建業','丁開','宋','宋诗','song-poetry','','[]','誰遣淒涼滿眼中，蘋花渺渺又秋風。',64,'全唐诗/poet.song.221000.json','["誰遣淒涼滿眼中，蘋花渺渺又秋風。", "龍蹲虎踞江山大，馬去牛來社稷空。", "縱有千人惟諾諾，本無百歲更匆匆。", "乾坤顛倒孤舟在，聊復殘生伴釣翁。"]'),
('a9294ab1-2faf-4c32-b657-0d118dbdf4fc','揚州歲莫','丁開','宋','宋诗','song-poetry','','[]','萬國春回日，層成晚眺餘。',48,'全唐诗/poet.song.221000.json','["萬國春回日，層成晚眺餘。", "江聲隔吳楚，原色到邳徐。", "大閲軍容壯，狂歌客禮疎。", "百年寒荻裏，風雨憶吾廬。"]'),
('f6f34d35-4cac-4ff7-a041-2c92db39c1c0','漂泊岳陽汎舟洞庭晚宿君山與丁開聯句','張中行','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','無正文。',4,'全唐诗/poet.song.221000.json','["無正文。"]'),
('4bb4fe7f-1858-485c-b79b-47d441cafcee','江帆','汪涯','宋','宋诗','song-poetry','','[]','江帆去去可腸斷，千古萬古越王臺。',64,'全唐诗/poet.song.221000.json','["江帆去去可腸斷，千古萬古越王臺。", "埽空黄葉晚風定，飛盡碧天晴鳥回。", "半生無成坐筆硯，萬事不理問樽罍。", "年年看梅今白首，已矣英雄留七哀。"]'),
('8fd35494-1a1e-4ffe-88cd-1353f9db5ffc','采石獨酌','汪涯','宋','宋诗','song-poetry','','[]','欲落不落月在手，百年幾何持釣綸。',64,'全唐诗/poet.song.221000.json','["欲落不落月在手，百年幾何持釣綸。", "不知春色萬象表，綠煙漠漠入江濱。", "天翻地覆有今夕，酒熟詩溫無可人。", "向來談笑成黄土，墮淚未了雞司晨。"]'),
('9c2362ed-1b01-4e07-8791-1b8ddbd4d8d5','江行  其一','汪涯','宋','宋诗','song-poetry','','[]','江陵白魚如斫玉，掛席獨去風日寒。',32,'全唐诗/poet.song.221000.json','["江陵白魚如斫玉，掛席獨去風日寒。", "封題兩甕寄白髮，兒涯不是作魚官。"]'),
('538c76db-809b-471d-87bc-ba8b108029ef','江行  其二','汪涯','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','秋光蕩漾滿行色，鄰舟吹笛不堪聞。',32,'全唐诗/poet.song.221000.json','["秋光蕩漾滿行色，鄰舟吹笛不堪聞。", "洞庭濯足一樽酒，夫君不來空白雲。"]'),
('abe27103-20ae-4876-9d05-5e04def8e84c','南徐懷古呈吳履齋','曹𨙅','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','匹馬來逢塞草秋，淮雲一片隔神州。',64,'全唐诗/poet.song.221000.json','["匹馬來逢塞草秋，淮雲一片隔神州。", "黄昏燈火西津渡，白晝風煙北固樓。", "猶有斷碑和晉宋，誰將遺石問孫劉。", "天荒地老英雄盡，落日長江萬古愁。"]'),
('deb6f5e3-fa65-4c4c-b8ca-f30dfb68ef4f','寄豫章詩社諸君子','曹𨙅','宋','宋诗','song-poetry','','[]','向來心事劍能知，曾結仙人汗漫期。',64,'全唐诗/poet.song.221000.json','["向來心事劍能知，曾結仙人汗漫期。", "南浦看花春載酒，西園刻燭夜吟詩。", "凄凉風月隨殘夢，零落江湖似斷棋。", "千里洪崖秋水隔，暮雲無處說相思。"]'),
('c0a2faf4-64c5-42fb-9bf0-a89b58962b95','憩凉月觀焦山在望','曹𨙅','宋','宋诗','song-poetry','','[]','凉尋小徑坐，心與大江閑。',48,'全唐诗/poet.song.221000.json','["凉尋小徑坐，心與大江閑。", "素月鏡秋水，碧雲巾暮山。", "殘蟬移別樹，吠犬出幽關。", "近對焦仙洞，飛霞不可攀。"]'),
('c041f5b1-214e-4970-93fb-14a3a1391bb1','燈市','曹𨙅','宋','宋诗','song-poetry','','[]','春滿天街夜色酣，綺羅香結霧漫漫。',64,'全唐诗/poet.song.221000.json','["春滿天街夜色酣，綺羅香結霧漫漫。", "試燈簾幕深藏暖，掃雪樓臺淺带寒。", "寶騎驕嘶金騕褭，翠翹醉倚玉闌干。", "江雲忽斷笙歌散，幾點粧梅落舞鸞。"]'),
('ff7a650e-318d-4183-bb8b-62466b9b9f30','水陽精舍','曹𨙅','宋','宋诗','song-poetry','','[]','塔高鈴自語，碑斷蘇成文。',48,'全唐诗/poet.song.221000.json','["塔高鈴自語，碑斷蘇成文。", "老樹擎凉月，初荷卷濕雲。", "螢飛臨水見，犬吠隔籬聞。", "靜對高僧坐，無眠到夜分。"]'),
('1e990e4d-5df4-4e17-a16c-6e1d3a062b6d','午窗','曹𨙅','宋','宋诗','song-poetry','','[]','午窗破夢角巾斜，自滌銅鐺煮茗芽。',32,'全唐诗/poet.song.221000.json','["午窗破夢角巾斜，自滌銅鐺煮茗芽。", "滿院綠苔春色靜，冥冥細雨落桐花。"]'),
('2f5e8db0-1f0b-4baa-855d-e477d0ca1a12','瓊花','翁孟寅','宋','宋诗','song-poetry','','[]','春雲一片辭天隙，千年萬年不收拾。',120,'全唐诗/poet.song.221000.json','["春雲一片辭天隙，千年萬年不收拾。", "化作靈花滄海頭，猶對春風怨紅日。", "一從汙世塵，幾度□□腥。", "瓊瓊抱寸心，亂離常獨醒。", "我疑太白散餘烈，飛入花心白如雪。", "西北勁氣磨不盡，孤根屢枯還再結。", "地祇一笑萬蕊香，玄鶴不來空斷腸。", "陰雲上天白日暗，何時來看春風狂。"]'),
('234d219d-35cf-4c26-bd8c-ceb77ab7dfc1','夜泊','翁孟寅','宋','宋诗','song-poetry','','[]','夜泊寒沙際，江風起舊愁。',24,'全唐诗/poet.song.221000.json','["夜泊寒沙際，江風起舊愁。", "離情惟怕晚，歸夢又逢秋。"]'),
('bda83e77-53d8-496c-8b7b-d444d8b85756','和賈平章咸淳庚午冬大雪遺安撫潛侍郎詩','鮑度','宋','宋诗','song-poetry','','[]','一陶催發萬園林，平施工夫天地心。',64,'全唐诗/poet.song.221000.json','["一陶催發萬園林，平施工夫天地心。", "計出陳奇殲巨寇，盟推滕六長諸任。", "三登氣象先呈臘，一統封疆後視今。", "多謝玉龍擎重力，太平蓑笠好溪陰。"]'),
('1bea77b0-5b71-49cd-a1eb-03276beeceb2','賦湖中漁翁','蜀僧','宋','宋诗','song-poetry','','[]','籃裏無魚欠酒錢，酒家門外繫漁船。',32,'全唐诗/poet.song.221000.json','["籃裏無魚欠酒錢，酒家門外繫漁船。", "幾回欲脫蓑衣當，又恐明朝是雨天。"]'),
('1c74d4ac-a0e2-43e1-bae8-c8805114d504','石華表','徐宗斗','宋','宋诗','song-poetry','','[]','仙人窀穸古，山寂自崔嵬。',48,'全唐诗/poet.song.221000.json','["仙人窀穸古，山寂自崔嵬。", "一柱華天表，千年壯壑隈。", "春深青薜荔，雨足綠蒼苔。", "世遠空遺跡，令威何日回。"]'),
('9bcfe836-9c77-4577-8499-7ef696c2cefb','白髮','顧逢','宋','宋诗','song-poetry','','[]','一莖白一莖，兩鬢忽然更。',48,'全唐诗/poet.song.221000.json','["一莖白一莖，兩鬢忽然更。", "難把黄金買，從教青鏡明。", "染來還似舊，鑷去又重生。", "多少人無此，相看未可輕。"]'),
('012f9ec7-b52d-40aa-b935-3caf0e954bae','無心','顧逢','宋','宋诗','song-poetry','','[]','世態真堪笑，機深禍亦深。',48,'全唐诗/poet.song.221000.json','["世態真堪笑，機深禍亦深。", "多謀還損己，有壽必無心。", "嘔肺因詩苦，開懷遇酒斟。", "平生隨造物，不暇問升沉。"]'),
('acd4b4c3-5efe-41b8-b99b-e3ee2294b339','息心','顧逢','宋','宋诗','song-poetry','','[]','詩酒無窮樂，功名陌上塵。',48,'全唐诗/poet.song.221000.json','["詩酒無窮樂，功名陌上塵。", "息心長壽藥，瞑目後生身。", "白日一回夢，青山萬古春。", "不知天地裏，誰是悟空人。"]'),
('e7eb85df-b2c8-4a29-9751-7b1a46cd223f','勞心','顧逢','宋','宋诗','song-poetry','','[]','多少勞心者，青春已白髭。',48,'全唐诗/poet.song.221000.json','["多少勞心者，青春已白髭。", "百年皆醉日，一死是醒時。", "天地蜉蝣化，江湖杜宇悲。", "此身元自贅，况復有妻兒。"]'),
('1331d281-b105-4288-b18d-952307809c24','儒巾','顧逢','宋','宋诗','song-poetry','','[]','儒冠同昔日，吾道未嘗衰。',48,'全唐诗/poet.song.221000.json','["儒冠同昔日，吾道未嘗衰。", "畢竟猶存古，從教不入時。", "簪花何足遜，漉酒尚堪爲。", "懶把青銅照，傷心兩鬢絲。"]'),
('a3649482-b847-4a32-8e70-c5ef7fb2f431','謝人惠米','顧逢','宋','宋诗','song-poetry','','[]','今年俸米不曾收，五字田中自有秋。',32,'全唐诗/poet.song.221000.json','["今年俸米不曾收，五字田中自有秋。", "二十斛珠光燦爛，且無日糴太倉愁。"]'),
('e2e21e89-4046-4731-87df-68c1f1d8c2bf','謝徐容齋送米','顧逢','宋','宋诗','song-poetry','','[]','米囊入戶甑無塵，一室歡聲四壁春。',32,'全唐诗/poet.song.221000.json','["米囊入戶甑無塵，一室歡聲四壁春。", "高廩如山堆積者，肯思白髮老人詩。"]'),
('29666430-a1cf-4dfd-bc50-3e857abe6e10','竹石園堂酒邊即事','顧逢','宋','宋诗','song-poetry','','[]','到此須終日，相忘醉不成。',48,'全唐诗/poet.song.221000.json','["到此須終日，相忘醉不成。", "一天惟有月，萬籟絕無聲。", "魚口萍吞吐，螢光草晦明。", "夜闌重秉燭，猶對石棋枰。"]'),
('4125a8a3-5260-4ff9-ae7d-38b63d8ecd35','嚼菜根','顧逢','宋','宋诗','song-poetry','','[]','口體累人終不免，菜根能嚼樂無窮。',32,'全唐诗/poet.song.221000.json','["口體累人終不免，菜根能嚼樂無窮。", "吾儒食慣知真味，誰信猶便幾富翁。"]'),
('cb4deb5f-b7bb-41e6-bfb6-02068bd2aa49','謝葉誠齋金丹','顧逢','宋','宋诗','song-poetry','','[]','往歲因痰壅，幾爲病廢人。',48,'全唐诗/poet.song.221000.json','["往歲因痰壅，幾爲病廢人。", "金丹如不服，粉骨已成塵。", "去死僅一線，更生又五春。", "再深詩裏債，筆硯日相親。"]'),
('68787f6b-b68c-494f-8438-5e10269432f1','枕上懷盧進齋','顧逢','宋','宋诗','song-poetry','','[]','三載吳庠住，何由再合并。',48,'全唐诗/poet.song.221000.json','["三載吳庠住，何由再合并。", "老來情不捨，枕上夢頻成。", "撼樹風終夜，敲窗雨數聲。", "每思湖上酒，無日不同傾。"]'),
('e6d25d67-ab36-42db-8a47-a089cc436a39','雪夜懷趙存我碧瀾潛心三昆仲','顧逢','宋','宋诗','song-poetry','','[]','坐久冰生硯，無聊撚白髭。',48,'全唐诗/poet.song.221000.json','["坐久冰生硯，無聊撚白髭。", "友朋上心處，風雪打頭時。", "夜永孤燈共，天寒一雁知。", "兒童來膝下，撥火覓蹲鴟。"]'),
('674f4517-b408-4570-b1fc-be14bedc3b3c','病中懷鄧覺非','顧逢','宋','宋诗','song-poetry','','[]','卧病寂寥中，浮生悟得空。',48,'全唐诗/poet.song.221000.json','["卧病寂寥中，浮生悟得空。", "半床清夜月，一枕破窗風。", "旅思聞孤笛，秋聲過斷鴻。", "可人常入夢，簪盍幾時同。"]'),
('b937f50e-714a-4da3-9739-e9cedfd66aa6','月夜懷徐冰壑','顧逢','宋','宋诗','song-poetry','','[]','靜掩書齋對短檠，夜深風露逼人清。',32,'全唐诗/poet.song.221000.json','["靜掩書齋對短檠，夜深風露逼人清。", "遥思萬壑千山裏，猿正啼時月正明。"]'),
('861dadfa-7d96-4234-a83a-2c453201e69a','贈廣淳破衣  其一','顧逢','宋','宋诗','song-poetry','','[]','包笠皆爲累，遊方僅此身。',48,'全唐诗/poet.song.221000.json','["包笠皆爲累，遊方僅此身。", "從教粗褐碎，不用一絲紉。", "赴供無閑日，得錢回施人。", "生平甘忍辱，性地本來淳。"]'),
('3e053fdb-acf3-4e7a-b4fd-70abc2cc6fa2','贈廣淳破衣  其二','顧逢','宋','宋诗','song-poetry','','[]','禪外親文墨，年來更用情。',48,'全唐诗/poet.song.221000.json','["禪外親文墨，年來更用情。", "三椽趺坐後，徹曉讀書聲。", "破硯雨窗潤，孤燈雪屋明。", "更參諸大老，莫計萬山程。"]'),
('a53396bb-07a0-44b6-9992-0c9a891e86ab','贈僧足庵','顧逢','宋','宋诗','song-poetry','','[]','幽居不可尋，高卧白雲深。',48,'全唐诗/poet.song.221000.json','["幽居不可尋，高卧白雲深。", "舉眼皆貪者，何人有止心。", "三衣了冬夏，一鉢飽山林。", "此外無他事，聽松生綠陰。"]'),
('33688a70-54e9-403f-9728-19c8c6175d46','贈老僧','顧逢','宋','宋诗','song-poetry','','[]','衆僧尊夏臘，靈岳遍曾登。',48,'全唐诗/poet.song.221000.json','["衆僧尊夏臘，靈岳遍曾登。", "渡水手中杖，行山溪畔藤。", "心空默是印，眉白雪爲稜。", "自得巡方道，棲禪老未能。"]'),
('6553c112-de25-4355-8ea0-570b6055d3f7','贈僧','顧逢','宋','宋诗','song-poetry','','[]','繁華舉世皆如夢，今古何人肯暫閑。',32,'全唐诗/poet.song.221000.json','["繁華舉世皆如夢，今古何人肯暫閑。", "唯有東林學禪客，白頭閑坐對青山。"]'),
('3b8af092-4fb3-465c-adea-dd2480995d99','贈僧慶雲衲','顧逢','宋','宋诗','song-poetry','','[]','赴供歸來後，跏趺對篆熏。',48,'全唐诗/poet.song.221000.json','["赴供歸來後，跏趺對篆熏。", "三椽忘歲月，一衲老烟雲。", "俗客無門入，閑情有硯分。", "山中高卧好，城市正紛紜。"]'),
('759dfba5-7c22-41d3-9b4d-6c76c176e46e','贈白雲','顧逢','宋','宋诗','song-poetry','','[]','蒲團穿幾箇，性地忽然開。',48,'全唐诗/poet.song.221000.json','["蒲團穿幾箇，性地忽然開。", "禪向靜中透，詩從悟處來。", "三椽青嶂裏，一榻白雲堆。", "自說爲僧後，浮生百念灰。"]'),
('dac1af0d-0317-4af4-8254-c431c95fceed','贈四明月巖永昌上人','顧逢','宋','宋诗','song-poetry','','[]','杖錫遊方外，叢林歷幾春。',48,'全唐诗/poet.song.221000.json','["杖錫遊方外，叢林歷幾春。", "息心修道者，鐵脊坐禪人。", "泉落岩千丈，天空月一輪。", "眼前清境界，不識世間塵。"]'),
('bd209991-1db5-4438-942f-e2ab41753f61','贈靈殿僧道寧一洲上人','顧逢','宋','宋诗','song-poetry','','[]','高誼如師果是稀，寺中扶策病翁歸。',32,'全唐诗/poet.song.221000.json','["高誼如師果是稀，寺中扶策病翁歸。", "西風吹我肌生粟，便對西風解一衣。"]'),
('59093549-652b-4861-bbdd-de80f42eaeb8','贈不食姑','顧逢','宋','宋诗','song-poetry','','[]','絕粒非凡術，仙丹固得存。',48,'全唐诗/poet.song.221000.json','["絕粒非凡術，仙丹固得存。", "一龕常瞑目，長日不開門。", "浴水無冬夏，逢人少語言。", "飛來天際鶴，時見下庭軒。"]'),
('64f6bb9a-544a-4494-b894-b8af0d980e8a','贈護國寺山上宏道者','顧逢','宋','宋诗','song-poetry','','[]','三十年趺坐，何曾下此山。',48,'全唐诗/poet.song.221000.json','["三十年趺坐，何曾下此山。", "忘形超物外，無夢到人間。", "窗暗月來照，門開風自關。", "虎狼情亦狎，夜夜廟前還。"]'),
('5699831e-cabb-4115-a150-22d2662f4ade','贈葉肖巖','顧逢','宋','宋诗','song-poetry','','[]','筆底妙如神，傳來面目真。',48,'全唐诗/poet.song.221000.json','["筆底妙如神，傳來面目真。", "便教知本相，不必問何人。", "一幅元非畫，百年留此身。", "山林樵穫者，只是舊衣巾。"]'),
('9398fc82-ee6d-46cd-9d3c-c74ebf841c3f','贈筆工','顧逢','宋','宋诗','song-poetry','','[]','科場久廢不曾開，一掃千軍謾有才。',32,'全唐诗/poet.song.221000.json','["科場久廢不曾開，一掃千軍謾有才。", "今日毛錐無用處，功名不自此中來。"]'),
('7f0a2950-f007-4def-8657-b586a924767b','贈僧隆古  其一','顧逢','宋','宋诗','song-poetry','','[]','一峰峻碧入雲端，怪石蒼松耐歲寒。',32,'全唐诗/poet.song.221000.json','["一峰峻碧入雲端，怪石蒼松耐歲寒。", "天地奠形時便有，今人莫作等閑看。"]'),
('2fbf1da2-0444-4d17-a6ff-56a4be13fb6c','贈僧隆古  其二','顧逢','宋','宋诗','song-poetry','','[]','萬山深處斷人烟，溪水潺潺接澗泉。',32,'全唐诗/poet.song.221000.json','["萬山深處斷人烟，溪水潺潺接澗泉。", "白髮老僧陵上住，晉朝松在屋頭邊。"]'),
('555e296c-59d5-4a1d-9942-d25e9d33de7a','贈天台徐秋巖','顧逢','宋','宋诗','song-poetry','','[]','馬乳真堪摘，曾參日觀師。',48,'全唐诗/poet.song.221000.json','["馬乳真堪摘，曾參日觀師。", "雲隨筆落處，月上架來時。", "寫意元非畫，無聲只是詩。", "寒藤吹不動，顆顆自攢枝。"]'),
('491e75c8-95ed-47d4-89e2-d3f9dd876e8a','贈峽山胡半村','顧逢','宋','宋诗','song-poetry','','[]','四鄰雞犬地，花竹自我陰。',48,'全唐诗/poet.song.221000.json','["四鄰雞犬地，花竹自我陰。", "去郭不多遠，入山猶未深。", "林巒常在望，樵牧久知心。", "他日如全隠，深居不可尋。"]'),
('7397a235-dbaf-49ea-b504-6927c04b33ee','贈林東之','顧逢','宋','宋诗','song-poetry','','[]','往年曾赴召，萬里涉修途。',48,'全唐诗/poet.song.221000.json','["往年曾赴召，萬里涉修途。", "樂府師長吉，名家祖老逋。", "雲烟生筆硯，風月樂江湖。", "金殿朝天日，宮衣寵渥殊。"]'),
('6222f0c3-c331-4a2f-98a1-9f3175cc9c5d','贈薛野鶴子繼野','顧逢','宋','宋诗','song-poetry','','[]','老鶴傳遺韻，君詩儘可觀。',48,'全唐诗/poet.song.221000.json','["老鶴傳遺韻，君詩儘可觀。", "江湖爲客易，父子得名難。", "草色烟城暗，蛩聲秋寺寒。", "自言鄉僕至，束檐又長安。"]'),
('22d9cb14-8956-426b-bad8-7550adc81861','贈吾世衍','顧逢','宋','宋诗','song-poetry','','[]','士友多交接，惟君有敬心。',48,'全唐诗/poet.song.221000.json','["士友多交接，惟君有敬心。", "少年精古篆，諸老喜新吟。", "簫品神仙曲，琴彈山水音。", "無人知此樂，只有竹房深。"]'),
('b72c193b-16a6-48a1-aa3c-8c733d6ebec5','寄王巨卿御史','顧逢','宋','宋诗','song-poetry','','[]','雖然居憲府，只似在家時。',48,'全唐诗/poet.song.221000.json','["雖然居憲府，只似在家時。", "年老扶筇出，官清借馬騎。", "布袍安素分，白髮結相知。", "長日關門坐，彈琴與賦詩。"]'),
('425ca50f-0db2-44cf-9d1f-85a279523d0e','寄趙西皋先生','顧逢','宋','宋诗','song-poetry','','[]','居官但欲歸，每恨去官遲。',48,'全唐诗/poet.song.221000.json','["居官但欲歸，每恨去官遲。", "天下蒼生福，朝中宰相時。", "龍蛇三寸筆，風月百篇詩。", "此去除書至，難言以病辭。"]'),
('f0461ef3-aee3-4608-9899-8f4242631750','寄黄直齋別駕','顧逢','宋','宋诗','song-poetry','','[]','不道還吳去，知心有故人。',48,'全唐诗/poet.song.221000.json','["不道還吳去，知心有故人。", "殘燈時對榻，一室夜生春。", "天下襟懷士，詩家骨肉親。", "槐陰多第宅，誰肯納閑賓。"]'),
('b66f83b5-d942-4edd-b0a4-db5576c5286a','寄寧海詩社諸友','顧逢','宋','宋诗','song-poetry','','[]','舊有詩筒在，讀來醒睡魂。',48,'全唐诗/poet.song.221000.json','["舊有詩筒在，讀來醒睡魂。", "綠林多事後，白社幾家存。", "明月人千里，遠山雲一痕。", "書成無便寄，心事若爲論。"]'),
('4bb22a39-916e-4313-bbc5-50496f794bb5','寄韓簡齋老友','顧逢','宋','宋诗','song-poetry','','[]','曾問梅花開未開，擬扶短策步蒼苔。',32,'全唐诗/poet.song.221000.json','["曾問梅花開未開，擬扶短策步蒼苔。", "可憐雨雪飄零盡，不得花邊醉一回。"]'),
('5ba4cd1f-86a1-4704-b706-6abee3da3186','寄林石田老友','顧逢','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖惟二老，乍別更傷情。',48,'全唐诗/poet.song.221000.json','["西湖惟二老，乍別更傷情。", "詩與何人說，酒無知己傾。", "病軀添藥債，夜影對燈檠。", "喜有僧相訪，門前日送迎。"]'),
('4a115183-773f-494a-9b60-9f0302d03502','寄陳石窗林石田老友','顧逢','宋','宋诗','song-poetry','','[]','典刑惟二老，利祿等鴻毛。',48,'全唐诗/poet.song.221000.json','["典刑惟二老，利祿等鴻毛。", "士行貧中見，詩名犯後高。", "苦心親筆硯，冷眼看兒曹。", "肥馬輕裘輩，多應笑弊袍。"]'),
('d13c7883-d154-42ab-b159-8c1d109eb91c','寄徐雪江溫日觀老友','顧逢','宋','宋诗','song-poetry','','[]','詩畫琴三絕，乾坤只一身。',48,'全唐诗/poet.song.221000.json','["詩畫琴三絕，乾坤只一身。", "生前長聚首，死後更無人。", "材大身猶壽，名高分合貧。", "自憐傳五字，造物亦相嗔。"]'),
('16664f59-0f8e-4945-b3b4-06e8056e7636','寄徐雪江珦潛山老友','顧逢','宋','宋诗','song-poetry','','[]','雪江連雪巘，天目一般清。',48,'全唐诗/poet.song.221000.json','["雪江連雪巘，天目一般清。", "三老真希有，幾年能再生。", "琴中彈自譜，講外著詩聲。", "豈獨箋莊老，猶於翰墨精。"]'),
('88729bc6-6e59-4178-bc90-b7c7f52450df','寄四明干月庭厲二友','顧逢','宋','宋诗','song-poetry','','[]','無言獨倚樓，故人在心頭。',48,'全唐诗/poet.song.221000.json','["無言獨倚樓，故人在心頭。", "幾作宵中夢，多生別後愁。", "溪聲疏竹下，月色一庭秋。", "此景皆詩料，何時共唱酬。"]'),
('7ece0ce9-fe9f-43b9-9784-8fe7f29aaeb6','寄鄧山房高士','顧逢','宋','宋诗','song-poetry','','[]','老來骨相清如鶴，煉就紅爐一大丹。',32,'全唐诗/poet.song.221000.json','["老來骨相清如鶴，煉就紅爐一大丹。", "只把古琴藏石匣，子期仙去不曾彈。"]'),
('84667bfb-8e29-43ac-824b-4464d636cb6c','寄八十僧寶月溪','顧逢','宋','宋诗','song-poetry','','[]','同庚同志又同師，湖海無人是舊知。',32,'全唐诗/poet.song.221000.json','["同庚同志又同師，湖海無人是舊知。", "百念俱灰惟一癖，死爲鬼後亦吟詩。"]'),
('3e82fc15-103f-4bf5-81a0-98796bfa4816','寄僧珦潛山','顧逢','宋','宋诗','song-poetry','','[]','講道未凋零，猶堪續祖燈。',48,'全唐诗/poet.song.221000.json','["講道未凋零，猶堪續祖燈。", "誰知青嶂裏，自有白頭僧。", "老貌松根石，閑心月下冰。", "往來車馬者，應笑倚枯藤。"]'),
('dbcc0e6e-1fcb-4643-afdc-42ef8354a268','寄僧鍾山凈玨','顧逢','宋','宋诗','song-poetry','','[]','忘懷獨有師，每恨會時稀。',48,'全唐诗/poet.song.221000.json','["忘懷獨有師，每恨會時稀。", "作別不得見，相尋聞已歸。", "兩雞花下鬭，一蝶雨中飛。", "想在陳湖寺，紉衣掩竹扉。"]'),
('174ec97a-62bf-4ede-b0c2-bc96ca0550e4','寄宏叟恢上人','顧逢','宋','宋诗','song-poetry','','[]','留吳幾兩月，每見若親知。',48,'全唐诗/poet.song.221000.json','["留吳幾兩月，每見若親知。", "却恨臨行日，相尋不見師。", "黄花籬下酒，白髮坐中詩。", "別後頻思憶，書成欲寄誰。"]'),
('2fb0dc54-6b15-4725-bd7b-350082fcf889','寄白蓮寺隆虛岩','顧逢','宋','宋诗','song-poetry','','[]','人自菁山出，先須問老師。',48,'全唐诗/poet.song.221000.json','["人自菁山出，先須問老師。", "未痊張籍眼，不廢貫休詩。", "課佛輪珠滑，翻經破帽欹。", "幾年修浄業，喜近白蓮池。"]'),
('0dd0dbb7-63de-47fb-8fa6-162621623631','寄田潤齋道錄','顧逢','宋','宋诗','song-poetry','','[]','銳志休官去，皆緣道法靈。',48,'全唐诗/poet.song.221000.json','["銳志休官去，皆緣道法靈。", "一符方落筆，萬怪已潛形。", "柳下犬迎客，花邊鶴聽經。", "結交三十載，我醉獨君醒。"]'),
('b324a14d-3e91-448b-8e66-bf652249de6e','寄張山居隠君','顧逢','宋','宋诗','song-poetry','','[]','賣卜山中去，逃名竟不聞。',48,'全唐诗/poet.song.221000.json','["賣卜山中去，逃名竟不聞。", "始終全一節，今古少如君。", "撥火燒黄葉，枕書眠白雲。", "恨無薇可采，只食水中芹。"]'),
('5f36bc26-1274-4c15-bbd1-442ecff43160','寄蔣自庵','顧逢','宋','宋诗','song-poetry','','[]','破屋依蕭寺，僅能容此身。',48,'全唐诗/poet.song.221000.json','["破屋依蕭寺，僅能容此身。", "無心長自笑，一語不言貧。", "議論思諸老，交游擇好人。", "名門誰解識，帽破與衣鶉。"]'),
('530b8d70-6dc6-4cf9-b9e3-f0f7a4946821','寄俞半村','顧逢','宋','宋诗','song-poetry','','[]','他無事役心，祇是苦於吟。',48,'全唐诗/poet.song.221000.json','["他無事役心，祇是苦於吟。", "結屋能終隠，入山何必深。", "雨中看瀑布，月下聽松琴。", "有此幽居樂，須當一訪尋。"]'),
('75a2189b-8f97-4a41-b466-f29989f4d97f','寄韓梅居','顧逢','宋','宋诗','song-poetry','','[]','去載書來日，曾回一卷詩。',48,'全唐诗/poet.song.221000.json','["去載書來日，曾回一卷詩。", "每當孤坐處，長憶共吟時。", "春酒花朝曲，秋燈雨夜棋。", "人間無聚散，安得有相思。"]'),
('746dba17-f94a-4672-9b85-7269487050fd','寄損益川','顧逢','宋','宋诗','song-poetry','','[]','休已燈難續，相傳喜有師。',48,'全唐诗/poet.song.221000.json','["休已燈難續，相傳喜有師。", "好詩誰共語，妙趣自能知。", "步月頻看影，聽松無厭時。", "山中名已出，莫悔出山遲。"]'),
('e47a347b-95fb-4969-90e8-41fe37a84847','寄童梅巖','顧逢','宋','宋诗','song-poetry','','[]','數盡寒更六十點，鐘聲聽了又雞催。',32,'全唐诗/poet.song.221000.json','["數盡寒更六十點，鐘聲聽了又雞催。", "枕間展轉不得睡，底事故人猶未來。"]'),
('7e951086-116b-4bd5-8c84-d417d8a6d8cd','寄趙碧瀾  其一','顧逢','宋','宋诗','song-poetry','','[]','窗下看書坐，挑燈庭欲分。',48,'全唐诗/poet.song.221000.json','["窗下看書坐，挑燈庭欲分。", "秋聲鳴處遠，落葉靜中聞。", "庭月一方雪，爐香數朵雲。", "寄來詩在几，讀著又思君。"]'),
('55965706-63df-4170-a855-f14dda7f6b6e','寄趙碧瀾  其二','顧逢','宋','宋诗','song-poetry','','[]','琴詩山水樂，頓與世情疏。',48,'全唐诗/poet.song.221000.json','["琴詩山水樂，頓與世情疏。", "每到相思際，還看所寄書。", "春風肥野蕨，曉雨潤園蔬。", "此地能容我，同君一處居。"]'),
('d23dc225-bad7-497e-98c2-c70e20a9d705','寄趙碧瀾右之  其一','顧逢','宋','宋诗','song-poetry','','[]','二十年朋友，同吟五字詩。',48,'全唐诗/poet.song.221000.json','["二十年朋友，同吟五字詩。", "琴精毛敏仲，字逼晉羲之。", "多聽諸公說，堪爲後輩師。", "苕溪深隠好，不欲仕明時。"]'),
('c3bd9cee-c48f-481a-a5e5-d634d094ff5f','寄趙碧瀾右之  其二','顧逢','宋','宋诗','song-poetry','','[]','移家歸故第，只在霅溪邊。',48,'全唐诗/poet.song.221000.json','["移家歸故第，只在霅溪邊。", "舊別無旬日，今回恰數年。", "鶑花晴暖際，風雨晦冥天。", "總是思君處，孤吟每日憐。"]'),
('81347034-2844-4f3f-9339-bc44005a2a9f','寄盧梅岩','顧逢','宋','宋诗','song-poetry','','[]','梅邊燈下別，又見石榴開。',48,'全唐诗/poet.song.221000.json','["梅邊燈下別，又見石榴開。", "人入多番夢，書無一字來。", "背風花下落，衝雨燕雙回。", "却憶中秋夜，杯餘醉講臺。"]'),
('e1f364e1-b24c-452d-beb4-59da9257e45d','寄四明史雪汀','顧逢','宋','宋诗','song-poetry','','[]','每見江湖友，相逢說項斯。',48,'全唐诗/poet.song.221000.json','["每見江湖友，相逢說項斯。", "未能通去信，先得寄來詩。", "汀上雪晴日，山中梅放時。", "何當携手出，同謁老逋祠。"]'),
('6f8b77d8-a996-4e19-830a-b5fabd295d2d','寄四明趙秋汀','顧逢','宋','宋诗','song-poetry','','[]','作別踰三紀，飄蓬更陸沉。',48,'全唐诗/poet.song.221000.json','["作別踰三紀，飄蓬更陸沉。", "一汀秋夜月，千里故人心。", "有夢長如昔，無書直至今。", "傳聞辭祿後，教子老山林。"]'),
('7d214578-941d-4099-911c-06bc82255c5d','寄金華方養晦','顧逢','宋','宋诗','song-poetry','','[]','懶對青銅鏡，羞看兩鬢絲。',48,'全唐诗/poet.song.221000.json','["懶對青銅鏡，羞看兩鬢絲。", "自憐垂老日，多有未刊詩。", "短策山林裏，孤燈雨雪時。", "苦吟心欲嘔，讀著轉傷悲。"]'),
('a9c2a64a-951f-40fc-95c9-76194b77a4c0','寄申屠雪磯','顧逢','宋','宋诗','song-poetry','','[]','病起何由慰所思，幾回重讀寄來詩。',32,'全唐诗/poet.song.221000.json','["病起何由慰所思，幾回重讀寄來詩。", "定應閉戶敲推處，雪滿漁磯未必知。"]'),
('7db1f5df-ecc9-4778-b570-86a4a3362ef7','寄杜北山','顧逢','宋','宋诗','song-poetry','','[]','住與老逋鄰，空湖隔市塵。',48,'全唐诗/poet.song.221000.json','["住與老逋鄰，空湖隔市塵。", "布衣安破屋，白髮守清貧。", "引鶴風穿袖，聽猿月滿身。", "五言吟得苦，一字不投人。"]'),
('271428bc-17e6-4b8a-9c46-a0d84887f1b5','寄林平山','顧逢','宋','宋诗','song-poetry','','[]','登高先一日，扶病强相辭。',48,'全唐诗/poet.song.221000.json','["登高先一日，扶病强相辭。", "幾度懷君處，孤燈獨坐時。", "爐溫餘篆在，雞唱和聲隨。", "安得相同醉，狂歌別後詩。"]'),
('4095febb-62cc-418e-aa8d-c7f67193ac7a','寄光福老磻古溪','顧逢','宋','宋诗','song-poetry','','[]','藏一諸公相聚日，鬢毛尚黑齒牙堅。',32,'全唐诗/poet.song.221000.json','["藏一諸公相聚日，鬢毛尚黑齒牙堅。", "傷心流落江湖上，不見溪翁四十年。"]'),
('1cc15455-9800-42dd-a3e7-25f56f70be1f','寄王脩竹','顧逢','宋','宋诗','song-poetry','','[]','小樓分袂後，別久憶君多。',48,'全唐诗/poet.song.221000.json','["小樓分袂後，別久憶君多。", "逆境詩排遣，殘軀病折磨。", "靜聞花落几，閑看螘移窠。", "幾夜窗前夢，携筇竹下過。"]'),
('34a01ea5-5e57-4c46-b65b-f8a8938a6bd3','寄韓簡齋','顧逢','宋','宋诗','song-poetry','','[]','年來衰颯甚，傴僂較前增。',48,'全唐诗/poet.song.221000.json','["年來衰颯甚，傴僂較前增。", "顧影如枯木，梳頭似老僧。", "酒杯辭滿勸，山路怯先登。", "僅免愁風雨，歡顔得少陵。"]'),
('348da1d9-8bd7-45b8-81d8-75683179385f','寄盧進齋','顧逢','宋','宋诗','song-poetry','','[]','酒邊無日不團欒，獨冷齋中憶舊歡。',32,'全唐诗/poet.song.221000.json','["酒邊無日不團欒，獨冷齋中憶舊歡。", "窗外一株紅杏樹，三年不得與君看。"]'),
('00bd27ee-a82a-4f09-8f76-de04087d8409','寄集慶寺聞碧溪','顧逢','宋','宋诗','song-poetry','','[]','達者古來少，貪心竟莫醫。',48,'全唐诗/poet.song.221000.json','["達者古來少，貪心竟莫醫。", "塵中何了日，夢裏亦忙時。", "富貴人無足，膏肓病不知。", "黄金身外物，萬事且隨宜。"]'),
('27d322ed-727c-4bfb-8645-8fb2a8b7ca02','寄金壇湯進卿','顧逢','宋','宋诗','song-poetry','','[]','幾度野窗下，看君所寄詩。',48,'全唐诗/poet.song.221000.json','["幾度野窗下，看君所寄詩。", "識韓雖未遂，說項已先知。", "獨鶴留晴影，殘花怕雨時。", "苦無千里遠，每恨納交遲。"]'),
('cd2306a3-9eaa-4b1c-873b-ce824bf0c668','寄平江薛梅坡','顧逢','宋','宋诗','song-poetry','','[]','別君五十載春冬，遥想年來亦老容。',32,'全唐诗/poet.song.221000.json','["別君五十載春冬，遥想年來亦老容。", "見說多番入城市，路中相覓不相逢。"]'),
('c14cc3d9-5156-426a-a55f-3f6d99fb4807','寄秋江許端甫','顧逢','宋','宋诗','song-poetry','','[]','妙年親雅道，諸老日從游。',48,'全唐诗/poet.song.221000.json','["妙年親雅道，諸老日從游。", "師法林和靖，家聲許郢州。", "江湖千里志，風月一襟秋。", "好句人傳志，詩名不待求。"]'),
('96997de7-39e8-479c-bfc7-8555e2e2e5c8','寄徑山首座','顧逢','宋','宋诗','song-poetry','','[]','雙徑平分席，叢林總下風。',48,'全唐诗/poet.song.221000.json','["雙徑平分席，叢林總下風。", "東西兩班首，兄弟幾人同。", "地湧溪雲白，潮推海日紅。", "不須思出世，只合老山中。"]'),
('76455b16-7b5a-4ae8-9174-57cd6aa054ad','寄黄鶴山呂雪村','顧逢','宋','宋诗','song-poetry','','[]','君從廬墓我西東，數載慚無一字通。',32,'全唐诗/poet.song.221000.json','["君從廬墓我西東，數載慚無一字通。", "却喜夢遊黄鶴寺，幾番携手月明中。"]'),
('2afadbca-1326-4bb0-b5b3-1b2229ce5db0','寄碧瀾趙右之','顧逢','宋','宋诗','song-poetry','','[]','交游歲月深，彼此各知音。',48,'全唐诗/poet.song.221000.json','["交游歲月深，彼此各知音。", "佳句不離口，可人長在心。", "多愁悲白玉，一笑棄黄金。", "流水高山樂，床頭自有琴。"]'),
('14d54c95-810f-481e-9381-7cbeb6fbbe63','懷寄碧瀾趙右之','顧逢','宋','宋诗','song-poetry','','[]','以詩相寄表殷勤，君信如何竟不聞。',32,'全唐诗/poet.song.221000.json','["以詩相寄表殷勤，君信如何竟不聞。", "每向友朋門首過，有琴聲處必思君。"]'),
('be2f221a-3c15-4595-bbda-384ceebf1631','懷寄周靜得','顧逢','宋','宋诗','song-poetry','','[]','老盡黄花梅又開，故人不見入城來。',32,'全唐诗/poet.song.221000.json','["老盡黄花梅又開，故人不見入城來。", "武康縣北三橋步，夜夜夢中行一回。"]'),
('f4da9bba-4dc1-48af-9e1f-6306b9eb33f2','寄謝李雪林','顧逢','宋','宋诗','song-poetry','','[]','日本僧高誼，勞君序拙吟。',48,'全唐诗/poet.song.221000.json','["日本僧高誼，勞君序拙吟。", "名雖傳海外，價不及雞林。", "白髮消豪氣，青燈見苦心。", "豈無鍾子耳，但欠伯牙琴。"]'),
('5c6878bd-5b78-45fa-9e95-fd3929398ec9','和吳中友人見寄韻','顧逢','宋','宋诗','song-poetry','','[]','孤蹤水上萍，豈料過希齡。',48,'全唐诗/poet.song.221000.json','["孤蹤水上萍，豈料過希齡。", "藥聖貧難療，錢神禱不靈。", "行雲風斷續，蛻葉雨飄零。", "半世知心者，書燈一點青。"]'),
('dfc9ab2f-c099-4cf3-b3cc-8348268dfa2e','和林平山見寄韻','顧逢','宋','宋诗','song-poetry','','[]','勞勞終日者，少見白頭時。',48,'全唐诗/poet.song.221000.json','["勞勞終日者，少見白頭時。", "過去事皆夢，未來人不知。", "偷生貧是福，真病藥難醫。", "學得巢由隠，無愁可上眉。"]'),
('296cb2e0-5da6-4ed7-97d1-813111f5de2a','申屠雪磯見寄韻','顧逢','宋','宋诗','song-poetry','','[]','潘閬祠前住，天教得此鄰。',48,'全唐诗/poet.song.221000.json','["潘閬祠前住，天教得此鄰。", "百年傳盛事，一巷兩詩人。", "老境羞磻水，高風想富春。", "但教樽有酒，不必更言貧。"]'),
('ac709f77-2e2e-466f-9f4d-be1578fedb08','謝陸梅磵曹靖庵見和拙稿','顧逢','宋','宋诗','song-poetry','','[]','梅磵先賡三體句，靖庵又和五言詩。',32,'全唐诗/poet.song.221000.json','["梅磵先賡三體句，靖庵又和五言詩。", "不知二稿流傳後，能續君詩更有誰。"]'),
('12ed5404-abce-4218-89c9-78ad407e2128','謝遠方諸友下訪','顧逢','宋','宋诗','song-poetry','','[]','遠友相尋意極濃，盡言專訪老吟翁。',32,'全唐诗/poet.song.221000.json','["遠友相尋意極濃，盡言專訪老吟翁。", "來從千里求詩去，愧我全無一句工。"]'),
('09805efd-1ab2-4654-a776-64f278279915','謝徐容齋見訪','顧逢','宋','宋诗','song-poetry','','[]','問病來車馬，窮簷非所宜。',48,'全唐诗/poet.song.221000.json','["問病來車馬，窮簷非所宜。", "拘攣眠枕席，扶策喚妻兒。", "鵲信今朝報，燈花昨夜知。", "從前潘閬巷，無此寵榮時。"]'),
('fb198877-4b8e-4f3e-97c5-979563b66ed0','老桂','顧逢','宋','宋诗','song-poetry','','[]','分得蟾宮種，凡葩豈足論。',48,'全唐诗/poet.song.221000.json','["分得蟾宮種，凡葩豈足論。", "古香吹不盡，生意至今存。", "秋晚花三色，年深樹半根。", "更無攀折日，此恨向誰言。"]'),
('5204aab5-0a0d-4057-a640-a15c18118c85','落花','顧逢','宋','宋诗','song-poetry','','[]','樹底飛紅雨，園林一望空。',48,'全唐诗/poet.song.221000.json','["樹底飛紅雨，園林一望空。", "寂寥春去路，狼籍曉來風。", "亂影斜陽裏，餘香流水中。", "可憐衰謝日，不與乍開同。"]'),
('a0688ea5-56c7-4128-beb3-331f8c9dc887','落梅','顧逢','宋','宋诗','song-poetry','','[]','孤山花已老，片片受風吹。',48,'全唐诗/poet.song.221000.json','["孤山花已老，片片受風吹。", "莫歎凋殘去，曾誇爛熳時。", "香痕留宿雨，春色戀空枝。", "看取成青子，何嘗生意衰。"]'),
('50caa802-eba9-46e6-998e-22a16d3b24a1','落葉','顧逢','宋','宋诗','song-poetry','','[]','秋林霜後紅，恰與染來同。',48,'全唐诗/poet.song.221000.json','["秋林霜後紅，恰與染來同。", "風雨一番過，亭臺幾樹空。", "亂飄窗紙上，流出水溝中。", "待看春三月，濃陰萬綠叢。"]'),
('8d433ef8-5ce3-47a1-94ca-ffad8eec3a8f','西瓜','顧逢','宋','宋诗','song-poetry','','[]','多自淮鄉得，天然碧玉團。',48,'全唐诗/poet.song.221000.json','["多自淮鄉得，天然碧玉團。", "破來肌體瑩，嚼處齒牙寒。", "清敵炎威退，凉生酒量寬。", "東門無此種，雪片簇冰盤。"]'),
('f13ebc66-78b4-4eef-b4d9-159e539d93dc','無弦琴','顧逢','宋','宋诗','song-poetry','','[]','三尺孤桐古，其中趣最優。',48,'全唐诗/poet.song.221000.json','["三尺孤桐古，其中趣最優。", "只須從意會，不必以聲求。", "袖手時橫膝，忘言自點頭。", "孫登猶未悟，多却一絲留。"]'),
('0b3d679a-b280-4490-ac3c-d2209b69a19f','棋邊和韻','顧逢','宋','宋诗','song-poetry','','[]','子分黑白似精兵，相對沉吟手自停。',32,'全唐诗/poet.song.221000.json','["子分黑白似精兵，相對沉吟手自停。", "一著要須尋活路，舊曾險處莫重經。"]'),
('8e7bf385-567e-4cab-b637-1053c11bf9e7','枕上','顧逢','宋','宋诗','song-poetry','','[]','俗念枕邊灰，晨鐘又喚回。',48,'全唐诗/poet.song.221000.json','["俗念枕邊灰，晨鐘又喚回。", "若無紅日出，方免白頭催。", "花不多時好，人誰百歲來。", "死生彈指頃，有酒且啣杯。"]'),
('20d0d797-0d40-4c4a-a161-7df717e6da59','舟中枕上','顧逢','宋','宋诗','song-poetry','','[]','官塘來往縴紛紛，月入疏篷漏碎紋。',32,'全唐诗/poet.song.221000.json','["官塘來往縴紛紛，月入疏篷漏碎紋。", "數盡寒更天未曉，兩三聲雁枕邊聞。"]'),
('4c288977-80e2-4cd8-ba95-ac4b167da2c5','古圓鏡','顧逢','宋','宋诗','song-poetry','','[]','翠剝青銅面，年深入手輕。',48,'全唐诗/poet.song.221000.json','["翠剝青銅面，年深入手輕。", "似教藏美惡，不欲大分明。", "細雨波心碎，浮雲月底行。", "便令無點翳，誰解照前生。"]'),
('a8fb2241-7635-4a52-90ed-c6f8be69a845','湖舟','顧逢','宋','宋诗','song-poetry','','[]','簫鼓別船鳴，吟邊酒自傾。',48,'全唐诗/poet.song.221000.json','["簫鼓別船鳴，吟邊酒自傾。", "遠山多少意，幽鳥兩三聲。", "風急浪爭起，雲開雨不成。", "斷橋歸已晚，塔杪夕陽明。"]'),
('b1ae4d71-e3a5-4b50-8893-9f5c34a58dc5','雪夜枕上','顧逢','宋','宋诗','song-poetry','','[]','客樓臨水際，轉覺夜寒生。',48,'全唐诗/poet.song.221000.json','["客樓臨水際，轉覺夜寒生。", "欹枕天將曉，搜詩睡不成。", "雪多添月色，風近遠鐘聲。", "却喜心無事，梅花紙帳清。"]'),
('d52ac1f7-526d-4011-915f-8e41fff96a2f','秋扇','顧逢','宋','宋诗','song-poetry','','[]','明月藏塵篋，曾歸掌握中。',48,'全唐诗/poet.song.221000.json','["明月藏塵篋，曾歸掌握中。", "得時思酷暑，袖手怯西風。", "用舍人相似，炎凉心不同。", "汗流沾背處，蔽日豈無功。"]'),
('c6684ebd-6948-4b42-bcc3-5f4bfb135699','方竹杖','顧逢','宋','宋诗','song-poetry','','[]','直節老猶堅，稜分四角全。',48,'全唐诗/poet.song.221000.json','["直節老猶堅，稜分四角全。", "自緣生處別，不逐世情圓。", "夜倚閑看月，春扶醉上船。", "只愁規漆者，本體失天然。"]'),
('51169e73-cab8-415e-ad52-643065350e0d','湯婆子','顧逢','宋','宋诗','song-poetry','','[]','皤然一器微，有用在冬時。',48,'全唐诗/poet.song.221000.json','["皤然一器微，有用在冬時。", "永夜寒如許，孤衾暖不知。", "少年皆見棄，老者最相宜。", "却恨無情處，春來便別離。"]'),
('284ef54b-ca94-49a8-a339-1d3e72cc5286','雷峰寺聽琴','顧逢','宋','宋诗','song-poetry','','[]','盡日山窗下，松風細細吹。',48,'全唐诗/poet.song.221000.json','["盡日山窗下，松風細細吹。", "喜於同坐處，樂在聽琴時。", "幽几靜相對，斜陽過不知。", "江湖襟誼好，臨別問來期。"]'),
('e27d3ee3-fe03-4cc9-b3c9-00a1f2166572','聽趙碧瀾操琴','顧逢','宋','宋诗','song-poetry','','[]','彈來三尺桐，知用幾年功。',48,'全唐诗/poet.song.221000.json','["彈來三尺桐，知用幾年功。", "聽到希聲處，凉生不語中。", "斷霞明似日，急雨過如風。", "曲罷爐香在，還思敏仲翁。"]'),
('ee5b512f-af83-4a41-9eab-b3ef4bbfcda5','王質觀棋','顧逢','宋','宋诗','song-poetry','','[]','弈邊忘日月，况復遇神仙。',48,'全唐诗/poet.song.221000.json','["弈邊忘日月，况復遇神仙。", "石上無多著，人間幾百年。", "指枰如料敵，落子欲爭先。", "想爾腰柯爛，回頭亦駭然。"]'),
('311ef1ab-e723-416d-a40c-aaf39764dd98','贈吳門造牋','顧逢','宋','宋诗','song-poetry','','[]','剡藤光澤浄無瑕，搗杵工夫自一家。',32,'全唐诗/poet.song.221000.json','["剡藤光澤浄無瑕，搗杵工夫自一家。", "安得張顛醉狂筆，此中飛走活龍蛇。"]'),
('00a7d424-44e3-4cf3-b5b2-eb890d19669a','月夜泛舟','顧逢','宋','宋诗','song-poetry','','[]','晴湖浮素練，蘆葦冷秋霜。',48,'全唐诗/poet.song.221000.json','["晴湖浮素練，蘆葦冷秋霜。", "四望皆空闊，孤舟泛渺茫。", "水紋星動影，雲縫月流光。", "不似漁翁樂，終身鷗鷺鄉。"]'),
('3ffce6d1-f791-46d5-a8fc-d85f99ff9b5d','湖舟即事','顧逢','宋','宋诗','song-poetry','','[]','樓閣青山裏，闌干幾處憑。',48,'全唐诗/poet.song.221000.json','["樓閣青山裏，闌干幾處憑。", "樂同湖上酒，清在坐中僧。", "水影飛雙蝶，風聲磨一鷹。", "夕陽堪入畫，金蚓走春冰。"]'),
('a7fa997d-57d1-4489-aa0d-75d3122b7864','舟中偶成','顧逢','宋','宋诗','song-poetry','','[]','江海船行東復西，風蒲高掛一檣危。',32,'全唐诗/poet.song.221000.json','["江海船行東復西，風蒲高掛一檣危。", "往來逆順休相訝，逆者還須有順時。"]'),
('9b8fbac9-de45-45c9-bf46-fada104061ca','倚篷','顧逢','宋','宋诗','song-poetry','','[]','山光遠近青，盡入倚篷吟。',48,'全唐诗/poet.song.221000.json','["山光遠近青，盡入倚篷吟。", "夜雨一番過，春流幾寸深。", "車聲驚睡犢，帆影閃飛禽。", "村舍偏瀟灑，家家楊柳陰。"]'),
('ab4fa13a-7632-4ad1-b8de-2cf01796e0da','湖上觀釣','顧逢','宋','宋诗','song-poetry','','[]','每見湖隄畔，持竿立柳陰。',48,'全唐诗/poet.song.221000.json','["每見湖隄畔，持竿立柳陰。", "不多吞餌者，空起羨魚心。", "嚴瀨山林石，磻溪歲月深。", "何如池館上，倚檻看浮沉。"]'),
('77f56c0a-c23b-4a71-bd64-edf5ab0805a3','月宮沙戲','顧逢','宋','宋诗','song-poetry','','[]','兔舂金臼藥，幻出廣寒宮。',48,'全唐诗/poet.song.221000.json','["兔舂金臼藥，幻出廣寒宮。", "時聽數聲響，皆歸一轉功。", "雲霄大境界，几案小屏風。", "何獨沙爲戲，人間萬事同。"]'),
('4c4eb3e7-71a3-4581-a760-e9ec5dfbe3de','候仙亭即事','顧逢','宋','宋诗','song-poetry','','[]','一峰飛到此，勝景幻幽林。',48,'全唐诗/poet.song.221000.json','["一峰飛到此，勝景幻幽林。", "蒼徑望不盡，白雲行漸深。", "鐘聲傳日午，笠影卸松陰。", "候得神仙否，神仙不可尋。"]'),
('2fa908c0-9b74-4640-a1d9-f1d73e052e4b','靈隠觀風亭雪磯小酌','顧逢','宋','宋诗','song-poetry','','[]','林巒深密地，怪石紫苔存。',48,'全唐诗/poet.song.221000.json','["林巒深密地，怪石紫苔存。", "留得巉巖勢，全無斧鑿痕。", "浮雲沉水底，落葉走山根。", "最喜傾杯處，高僧遇老溫。"]'),
('2be1d23b-9173-4fee-b70e-233129930ac8','過林和靖祠','顧逢','宋','宋诗','song-poetry','','[]','入得梅村去，烟雲鎖廢祠。',48,'全唐诗/poet.song.221000.json','["入得梅村去，烟雲鎖廢祠。", "我來遲幾日，花已過多時。", "童鶴看如活，山川變不知。", "游人休著句，不比暗香詩。"]'),
('b9e6640b-58ec-414d-93fa-71fe0a1ad1db','天竺道中','顧逢','宋','宋诗','song-poetry','','[]','衝開秋色去，深入萬松間。',48,'全唐诗/poet.song.221000.json','["衝開秋色去，深入萬松間。", "風月無邊樂，乾坤幾箇閑。", "斷雲難掩日，急水不流山。", "樹杪忽然響，斜飛過白鷳。"]'),
('a90fdf6f-b63f-460b-8c92-f4d57ad6fbc6','茜水道中','顧逢','宋','宋诗','song-poetry','','[]','半世客孤篷，驚心景不同。',48,'全唐诗/poet.song.221000.json','["半世客孤篷，驚心景不同。", "路危人自恐，港澀艣無功。", "折樹龍眠水，長橋虹跨空。", "潮來通海道，爭趁一帆風。"]'),
('e6ef5a0f-c051-4ba4-97c9-f12347597dfa','太倉道中  其一','顧逢','宋','宋诗','song-poetry','','[]','露氣侵衣月滿船，夢回依約五更天。',32,'全唐诗/poet.song.221000.json','["露氣侵衣月滿船，夢回依約五更天。", "枕間聽得鳴雞犬，知在誰家村上眠。"]'),
('6b7deb21-bb8d-4b45-a910-1768fff06e14','太倉道中  其二','顧逢','宋','宋诗','song-poetry','','[]','江烟漠漠暮天昏，且把扁舟繫樹根。',32,'全唐诗/poet.song.221000.json','["江烟漠漠暮天昏，且把扁舟繫樹根。", "欲問村中沽酒處，家家風雨不開門。"]'),
('6e9eb465-54e0-4943-9c3c-8f756b647d6f','圓池','顧逢','宋','宋诗','song-poetry','','[]','一片水環璧，分明鏡可窺。',48,'全唐诗/poet.song.221000.json','["一片水環璧，分明鏡可窺。", "遊鱼吹白沫，浴鷺撲清漪。", "有月有星夜，無雲無雨時。", "倚欄相對處，如看渾天儀。"]'),
('11f61424-be15-4269-bd33-397eaf6063e3','隄上','顧逢','宋','宋诗','song-poetry','','[]','隄上喧絲竹，風流幾少年。',48,'全唐诗/poet.song.221000.json','["隄上喧絲竹，風流幾少年。", "衣冠雖較別，山水只如前。", "綠柳陰中馬，斜陽影裏船。", "晚雲眉一抹，橫翠斷霞邊。"]'),
('0d31028b-bffb-49c0-b608-3816df33bd76','慧山','顧逢','宋','宋诗','song-poetry','','[]','空山塵不到，白晝定僧禪。',48,'全唐诗/poet.song.221000.json','["空山塵不到，白晝定僧禪。", "龍口一泓水，人間第二泉。", "殿高雲氣濕，屋斷樹陰連。", "張祜曾題品，唐碑尚儼然。"]'),
('bb2fdc16-7e82-4301-8376-8b329cdd0d03','湖上','顧逢','宋','宋诗','song-poetry','','[]','湖邊春已過，正是綠陰時。',48,'全唐诗/poet.song.221000.json','["湖邊春已過，正是綠陰時。", "獨步無人處，微吟得意詩。", "斜陽浮舴艋，遠水立鸕鷀。", "物命真堪惜，遊鱼脫釣絲。"]'),
('9ecbc1e0-3081-4a3b-90c7-6ed879c7f177','盧進齋湖上韻','顧逢','宋','宋诗','song-poetry','','[]','潦倒江湖上，光陰夢裏過。',48,'全唐诗/poet.song.221000.json','["潦倒江湖上，光陰夢裏過。", "黄金消酒債，白髮苦詩魔。", "風細松琴慢，天晴柳絮多。", "斷橋斜陽裏，一路聽笙歌。"]'),
('1837ddd7-d423-4842-b316-8c1bb1c4a4e0','題直上天津','顧逢','宋','宋诗','song-poetry','','[]','欲向銀河去，唐家有畫船。',48,'全唐诗/poet.song.221000.json','["欲向銀河去，唐家有畫船。", "更無風浪險，竟到斗牛邊。", "笑傲瓊樓上，歌吟玉宇前。", "乘槎今有便，不必羨張騫。"]'),
('c15c4db3-4734-42b7-9eca-c96c0b5657bf','鰲山下燈市即事','顧逢','宋','宋诗','song-poetry','','[]','元夕牌燈大字題，高懸綵架果然奇。',32,'全唐诗/poet.song.221000.json','["元夕牌燈大字題，高懸綵架果然奇。", "鰲山山下人來往，只聽笙歌不看詩。"]'),
('24d22f18-c034-41aa-b63d-ef07a079a8ab','石湖行春橋','顧逢','宋','宋诗','song-poetry','','[]','十里湖光漾碧霄，山雲吞吐筆難描。',32,'全唐诗/poet.song.221000.json','["十里湖光漾碧霄，山雲吞吐筆難描。", "宜凉宜月猶宜雪，何獨行春過此橋。"]'),
('78a1984e-c7cc-4c8f-bfaa-91aa96d1da08','寒食日湖上','顧逢','宋','宋诗','song-poetry','','[]','寒食家家掃紙灰，道傍相吊總悲哀。',32,'全唐诗/poet.song.221000.json','["寒食家家掃紙灰，道傍相吊總悲哀。", "湖邊多少詩人墓，不見兒孫酹酒來。"]'),
('8d4b5c5f-2266-4907-b741-df93c3e2e3fd','早秋湖上','顧逢','宋','宋诗','song-poetry','','[]','藕花香裏去，獨步自尋詩。',48,'全唐诗/poet.song.221000.json','["藕花香裏去，獨步自尋詩。", "秋意在何處，夕陽將下時。", "鳥幽忘立久，山好覺行遲。", "飲興忽然動，橋邊有酒旗。"]'),
('e49d5b14-8c26-4f53-9b31-6e275d90eb77','花市','顧逢','宋','宋诗','song-poetry','','[]','賣聲喧市巷，紅紫售東風。',48,'全唐诗/poet.song.221000.json','["賣聲喧市巷，紅紫售東風。", "祇說春無價，誰知雨有功。", "蝶隨群檐出，鶑恨故園空。", "松柏何人愛，甘心巖壑中。"]'),
('911010ea-c47c-4b69-ae03-0c9da86c6ba1','孤山梅後','顧逢','宋','宋诗','song-poetry','','[]','晴雪白漫漫，山中幾樹殘。',48,'全唐诗/poet.song.221000.json','["晴雪白漫漫，山中幾樹殘。", "但知開處好，誰向落時看。", "影不隨流水，香猶在曲闌。", "飛來和靖鶴，相對立前灘。"]'),
('92d07af3-0951-4d0d-9f4f-3b84137d6fa7','夏菊','顧逢','宋','宋诗','song-poetry','','[]','粲粲發幽芳，何愁午夜霜。',48,'全唐诗/poet.song.221000.json','["粲粲發幽芳，何愁午夜霜。", "花先開六月，節不待重陽。", "彭澤應無種，東籬未有香。", "王弘如此見，必遣白衣忙。"]'),
('c3d5253e-ce48-476f-9c49-2a64fb478fb1','鴛鴦梅','顧逢','宋','宋诗','song-poetry','','[]','似厭沙頭睡，來棲隴樹中。',48,'全唐诗/poet.song.221000.json','["似厭沙頭睡，來棲隴樹中。", "一花飛夜雨，雙子倚東風。", "冰雪芳心共，池塘舊夢同。", "只愁羌笛響，驚散曉林空。"]'),
('1dafa301-2b49-4805-b447-523a749f21b5','徐容齋庭下竹','顧逢','宋','宋诗','song-poetry','','[]','碧玉黄金竹，求來此種難。',48,'全唐诗/poet.song.221000.json','["碧玉黄金竹，求來此種難。", "數竿真可愛，幾度共相看。", "月影畫半幅，風聲雨一般。", "歲寒心不改，日日報平安。"]'),
('966ae0b3-16aa-4df8-b58c-e6b2b31e1717','供花即事','顧逢','宋','宋诗','song-poetry','','[]','滿地盆花間樣栽，四時長有好花開。',32,'全唐诗/poet.song.221000.json','["滿地盆花間樣栽，四時長有好花開。", "勸君莫惜供花費，只恐園丁不獻來。"]'),
('1c8282ea-b066-45f3-b4fd-f113edaf95e3','多心茶花','顧逢','宋','宋诗','song-poetry','','[]','此花別是山茶種，鶴頂丹紅眩碧柯。',32,'全唐诗/poet.song.221000.json','["此花別是山茶種，鶴頂丹紅眩碧柯。", "開出多心雖可愛，一心好處不須多。"]'),
('217370f8-8110-4797-a2d2-7483725f0520','綠陰','顧逢','宋','宋诗','song-poetry','','[]','夏木千重裹，春無跡可窺。',48,'全唐诗/poet.song.221000.json','["夏木千重裹，春無跡可窺。", "靜如雲聚處，動似雨來時。", "坐對清相逼，行吟暑不知。", "幽禽啼復歇，難認著巢枝。"]'),
('ad63c84e-27b7-45c4-a621-c557db148270','二色芙蓉花','顧逢','宋','宋诗','song-poetry','','[]','拒霜一樹碧叢叢，兩色花開迥不同。',32,'全唐诗/poet.song.221000.json','["拒霜一樹碧叢叢，兩色花開迥不同。", "疑是酒邊西子在，半醒半醉立西風。"]'),
('b2f7bcfe-b9c3-4232-bd48-bb1f56f86c8a','白菊花','顧逢','宋','宋诗','song-poetry','','["\u897f\u6e56"]','淵明籬落發鉛華，疑是西湖處士家。',32,'全唐诗/poet.song.221000.json','["淵明籬落發鉛華，疑是西湖處士家。", "一白自知非正色，此心只欲比梅花。"]'),
('b3a58c5d-0780-4e58-b82d-67b5d1ae69dd','紅梅','顧逢','宋','宋诗','song-poetry','','[]','壽陽曾點額，脂粉带餘馨。',48,'全唐诗/poet.song.221000.json','["壽陽曾點額，脂粉带餘馨。", "晴雨看如醉，冰霜凍不醒。", "溪清羞潔白，色艷易飄零。", "桃杏休相忌，東君眼自青。"]'),
('100e9d1a-bf9b-4032-90fa-94e9d43e1224','梅影','顧逢','宋','宋诗','song-poetry','','[]','最喜孤山夜，斜枝月下清。',48,'全唐诗/poet.song.221000.json','["最喜孤山夜，斜枝月下清。", "透窗疑筆寫，映地若天生。", "鶴步踏不動，蜂腰時自橫。", "幾回雲聚散，晦後再分明。"]'),
('8f51ff7a-9ff4-4644-819a-5b838b6a46af','白蓮花','顧逢','宋','宋诗','song-poetry','','[]','種向東林得，此花真箇希。',48,'全唐诗/poet.song.221000.json','["種向東林得，此花真箇希。", "芳心能自潔，玉體靜相依。", "每訝鷗將浴，猶疑鷺不飛。", "月明無處認，香氣襲人衣。"]'),
('8453ff3d-da00-41b8-9d3e-6b21b0107edb','玉繡毬花','顧逢','宋','宋诗','song-poetry','','[]','正是紅稀綠暗時，花如圓玉瑩無疵。',32,'全唐诗/poet.song.221000.json','["正是紅稀綠暗時，花如圓玉瑩無疵。", "何人團雪高拋去，凍在枝頭春不知。"]'),
('83c6a8dc-a75b-42ec-b741-919bfb8b8742','芳所堂賞桂楊順齋酒邊賦','顧逢','宋','宋诗','song-poetry','','[]','秋風芳所地，把酒又重來。',48,'全唐诗/poet.song.221000.json','["秋風芳所地，把酒又重來。", "種有仙凡異，花分早晚開。", "滿簪烏帽去，如入月宮回。", "莫說郄詵事，功名念已灰。"]'),
('b2fa45e2-cf1b-41ae-afd0-9bbec63d73ea','不買花','顧逢','宋','宋诗','song-poetry','','[]','清似咸平處士家，案頭詩卷是生涯。',32,'全唐诗/poet.song.221000.json','["清似咸平處士家，案頭詩卷是生涯。", "膽瓶莫訝無花插，過了梅花不買花。"]'),
('dcc514aa-af4b-4dd4-8181-cce1dd5df2bf','雨中賞薔薇','顧逢','宋','宋诗','song-poetry','','[]','春風庭院少遲留，爛熳紅英带雨羞。',32,'全唐诗/poet.song.221000.json','["春風庭院少遲留，爛熳紅英带雨羞。", "最是花邊情緒惡，看花狼藉爲花愁。"]'),
('eb278e1c-2d4d-4ead-8d4c-d65489681862','父子同賞楊寺月牡','顧逢','宋','宋诗','song-poetry','','[]','世上月丹無此種，倚欄不覺夕陽斜。',32,'全唐诗/poet.song.221000.json','["世上月丹無此種，倚欄不覺夕陽斜。", "百年雨露春風力，高樹一根三色花。"]'),
('5db12aec-05c7-4b00-90c2-9a56794d7640','訪菊','顧逢','宋','宋诗','song-poetry','','[]','白髮蕭蕭映帽紗，相扶訪菊到山家。',32,'全唐诗/poet.song.221000.json','["白髮蕭蕭映帽紗，相扶訪菊到山家。", "攙先一日東籬醉，要見人間未見花。"]'),
('84793a67-a290-470f-9f26-de20f070f17a','黄醫諭求菊存詩','顧逢','宋','宋诗','song-poetry','','[]','門前三徑在，瀟灑傍林塘。',48,'全唐诗/poet.song.221000.json','["門前三徑在，瀟灑傍林塘。", "何事惟栽菊，其家本姓黄。", "嚴霜堅晚節，細雨潤幽香。", "指下誰能及，多收起死方。"]'),
('07ab4e4b-e1be-4945-8b20-61f215bd165c','九日對菊','顧逢','宋','宋诗','song-poetry','','[]','秋滿南山菊滿籬，卷簾相對坐多時。',32,'全唐诗/poet.song.221000.json','["秋滿南山菊滿籬，卷簾相對坐多時。", "琴中自得無弦趣，蝶與西風總不知。"]'),
('7e1d07ea-2ec7-4b37-8a8a-df5c6439bb33','雨邊對菊','顧逢','宋','宋诗','song-poetry','','[]','一片東籬菊，凄凉風雨邊。',48,'全唐诗/poet.song.221000.json','["一片東籬菊，凄凉風雨邊。", "花雖黄似舊，髮更白於前。", "把酒傷今日，登高憶去年。", "淵明曾作令，相對亦無錢。"]'),
('64aeec32-4311-4655-beba-791db82d859d','雪後尋梅','顧逢','宋','宋诗','song-poetry','','[]','尋梅不憚路程賒，行遍山邊與水涯。',32,'全唐诗/poet.song.221000.json','["尋梅不憚路程賒，行遍山邊與水涯。", "幾處樹頭殘雪在，只疑昨夜又開花。"]'),
('ccf0d8d8-225f-4644-99da-1b4c8c068680','探梅','顧逢','宋','宋诗','song-poetry','','[]','探梅自策短筇來，是處溪山到一回。',32,'全唐诗/poet.song.221000.json','["探梅自策短筇來，是處溪山到一回。", "歲歲見花人已老，幾番花落又花開。"]'),
('621e04f6-8fd4-41d3-babb-ce809eeaf3d1','牆外見梅','顧逢','宋','宋诗','song-poetry','','[]','隔水園林賸有梅，重門扃鑰少曾開。',32,'全唐诗/poet.song.221000.json','["隔水園林賸有梅，重門扃鑰少曾開。", "主翁只恐吹香出，不道花梢過屋來。"]'),
('81007f7c-1594-463f-8375-6fc23138f316','孤山問梅','顧逢','宋','宋诗','song-poetry','','[]','欲扣隴頭信，侵晨踏雪來。',48,'全唐诗/poet.song.221000.json','["欲扣隴頭信，侵晨踏雪來。", "不知今夜裏，先放幾花開。", "地有孤根在，春從何處回。", "向人如解語，約我辦樽罍。"]'),
('8f4d16ee-9f1a-4c1c-addd-82207296c081','嚼梅','顧逢','宋','宋诗','song-poetry','','[]','冷竈無煙過午時，可憐童鶴望鄰炊。',32,'全唐诗/poet.song.221000.json','["冷竈無煙過午時，可憐童鶴望鄰炊。", "饑來細把梅花嚼，不信梅花不療饑。"]'),
('17b0a131-b28b-4079-a11b-096ef4a181e0','百舌','顧逢','宋','宋诗','song-poetry','','[]','得意春風裏，山林異樣鳴。',48,'全唐诗/poet.song.221000.json','["得意春風裏，山林異樣鳴。", "雖無三寸舌，解作百禽聲。", "巧處難求色，聽時可辨名。", "金籠容不得，應是愧流鶑。"]'),
('b02b2f8f-9283-46cf-8029-20e4c79a1751','雁影','顧逢','宋','宋诗','song-poetry','','[]','萬里衡陽別，翱翔背夕暉。',48,'全唐诗/poet.song.221000.json','["萬里衡陽別，翱翔背夕暉。", "數行天外過，一片水中飛。", "無迹留沙渚，有聲過釣磯。", "回頭還自顧，上下带雲歸。"]'),
('4a4d7f99-3f0e-44f4-8e62-0ce804215993','海東青','顧逢','宋','宋诗','song-poetry','','[]','相傳産海東，不與衆禽同。',48,'全唐诗/poet.song.221000.json','["相傳産海東，不與衆禽同。", "兩翅飛騰去，層霄頃刻中。", "轉眸明似電，追馬疾如風。", "墜得天鵝落，人皆指遠空。"]'),
('e639d23d-4626-4eb9-a912-c4d2a6669fcb','飛來峰猿','顧逢','宋','宋诗','song-poetry','','[]','天竺如巴峽，畫圖無此奇。',48,'全唐诗/poet.song.221000.json','["天竺如巴峽，畫圖無此奇。", "掛藤伸黑臂，剝果餧黄兒。", "孤影池中夜，三聲月下時。", "倚闌僧不去，應是苦於詩。"]'),
('b9e2ed00-ea46-4f81-bc0b-15d67f4b8811','紙鳶','顧逢','宋','宋诗','song-poetry','','[]','祇是憑風力，飛騰自不知。',48,'全唐诗/poet.song.221000.json','["祇是憑風力，飛騰自不知。", "轉來高處去，肯顧此身危。", "雲外摇雙翼，空中寄一絲。", "每愁吹斷後，欲覓意何之。"]'),
('98713ff2-66aa-4b94-9ef8-a70af38eb0e1','下竺寺金魚','顧逢','宋','宋诗','song-poetry','','[]','黄金成一片，雨過唼方池。',48,'全唐诗/poet.song.221000.json','["黄金成一片，雨過唼方池。", "想爾浮沉樂，如吾愛傲時。", "水聲頻撥剌，人影不驚疑。", "中有成龍者，騰空未可知。"]'),
('c07398ed-0dc6-4372-9c40-4b9dcf646b96','觀鬬蟋蟀有感','顧逢','宋','宋诗','song-poetry','','[]','徼蟲亦可傷，何事苦爭强。',48,'全唐诗/poet.song.221000.json','["徼蟲亦可傷，何事苦爭强。", "百勝終歸死，一秋空自忙。", "吟殘庭際月，冷怯草根霜。", "不入兒童手，誰能較短長。"]'),
('10b8d561-fcff-4b7c-8f1d-5ea516fe224a','冬夜聞蛩','顧逢','宋','宋诗','song-poetry','','[]','尚有一蛩在，悲吟廢草邊。',48,'全唐诗/poet.song.221000.json','["尚有一蛩在，悲吟廢草邊。", "想於深夜裏，自憶早秋前。", "勝負皆成夢，孤寒似可憐。", "晚年飄泊老，此况亦同然。"]'),
('5509aa93-a244-4c74-ae8a-0194cde84d67','冠勝軒','顧逢','宋','宋诗','song-poetry','','[]','六橋多少景，盡在倚欄中。',48,'全唐诗/poet.song.221000.json','["六橋多少景，盡在倚欄中。", "佳處無如此，看來總不同。", "湖光四時別，山影半江空。", "圖盡天開出，人間筆未工。"]'),
('4316ff96-27a4-4149-abc3-7f3a407451be','寄題翠侍軒','顧逢','宋','宋诗','song-poetry','','[]','華軒居地隠，塵世總相忘。',48,'全唐诗/poet.song.221000.json','["華軒居地隠，塵世總相忘。", "白髮坐來久，青山立在旁。", "兩峰如拱手，一鶴自升堂。", "唯諾疑相應，松琴奏羽商。"]'),
('ce255763-8d5f-4e64-81da-78c66f6ea6a0','題風雨樓','顧逢','宋','宋诗','song-poetry','','[]','湖上晴看好，雨中猶更奇。',48,'全唐诗/poet.song.221000.json','["湖上晴看好，雨中猶更奇。", "無窮憑檻趣，正是捲簾時。", "鷗鷺飛相失，山林晚不知。", "烟雲多變態，難畫亦難詩。"]'),
('72660790-64f7-46b2-be1b-66367f20a47c','雨樓即事','顧逢','宋','宋诗','song-poetry','','[]','客久顔容改，羞開古鏡奩。',48,'全唐诗/poet.song.221000.json','["客久顔容改，羞開古鏡奩。", "瘦添清骨相，老減白髭髯。", "雲暗山無塔，樓空雨一簾。", "休官歸去後，疏散似陶潛。"]'),
('2a785f85-5c48-4750-b3d3-055383eb98eb','聽雨軒','顧逢','宋','宋诗','song-poetry','','[]','此地偏於靜夜宜，爐香相對一編詩。',32,'全唐诗/poet.song.221000.json','["此地偏於靜夜宜，爐香相對一編詩。", "幾回聞得敲窗響，不是開門落葉時。"]'),
('bf93ced0-0535-4d09-bc93-a9b4db019afd','碧瀾堂即事','顧逢','宋','宋诗','song-poetry','','[]','白蘋洲暖漾晴波，雪點沙汀立鷺多。',32,'全唐诗/poet.song.221000.json','["白蘋洲暖漾晴波，雪點沙汀立鷺多。", "幾度月明窗下見，打漁人醉枕輕蓑。"]'),
('87bcdf97-9282-4c43-acd2-595b07a3c9f5','冷泉亭即事','顧逢','宋','宋诗','song-poetry','','[]','亭上數僧俱不識，倚闌無語坐多時。',32,'全唐诗/poet.song.221000.json','["亭上數僧俱不識，倚闌無語坐多時。", "聽談五字中奇句，盡是山翁舊日詩。"]'),
('2ecb118a-794b-46cd-a8e9-c5877568961e','石湖山居  其一','顧逢','宋','宋诗','song-poetry','','[]','湖光終日對，且喜絕塵紛。',48,'全唐诗/poet.song.221000.json','["湖光終日對，且喜絕塵紛。", "時事年來別，山中人不聞。", "霜林晴滴雨，寒井晚雲生。", "門掩松風裏，知心有范君。"]'),
('5eb71f07-b74e-4879-8070-2bb0f8a49b5b','石湖山居  其二','顧逢','宋','宋诗','song-poetry','','[]','幽居入翠微，樂似在松時。',48,'全唐诗/poet.song.221000.json','["幽居入翠微，樂似在松時。", "野景俱成畫，山行總是詩。", "黠禽爭浴水，戲鵲倒懸枝。", "此意誰能識，徜徉只自知。"]'),
('90694192-b736-4d0e-ad26-23189bf4d7cc','石湖山居  其三','顧逢','宋','宋诗','song-poetry','','[]','越來溪上望，雨漲一篙深。',48,'全唐诗/poet.song.221000.json','["越來溪上望，雨漲一篙深。", "折葦眠枯葉，老蓮生苦心。", "水連孤嶼遠，山入半湖陰。", "喜近行春路，時於月下吟。"]'),
('00f03c97-7c4e-4a8c-8d85-5cacce6aa5c6','西湖城邊水閣即事','顧逢','宋','宋诗','song-poetry','','["\u897f\u6e56"]','水閣凉亭飲宴時，遥看葛嶺亦傷悲。',32,'全唐诗/poet.song.221000.json','["水閣凉亭飲宴時，遥看葛嶺亦傷悲。", "歌童舞女今何在，一带枯樁立鷺鷥。"]'),
('6609df3f-2dd3-4606-972a-84d396930d0d','西湖如畫軒','顧逢','宋','宋诗','song-poetry','','["\u897f\u6e56"]','世間何處覓西湖，風月無邊酒一壺。',32,'全唐诗/poet.song.221000.json','["世間何處覓西湖，風月無邊酒一壺。", "盡道此中如畫景，不知此景畫中無。"]'),
('9629168b-cbac-4a7f-9a4b-c1ab87e78548','題徐容齋先生愛蘭軒','顧逢','宋','宋诗','song-poetry','','[]','入得善人室，塵凡一洗空。',48,'全唐诗/poet.song.221000.json','["入得善人室，塵凡一洗空。", "三閭心上事，九畹國香中。", "坐對清幽地，時來旎□風。", "紛紛桃與李，不與此花同。"]'),
('9e198676-91dc-45fd-a80c-75bfae74eaad','西湖書院重建三賢堂  其一','顧逢','宋','宋诗','song-poetry','','["\u897f\u6e56"]','三賢堂廢西湖上，文廟重營氣宇新。',32,'全唐诗/poet.song.221000.json','["三賢堂廢西湖上，文廟重營氣宇新。", "若得雪江相配享，方知創立是何人。"]'),
('dd9a3cef-1d4d-4a72-9926-b2f77dd77e20','西湖書院重建三賢堂  其二','顧逢','宋','宋诗','song-poetry','','["\u897f\u6e56"]','堂上瞻三像，衣冠各儼然。',48,'全唐诗/poet.song.221000.json','["堂上瞻三像，衣冠各儼然。", "兩朝賢太守，一代老詩仙。", "棠影春風裏，梅花夜月邊。", "西湖新學校，千載後同傳。"]'),
('8d3b7460-8385-419a-a341-7f1e33a2920b','琴書齋','顧逢','宋','宋诗','song-poetry','','[]','不道鄴侯家，有人如伯牙。',48,'全唐诗/poet.song.221000.json','["不道鄴侯家，有人如伯牙。", "七絃真得趣，萬卷足生涯。", "石鼎時添火，銅瓶日換花。", "高山流水罷，筆下走龍蛇。"]'),
('11f286ef-5100-468c-aa26-9e2371a50762','題詩境樓','顧逢','宋','宋诗','song-poetry','','[]','白晝鈎簾坐，湖山靜裏看。',48,'全唐诗/poet.song.221000.json','["白晝鈎簾坐，湖山靜裏看。", "分明吟世界，盡在此闌干。", "妙處寫不就，題來句轉難。", "幾回風雪際，遥憶灞橋寒。"]'),
('b334e1cc-4107-4c8f-a1d1-f8ac3917d260','和移家春洲寄韻','顧逢','宋','宋诗','song-poetry','','[]','家具與妻兒，知經幾處移。',48,'全唐诗/poet.song.221000.json','["家具與妻兒，知經幾處移。", "不堪多病日，頓憶少年時。", "犬吠風行葉，魚驚月在池。", "人生俱是寓，無我重流離。"]'),
('c18601ca-e621-4ecf-8920-0cbb62d62ec6','留別干月亭','顧逢','宋','宋诗','song-poetry','','[]','客中愁送別，臨別轉傷心。',48,'全唐诗/poet.song.221000.json','["客中愁送別，臨別轉傷心。", "最是情相得，猶教老不禁。", "離懷空記憶，遠信有浮沉。", "爭似長携手，山邊水際吟。"]'),
('32cff557-b18d-4d57-92ea-3161e713d27c','過林忠甫山房','顧逢','宋','宋诗','song-poetry','','[]','雖是無猿鶴，何殊林麓間。',48,'全唐诗/poet.song.221000.json','["雖是無猿鶴，何殊林麓間。", "從教居近市，不必入深山。", "白日窗如炙，清風門自關。", "留連詩酒樂，坐久竟忘還。"]'),
('2a92fe52-31d8-4c35-9c13-f6799cecd2a1','寓擁葉精舍','顧逢','宋','宋诗','song-poetry','','[]','禪房靜掩扃，長日勘傳燈。',48,'全唐诗/poet.song.221000.json','["禪房靜掩扃，長日勘傳燈。", "身健高飛鶴，心空入定僧。", "炭煙生濕癭，簷水滴晴冰。", "從此無依戀，相隨只瘦藤。"]'),
('abcdaf14-68b1-4d5b-a615-40fe8a0f4e34','鄧覺非寓舍即事','顧逢','宋','宋诗','song-poetry','','[]','老屋幽深靜掩門，四圍多有古碑存。',32,'全唐诗/poet.song.221000.json','["老屋幽深靜掩門，四圍多有古碑存。", "庭前黄葉無人掃，留得秋風在樹根。"]'),
('2ca1dfcc-efea-4c17-96c5-d9e0062195ea','訪明月堂','顧逢','宋','宋诗','song-poetry','','[]','山路亦迢迢，殷勤訪久要。',48,'全唐诗/poet.song.221000.json','["山路亦迢迢，殷勤訪久要。", "三門雖未入，一僕已相邀。", "枕臂眠平石，扶筇過險橋。", "詩翁歸步醉，空費酒旗招。"]'),
('3494db8e-0141-4fb8-af43-103ecf6ca52a','秀邸綠陰堂','顧逢','宋','宋诗','song-poetry','','[]','連朝風雨卷殘紅，四望亭臺眼界空。',32,'全唐诗/poet.song.221000.json','["連朝風雨卷殘紅，四望亭臺眼界空。", "多少東君生物意，不知俱在綠陰中。"]'),
('61c77bf3-aeaa-4c66-a6db-9eeaeb3d3ba4','過冷泉亭','顧逢','宋','宋诗','song-poetry','','[]','綠影浮陰玉一淵，吟翁同立石闌邊。',32,'全唐诗/poet.song.221000.json','["綠影浮陰玉一淵，吟翁同立石闌邊。", "池中石與詩中字，知是幾年磨得圓。"]'),
('e275470a-fbaf-41c6-88c1-f55e0ac7effa','甫遊冷泉亭','顧逢','宋','宋诗','song-poetry','','[]','萬綠重重如潑翠，一泓泉水浸蒼苔。',32,'全唐诗/poet.song.221000.json','["萬綠重重如潑翠，一泓泉水浸蒼苔。", "分明天地開圖畫，山自飛來猿自來。"]'),
('1de05082-67f2-4014-95e4-45f371a549b1','過林石田湖上所居','顧逢','宋','宋诗','song-poetry','','[]','第一橋邊住，柴扉傍釣磯。',48,'全唐诗/poet.song.221000.json','["第一橋邊住，柴扉傍釣磯。", "天晴扶杖出，寺近與僧歸。", "梁燕穿簾去，沙鷗入屋飛。", "幾回吟苦處，獨立對斜暉。"]'),
('5ed4713c-5a7f-4201-bb91-bd54ef38919f','過楊春磵所居','顧逢','宋','宋诗','song-poetry','','[]','過門須憶老相知，日日長看掩竹扉。',32,'全唐诗/poet.song.221000.json','["過門須憶老相知，日日長看掩竹扉。", "只有畫梁巢燕在，主人三載不曾歸。"]'),
('b09d2519-8695-4c87-addf-c3aa3a7479f3','過沈東林所居','顧逢','宋','宋诗','song-poetry','','[]','屋破深山裏，門無車馬塵。',48,'全唐诗/poet.song.221000.json','["屋破深山裏，門無車馬塵。", "誰知青竹塢，中有白蓮人。", "坐上長留客，詩中不見貧。", "池塘園圃樂，花木四時春。"]'),
('ec1881c0-296b-448d-90ef-c502b65efab8','史紫微徐容齋閻靜軒過潘閬巷所居','顧逢','宋','宋诗','song-poetry','','[]','門外喧車馬，歡聲震四鄰。',48,'全唐诗/poet.song.221000.json','["門外喧車馬，歡聲震四鄰。", "爭疑來陋巷，不道訪詩人。", "枉駕屈三老，開樽愧一貧。", "逍遥祠宇近，容邈亦精神。"]'),
('4de7bd16-3e93-44d1-8ad0-2cc29c33f1e5','過杜北山老友舊居','顧逢','宋','宋诗','song-poetry','','[]','曲院猶存破屋斜，北山老子舊詩家。',32,'全唐诗/poet.song.221000.json','["曲院猶存破屋斜，北山老子舊詩家。", "往來多少人惆悵，只見山茶一樹花。"]'),
('6269825d-f1b6-4449-a1bf-9d9494b8d70b','過葉苔磯故居有感','顧逢','宋','宋诗','song-poetry','','[]','天井坊中過，令人憶故知。',48,'全唐诗/poet.song.221000.json','["天井坊中過，令人憶故知。", "幾回上心處，諸老倚樓時。", "猶記負暄稿，誰傳詠史詩。", "坐間年最小，今已白髭眉。"]'),
('79f247d5-85ab-4815-a96b-a3060f9da0e4','過凈慈傅無文竹院退居','顧逢','宋','宋诗','song-poetry','','[]','李涉題詩處，軒窗一室明。',48,'全唐诗/poet.song.221000.json','["李涉題詩處，軒窗一室明。", "游人閑半日，老子樂餘生。", "碧落雲無影，清風竹有聲。", "自言身後事，龕塔已圓成。"]'),
('d3996e8a-1c91-4567-8b8f-8ff6d34fc556','訪金蓀壁山居','顧逢','宋','宋诗','song-poetry','','[]','徐行策瘦筇，不覺過層峰。',48,'全唐诗/poet.song.221000.json','["徐行策瘦筇，不覺過層峰。", "隠者在何處，白雲知幾重。", "細泉鳴碎石，遠籟起高松。", "只恐南天竺，夕陽催暮鐘。"]'),
('d30d3cd1-2b49-4eed-8198-21f5d8b1820e','閑居雜興  其一','顧逢','宋','宋诗','song-poetry','','[]','滿眼皆詩料，詩成稿自添。',48,'全唐诗/poet.song.221000.json','["滿眼皆詩料，詩成稿自添。", "好山長在眼，終日不垂簾。", "風度雲行水，鳥隨花墮簷。", "爐香窗下坐，飛絮上書籤。"]'),
('54973aed-4b3a-4276-a977-f55a5dd12e5c','閑居雜興  其二','顧逢','宋','宋诗','song-poetry','','[]','蕭然一弊廬，門巷似樵漁。',48,'全唐诗/poet.song.221000.json','["蕭然一弊廬，門巷似樵漁。", "鷄犬情相得，山林樂有餘。", "霜濃黄木葉，雨過綠園蔬。", "獨坐寒窗下，時看未見書。"]'),
('6dac1f21-5abb-4aa4-a640-87c8481781f8','雪後月夜登樓','顧逢','宋','宋诗','song-poetry','','[]','雪屋凝寒凍不流，碧天如水似中秋。',32,'全唐诗/poet.song.221000.json','["雪屋凝寒凍不流，碧天如水似中秋。", "一樓月色無人共，聽盡鐘聲未下樓。"]'),
('9afb1e10-4ca1-4102-a4ad-502960b8aa12','碧磵同飲麗景樓分韻得花字','顧逢','宋','宋诗','song-poetry','','[]','醉倚歌樓上，歸來帽欲斜。',48,'全唐诗/poet.song.221000.json','["醉倚歌樓上，歸來帽欲斜。", "山銜半規日，雲間一稜霞。", "砌雪膠庭草，簷冰墜瓦花。", "明朝重有約，同訪趙州茶。"]'),
('95a2f9cf-dfc5-4e8e-817a-ade4be10eda5','劉蕭雲水閣','顧逢','宋','宋诗','song-poetry','','[]','亭臺入畫圖，石怪樹蕭疏。',48,'全唐诗/poet.song.221000.json','["亭臺入畫圖，石怪樹蕭疏。", "池上多佳致，城中無此居。", "垂楊偏稱鶴，宿鷺不驚魚。", "酒罷出門去，雲稜月一梳。"]'),
('64761631-c817-4e18-b82b-92558a10eaea','登姑蘇懷古','顧逢','宋','宋诗','song-poetry','','[]','高臺登眺處，凉思爽衰顔。',48,'全唐诗/poet.song.221000.json','["高臺登眺處，凉思爽衰顔。", "只此闌干外，不知多少山。", "龍收殘雨去，鶴带斷雲還。", "一片興亡恨，越來溪上閒。"]'),
('b7100051-4f20-4a70-8f2d-5b89ae8d8c09','雨窗即事','顧逢','宋','宋诗','song-poetry','','[]','羞將鐵硯磨，萬事總談何。',48,'全唐诗/poet.song.221000.json','["羞將鐵硯磨，萬事總談何。", "斷酒除狂興，看書起睡魔。", "霜林秋色慘，山館雨聲多。", "安得乘漁艇，空江掛綠蓑。"]'),
('66565a40-80c0-46b0-a71b-4e55596d07f4','斯巖庵','顧逢','宋','宋诗','song-poetry','','[]','艤棹水之涯，重來訪可師。',48,'全唐诗/poet.song.221000.json','["艤棹水之涯，重來訪可師。", "磬聲連古寺，僧語隔疏籬。", "果熟時拋地，花繁欲墮枝。", "三年前到此，不記舊題詩。"]'),
('da712aa9-20fa-47ce-b085-fd2fd291c4bf','儒學禮上公堂即事','顧逢','宋','宋诗','song-poetry','','[]','明倫堂上橫經日，列坐諸生酒半酣。',32,'全唐诗/poet.song.221000.json','["明倫堂上橫經日，列坐諸生酒半酣。", "折得一枝梅在手，幾多人笑學官貪。"]'),
('2497c9fe-3f72-40c6-9e44-e4b36a75843d','訪王文質西塾','顧逢','宋','宋诗','song-poetry','','[]','獨對梅花坐，枝頭數點開。',48,'全唐诗/poet.song.221000.json','["獨對梅花坐，枝頭數點開。", "畫中無此景，雪裏有僧來。", "饑鶴窺流水，行龜落凍苔。", "茶邊清話處，一字共敲推。"]'),
('d1b2d672-54ec-4258-a572-63eb498caea3','湯信卿新移書塾','顧逢','宋','宋诗','song-poetry','','[]','又見榮遷去，門多客往還。',48,'全唐诗/poet.song.221000.json','["又見榮遷去，門多客往還。", "別開新縫帳，重對舊青山。", "孤塔秋風裏，閑雲遠樹間。", "西窗堪夜坐，有月不須關。"]'),
('db7bd737-cbed-490d-b8d1-d118931676d8','王巨卿御史西塾','顧逢','宋','宋诗','song-poetry','','[]','烏臺清要地，門戶少曾開。',48,'全唐诗/poet.song.221000.json','["烏臺清要地，門戶少曾開。", "俗客無由入，詩人不憚來。", "閑雲行碧落，倦馬卧蒼苔。", "再約中秋夜，同傾月下杯。"]'),
('eb8605f1-5bac-4ea5-a436-43ee810a9673','過秀邸賜第','顧逢','宋','宋诗','song-poetry','','[]','往年珠履客，獨有老夫存。',48,'全唐诗/poet.song.221000.json','["往年珠履客，獨有老夫存。", "觸目景非昔，傷心事莫論。", "樓臺新白屋，瓦礫舊朱門。", "却憶朝回日，山堂共酒樽。"]'),
('2f91aa0a-cb8b-4409-a207-a987eb9b048f','題可耕漁處','顧逢','宋','宋诗','song-poetry','','[]','自得田園趣，臨溪屋數椽。',48,'全唐诗/poet.song.221000.json','["自得田園趣，臨溪屋數椽。", "最堪犂釣處，只在水雲邊。", "細雨歸莊犢，斜陽曬網船。", "烹鮮供一飽，垂老正相便。"]'),
('07c241c0-647c-4a22-b79d-d7b695551b05','相嚴寺僧樓','顧逢','宋','宋诗','song-poetry','','[]','鏡樣湖光照眼明，無風無浪水如冰。',32,'全唐诗/poet.song.221000.json','["鏡樣湖光照眼明，無風無浪水如冰。", "畫圖只在闌干外，柳下行人樓上僧。"]'),
('7946c157-6839-4a0b-9306-349686dc5014','東陵方丈納凉','顧逢','宋','宋诗','song-poetry','','[]','愛入高明處，雲扉策杖登。',48,'全唐诗/poet.song.221000.json','["愛入高明處，雲扉策杖登。", "暑威消宿雨，清話聽高僧。", "驟馬風簷鐵，殘星晚殿燈。", "山中凉可喜，澗水一泓冰。"]'),
('7ceb33d4-a564-42c3-939f-6385fbb605a8','同吳心雲避暑','顧逢','宋','宋诗','song-poetry','','[]','寺在深山裏，軒窗面面嘉。',48,'全唐诗/poet.song.221000.json','["寺在深山裏，軒窗面面嘉。", "畫圖看水石，僧供款茶瓜。", "臺蟻搬生飯，池魚噴落花。", "何人溪上住，竹林兩三家。"]'),
('c0dfa8fe-a815-46f3-8768-dea2e36a8243','晞淵仲齋避暑','顧逢','宋','宋诗','song-poetry','','[]','避暑來高寺，終朝脫帽翁。',48,'全唐诗/poet.song.221000.json','["避暑來高寺，終朝脫帽翁。", "四簷青嶂下，一枕綠陰中。", "雲意看無盡，禽聲聽不同。", "樓臺城市有，何地覓凉風。"]'),
('f3ff41c0-a0e7-4320-8b81-7022742fc2e8','秋夜宿山寺','顧逢','宋','宋诗','song-poetry','','[]','靜夜留山寺，清談對老龐。',48,'全唐诗/poet.song.221000.json','["靜夜留山寺，清談對老龐。", "樹聲如有雨，秋氣欲無窗。", "簷馬隨風走，樓鐘带月撞。", "何人呼渡急，隔水吠村厖。"]'),
('e2683113-986e-4bc1-8375-3583775a2848','天童寺','顧逢','宋','宋诗','song-poetry','','[]','雙峨聚首去年冬，知得還歸太白峯。',32,'全唐诗/poet.song.221000.json','["雙峨聚首去年冬，知得還歸太白峯。", "二十里松山色裏，天晴時節一枝筇。"]'),
('ac931c36-d83a-44b0-9e19-14c2a4bddeb1','秋夜宿僧房','顧逢','宋','宋诗','song-poetry','','[]','白雲分半榻，正在磵聲邊。',48,'全唐诗/poet.song.221000.json','["白雲分半榻，正在磵聲邊。", "一夜山中宿，三生石上緣。", "聽猿推枕坐，愛月近窗眠。", "不覺天將曉，疎鐘度暝煙。"]'),
('398c5ca5-d389-4669-b0dd-15faf2938e00','過僧房','顧逢','宋','宋诗','song-poetry','','[]','一飽聽鐘魚，浮生百念疎。',48,'全唐诗/poet.song.221000.json','["一飽聽鐘魚，浮生百念疎。", "不知門外事，長對案頭書。", "白日閑中過，青山深處居。", "老天憐供薄，夜雨長園蔬。"]'),
('720c4b92-5928-432f-8e3d-01f8e9d2aeb7','過下竺清古源房','顧逢','宋','宋诗','song-poetry','','[]','草堂人別久，今日特相過。',48,'全唐诗/poet.song.221000.json','["草堂人別久，今日特相過。", "轉覺交游少，徒增感慨多。", "巖花香宿雨，春葉暗庭柯。", "窗下破孤寂，幽禽啼翠蘿。"]'),
('0a143f4e-0555-447a-bca7-7d72274b9ee8','再過悟竹庭房','顧逢','宋','宋诗','song-poetry','','[]','兩度客僧廬，交情密似初。',48,'全唐诗/poet.song.221000.json','["兩度客僧廬，交情密似初。", "墨雲膠凍硯，鬢雪落寒梳。", "鳴鶴聲高下，盤鷹羽疾徐。", "此時親老念，重讀寄來書。"]'),
('2f7d3d78-d703-4ca4-993a-b1b3fa0142ba','石堂上人房夜坐','顧逢','宋','宋诗','song-poetry','','[]','秋夜坐來清，禪房靜掩扃。',48,'全唐诗/poet.song.221000.json','["秋夜坐來清，禪房靜掩扃。", "希賢思益語，愛國讀忠經。", "香篆行微蚓，燈花落小螢。", "西風憐寂寞，一曲奏簷鈴。"]'),
('b4311e09-49f2-49c0-b8dd-b298074fce88','下竺寺堂前獨坐','顧逢','宋','宋诗','song-poetry','','[]','風舞花旛萬縷輕，石爐香冷一燈明。',32,'全唐诗/poet.song.221000.json','["風舞花旛萬縷輕，石爐香冷一燈明。", "坐來耳目身心靜，髣髴慈雲禮懺聲。"]'),
('a49ca71e-42fb-4ddf-9464-1240c1388b6a','題方家峪劉寺山門','顧逢','宋','宋诗','song-poetry','','[]','灑墨起雲端，神威聳衆觀。',48,'全唐诗/poet.song.221000.json','["灑墨起雲端，神威聳衆觀。", "直疑鮮甲動，相對骨毛寒。", "瞠目真如活，騰空似不難。", "傳聞風雨夜，雷電遶闌干。"]'),
('0273666c-9221-4586-8ad5-96070e7b1e1d','寄真覺庵','顧逢','宋','宋诗','song-poetry','','[]','百年如閃電，未可百年期。',48,'全唐诗/poet.song.221000.json','["百年如閃電，未可百年期。", "少見回頭者，能思瞑目時。", "山林忙不歇，猿鶴冷相窺。", "千里求名客，多應惡子規。"]'),
('b3493e3b-a47d-4264-9037-e34a6625522b','覺報和蒲溪方丈送友歸','顧逢','宋','宋诗','song-poetry','','[]','汶陽詩板在，拂拭劍池前。',48,'全唐诗/poet.song.221000.json','["汶陽詩板在，拂拭劍池前。", "欲識無由得，相逢豈偶然。", "溪蒲凉雨後，塞雁斷雲邊。", "又作家山計，巴陵有便船。"]'),
('a9f32339-cf45-4e7d-8f55-51998e6b7d85','濬耕雲敬得方丈','顧逢','宋','宋诗','song-poetry','','[]','耕雲老子久相期，同賦山中鶑燕詩。',32,'全唐诗/poet.song.221000.json','["耕雲老子久相期，同賦山中鶑燕詩。", "可惜我來遲數日，牡丹過了有花時。"]'),
('10c62917-26af-4185-8ace-96ab4f0f343c','雜興  其一','顧逢','宋','宋诗','song-poetry','','[]','簷雀啾啾無歇時，幾回啣食餧雛歸。',32,'全唐诗/poet.song.221000.json','["簷雀啾啾無歇時，幾回啣食餧雛歸。", "羽毛長得完全後，子母東西各自飛。"]'),
('ff98ea9c-00fd-4b93-b1bc-f37b46ec1738','雜興  其二','顧逢','宋','宋诗','song-poetry','','[]','彈丸弩矢取飛禽，日日端親望遠林。',32,'全唐诗/poet.song.221000.json','["彈丸弩矢取飛禽，日日端親望遠林。", "百發少曾能一中，可憐輕動殺生心。"]'),
('29fecb65-eabe-46a0-ac24-9d8c6d941700','雜興  其三','顧逢','宋','宋诗','song-poetry','','[]','庭院秋深露氣清，夜窗紉補一燈明。',32,'全唐诗/poet.song.221000.json','["庭院秋深露氣清，夜窗紉補一燈明。", "莫嫌搗練喧人耳，多少貧家無此聲。"]'),
('4747e67d-681a-4d7f-8341-24ec318c2a47','雜興  其四','顧逢','宋','宋诗','song-poetry','','[]','等閑白却少年頭，悟得空時總不愁。',32,'全唐诗/poet.song.221000.json','["等閑白却少年頭，悟得空時總不愁。", "畢竟生來何所有，只如水上一浮漚。"]'),
('62be4f91-6c1f-45a2-81aa-0d2304df3703','雜興  其五','顧逢','宋','宋诗','song-poetry','','[]','我於推步亦留心，造化無踰碧玉經。',32,'全唐诗/poet.song.222000.json','["我於推步亦留心，造化無踰碧玉經。", "何日酒星離命度，且教老眼幾時醒。"]'),
('387b7c3b-21b9-4526-bcf2-894940a1dbac','雜興  其六','顧逢','宋','宋诗','song-poetry','','[]','雅道終爲造物嗔，不教淹屈定教貧。',32,'全唐诗/poet.song.222000.json','["雅道終爲造物嗔，不教淹屈定教貧。", "詩家一脈難相繼，父子得名能幾人。"]'),
('f581cc9d-73c8-4906-bf0a-1b4e6c5db112','雜興  其七','顧逢','宋','宋诗','song-poetry','','[]','異鄉飄泊暫歸來，獨上蕪城望一回。',32,'全唐诗/poet.song.222000.json','["異鄉飄泊暫歸來，獨上蕪城望一回。", "三十年前人已往，樓臺不是舊樓臺。"]'),
('6f6e992b-80b4-441c-8e86-042ca8b01ca5','雲邊偶成  其一','顧逢','宋','宋诗','song-poetry','','[]','彭殤皆定數，萬事轉頭非。',48,'全唐诗/poet.song.222000.json','["彭殤皆定數，萬事轉頭非。", "不悟身如寄，安知死是歸。", "世情趨馬首，道眼識鶉衣。", "堪笑磻磎老，皤然立釣磯。"]'),
('091069e6-6e05-49a5-913a-d7a9e564eb97','雲邊偶成  其二','顧逢','宋','宋诗','song-poetry','','[]','達者由來少，機心肯暫停。',48,'全唐诗/poet.song.222000.json','["達者由來少，機心肯暫停。", "幾家纔富貴，中道又凋零。", "白髮人間寶，黄金水上萍。", "無錢陶靖節，醉眼不曾醒。"]'),
('36d507bd-97b2-47ee-8b42-855b54105dcf','題良玉上人十老詩卷','顧逢','宋','宋诗','song-poetry','','[]','展開此卷便開顔，十老詩無一字閒。',32,'全唐诗/poet.song.222000.json','["展開此卷便開顔，十老詩無一字閒。", "多少工夫難及處，幾年吟得到其間。"]'),
('d48e6aa9-2d2f-4a27-9b93-77c14549d136','題厲竹溪詩稿','顧逢','宋','宋诗','song-poetry','','[]','覓句如禪定，君應入悟門。',48,'全唐诗/poet.song.222000.json','["覓句如禪定，君應入悟門。", "淡中真有味，空處妙難言。", "下字去花草，讀書爲本根。", "莫疑知者少，清氣入乾坤。"]'),
('4144326d-508e-4f21-a96d-f76e0546e27c','題趙蒙齋子山居詩集','顧逢','宋','宋诗','song-poetry','','[]','用書全不覺，地步有餘寬。',48,'全唐诗/poet.song.222000.json','["用書全不覺，地步有餘寬。", "如此自然句，還須識者觀。", "空中圓未易，妙處到尤難。", "草聖更奇特，龍蛇走一般。"]'),
('2f674127-6702-477d-94e9-a4b1f2723d60','斷碑','顧逢','宋','宋诗','song-poetry','','[]','此地何時立，相傳歲月多。',48,'全唐诗/poet.song.222000.json','["此地何時立，相傳歲月多。", "僅留殘刻在，免得後人磨。", "剝處補蒼蘚，斷痕穿細莎。", "欲知前代事，幾度讀來訛。"]'),
('3c6792db-3bda-45d9-8d83-f96accbec3cd','字耕','顧逢','宋','宋诗','song-poetry','','[]','此田無水旱，只在硯池中。',48,'全唐诗/poet.song.222000.json','["此田無水旱，只在硯池中。", "善作諸家體，能成八法功。", "墨痕生夏雨，筆穎熟秋風。", "蓑笠辛勤者，常憂歲不豐。"]'),
('ac688593-978e-42e3-acb4-68b0b639a0f2','牟少卿夫婦七十求詩','顧逢','宋','宋诗','song-poetry','','[]','未當求致仕，知命已先歸。',48,'全唐诗/poet.song.222000.json','["未當求致仕，知命已先歸。", "舉案能同壽，如公者亦稀。", "龐眉天下老，綠髮鏡中希。", "呂望真堪笑，高年尚釣磯。"]'),
('c1e8f95e-745f-44e3-909b-c3de36b307be','觀移碑石有感','顧逢','宋','宋诗','song-poetry','','[]','自古興衰皆有數，移來舊碣作新碑。',32,'全唐诗/poet.song.222000.json','["自古興衰皆有數，移來舊碣作新碑。", "少年會見重磨日，還憶今朝刻字時。"]'),
('cb5ef1ef-0889-4272-94c9-ee9f2447ab3a','詩債','顧逢','宋','宋诗','song-poetry','','[]','詩債未能償得盡，白頭猶自聳吟肩。',32,'全唐诗/poet.song.222000.json','["詩債未能償得盡，白頭猶自聳吟肩。", "如何黑髮人先死，地下修文愛少年。"]'),
('65f462f7-3c53-4834-8c9d-9cbc3e2619ce','閻靜軒先生還吳','顧逢','宋','宋诗','song-poetry','','[]','湖山重作記，當代得名公。',48,'全唐诗/poet.song.222000.json','["湖山重作記，當代得名公。", "多有前時事，皆歸片石中。", "船頭擎白浪，帆腹飽秋風。", "共載還吳□，樽前笑語同。"]'),
('0569456f-7e8a-4059-baf5-485441d08833','送徐閻二遊洞霄','顧逢','宋','宋诗','song-poetry','','[]','洞天三十六，大滌景猶希。',48,'全唐诗/poet.song.222000.json','["洞天三十六，大滌景猶希。", "樓閣仙人宅，雲霞羽士衣。", "風號松虎嘯，雨卷瀑龍飛。", "搗藥禽猶在，時聞出翠微。"]'),
('a4288ac8-9bd2-47a0-8770-a3e362404407','壽呂浩翁端明','顧逢','宋','宋诗','song-poetry','','[]','壽樂長生宴，歡聲滿座頻。',48,'全唐诗/poet.song.222000.json','["壽樂長生宴，歡聲滿座頻。", "華燈留五日，今夕慶千春。", "且作山中相，直誠天上人。", "兒孫列庭下，冰玉更相親。"]'),
('267de51b-acb4-4c5b-aad7-fcbe7c1daaa2','嚴月澗同飲湖邊','顧逢','宋','宋诗','song-poetry','','[]','斗酒復斗酒，高歌山水邊。',48,'全唐诗/poet.song.222000.json','["斗酒復斗酒，高歌山水邊。", "世間無此樂，我輩即神仙。", "狂發花前笑，醉來松下眠。", "行人相偶語，堪作畫圖傳。"]'),
('02dff184-dcfe-44e8-a100-286ec4ecce9c','題山居圖','顧逢','宋','宋诗','song-poetry','','[]','展卷擬曾到，柴門非一灣。',48,'全唐诗/poet.song.222000.json','["展卷擬曾到，柴門非一灣。", "抱琴隨白鶴，坐石看青山。", "隠者有餘樂，貴人無此閒。", "更須添數筆，著我在其間。"]'),
('d4c778cc-9f31-485d-9ac7-4ef2d27e8deb','厲杭雲袖詩見訪','顧逢','宋','宋诗','song-poetry','','[]','此心無所著，閒散似神仙。',48,'全唐诗/poet.song.222000.json','["此心無所著，閒散似神仙。", "每日三餐飯，誰家一熟田。", "健吟輸少俊，起思憶衰年。", "安得同携手，倘徉泉石邊。"]'),
('5c6f53ad-49b0-4490-a58e-c00f5cf0c0f0','雪中同鄭所南訪趙溪梅','顧逢','宋','宋诗','song-poetry','','[]','移宅雖然遠，携筇到兩回。',48,'全唐诗/poet.song.222000.json','["移宅雖然遠，携筇到兩回。", "只知相別去，不道又重來。", "溪鯽和冰煮，鄰醅带雪開。", "詩家堪入畫，滿眼玉樓臺。"]'),
('4d38fbfe-706d-42ee-8748-ccd430e8a0b5','和文本公先生贈許端甫','顧逢','宋','宋诗','song-poetry','','[]','世上無難事，難中獨有詩。',48,'全唐诗/poet.song.222000.json','["世上無難事，難中獨有詩。", "看來都說易，吟到苦方知。", "潭影三年句，蟬聲一字師。", "古人如此癖，刻燭未爲奇。"]'),
('34c9a344-a91a-46a7-86b4-85d528399319','秋晚與許端甫山行','顧逢','宋','宋诗','song-poetry','','[]','山行多妙處，妙在倚筇中。',48,'全唐诗/poet.song.222000.json','["山行多妙處，妙在倚筇中。", "到此興難盡，吟成詩不同。", "松濤鳴絕壑，葉雨下晴空。", "鐘鼓雲邊寺，應知有路通。"]'),
('5f6a3321-5b9d-4c8f-b664-db9d3aad8ade','題善權寺','顧逢','宋','宋诗','song-poetry','','[]','英臺修讀地，舊刻字猶存。',48,'全唐诗/poet.song.222000.json','["英臺修讀地，舊刻字猶存。", "一閣出霄漢，萬松連寺門。", "洞深雲氣冷，池淺鹿行潭。", "山下流來水，風雷日夜喧。"]'),
('cfcb3160-c5ea-44b8-8055-c9ab092f3e97','題虎邱','顧逢','宋','宋诗','song-poetry','','[]','此山雖小衆山尊，半近吳城半近村。',64,'全唐诗/poet.song.222000.json','["此山雖小衆山尊，半近吳城半近村。", "一壑風烟龍窟宅，滿堂巾盔佛兒孫。", "生公說法臺空在，陸羽煎茶井不存。", "喚起幽人無限意，塔鈴獨語到黄昏。"]'),
('7f0822cc-7019-4205-a55e-f021b6a3d5dc','史雲麓先生席上贈顧梅山','顧逢友','宋','宋诗','song-poetry','','[]','五字詩名著少年，端嘉諸老喜相傳。',32,'全唐诗/poet.song.222000.json','["五字詩名著少年，端嘉諸老喜相傳。", "幾回春雨堂中醉，笑拍闌干月正圓。"]'),
('d86d48d3-0ac0-4582-8c17-1e046648390f','顧君際號梅山','顧逢友','宋','宋诗','song-poetry','','[]','數畝蕭疏一徑寬，散飛香雪遍林端。',32,'全唐诗/poet.song.222000.json','["數畝蕭疏一徑寬，散飛香雪遍林端。", "應思處士橋邊路，吟遶橫枝月影寒。"]'),
('9539fc16-5206-43e2-8246-a744800cc0a3','題吳田園雜興詩','顧逢友','宋','宋诗','song-poetry','','[]','一卷田園雜興詩，世人傳誦已多時。',32,'全唐诗/poet.song.222000.json','["一卷田園雜興詩，世人傳誦已多時。", "其中字字有來處，不是箋來不得知。"]'),
('8ba648da-40ab-4b24-8cc8-3ef59ba84c12','御覽所同顧君際檢書','顧逢友','宋','宋诗','song-poetry','','[]','金鎖朱門次第開，萬籤黄冊絕塵埃。',32,'全唐诗/poet.song.222000.json','["金鎖朱門次第開，萬籤黄冊絕塵埃。", "此中亦有先生稿，應是曾經御覽來。"]'),
('5f3d42f6-b717-42ed-978b-fab0d6656f8d','顧君際近集','顧逢友','宋','宋诗','song-poetry','','[]','有詔曾求魏仲先，草堂飛鶴避茶烟。',32,'全唐诗/poet.song.222000.json','["有詔曾求魏仲先，草堂飛鶴避茶烟。", "晚營餒鬼今何限，弱冠詩名六十年。"]'),
('9270fce9-2ff1-4565-a187-7832315187e9','贈梅山顧先生','徐容齋','宋','宋诗','song-poetry','','[]','錢塘詩老顧梅山，鄉校孤吟樂一簞。',64,'全唐诗/poet.song.222000.json','["錢塘詩老顧梅山，鄉校孤吟樂一簞。", "修翼分甘棲宿下，短章功到寂寥間。", "嘔心長吉奚奴錦，染指昌黎白玉丹。", "好句真能換凡骨，覺君春色上蒼顔。"]'),
('ce2b1a12-0880-4329-8c1a-6e31e37a58e9','贈顧梅山','雷苦齋','宋','宋诗','song-poetry','','[]','携手河梁送子卿，池塘春草夢中生。',32,'全唐诗/poet.song.222000.json','["携手河梁送子卿，池塘春草夢中生。", "武林今有梅山老，五字才高筆代耕。"]'),
('9eef39c0-c198-407a-9b23-31bb212b1415','贈館人顧梅山','王素行','宋','宋诗','song-poetry','','[]','前朝相補一官歸，東海僧傳五字詩。',32,'全唐诗/poet.song.222000.json','["前朝相補一官歸，東海僧傳五字詩。", "今日蒲輪徵不去，逢人笑指鬢邊絲。"]'),
('7768f172-211b-472c-afa3-0fd2886d40d4','贈陸自明','王素行','宋','宋诗','song-poetry','','[]','家世本龜蒙，冥搜趣不窮。',48,'全唐诗/poet.song.222000.json','["家世本龜蒙，冥搜趣不窮。", "詩如諸子別，體與老夫同。", "筆影燈窗下，書聲雪屋中。", "此時多用力，下字欲清空。"]'),
('afb7ca1b-b929-4647-ac15-2c8dd720aec0','寄梅山廣文先生','程中山','宋','宋诗','song-poetry','','[]','誰謂梅山耄，胸中耿耿存。',48,'全唐诗/poet.song.222000.json','["誰謂梅山耄，胸中耿耿存。", "五言非小壘，一藝可專門。", "年老人皆敬，名高道自尊。", "羣兒誇疾走，先長不堪論。"]'),
('b4359d0a-d5e9-4366-af19-a8eddb56202f','寄梅山顧君際','家性存','宋','宋诗','song-poetry','','[]','門掩桑輿晝，爐寒郊島灰。',48,'全唐诗/poet.song.222000.json','["門掩桑輿晝，爐寒郊島灰。", "山荒無應下，梅瘦等春開。", "宇宙歸詩眼，功名入酒杯。", "思君三日雨，有夢付潮來。"]'),
('753d5d10-01e8-4442-aa2b-dad9a215754f','題釋英白雲集','陳麟','宋','宋诗','song-poetry','','[]','樹立烟行句，工夫百鍊成。',48,'全唐诗/poet.song.222000.json','["樹立烟行句，工夫百鍊成。", "年方登弱冠，詩已有高名。", "湖上看山色，松邊聽瀑聲。", "無心趨利祿，誰識白雲情。"]'),
('02d3dfb2-bd21-411d-aeb4-b1e125721854','慶南樓居士  其一','周應合','宋','宋诗','song-poetry','','[]','阻壽南樓恰二年，此心恧甚思依然。',32,'全唐诗/poet.song.222000.json','["阻壽南樓恰二年，此心恧甚思依然。", "今朝喜遇稱觴日，袖裏新詩再辦□。"]'),
('0aa93d69-b097-4932-b3d0-953e26ae0ffb','慶南樓居士  其二','周應合','宋','宋诗','song-poetry','','[]','凈土何如樂土真，金蓮開處善根成。',32,'全唐诗/poet.song.222000.json','["凈土何如樂土真，金蓮開處善根成。", "西來孰謂南無佛，今見南樓一佛生。"]'),
('9bd6940a-0920-424a-98b3-2a39ecac62c6','慶南樓居士  其三','周應合','宋','宋诗','song-poetry','','[]','南極垣頭現一星，輝光特著老人名。',32,'全唐诗/poet.song.222000.json','["南極垣頭現一星，輝光特著老人名。", "不隨東壁西庚照，要對南樓夜夜明。"]'),
('99b073ac-7f29-41d3-a542-09c8a4a6db2c','慶南樓居士  其四','周應合','宋','宋诗','song-poetry','','[]','萬古南山聳翠屏，岧嶢上拂斗牛星。',32,'全唐诗/poet.song.222000.json','["萬古南山聳翠屏，岧嶢上拂斗牛星。", "不隨北華西崧見，要對南樓歲歲青。"]'),
('19fd09ec-6004-4e83-b0f2-33fd65db9c30','望江樓','周應合','宋','宋诗','song-poetry','','[]','澄江如練正高秋，一笛吹秋上此樓。',32,'全唐诗/poet.song.222000.json','["澄江如練正高秋，一笛吹秋上此樓。", "有客乘風來縱酒，長歌遠送下灘舟。"]'),
('cd60f065-b7b7-4c67-8afb-9acf52f660b3','句  其一','諶祜','宋','宋诗','song-poetry','','[]','兩表蜀天開日月，三軍漢地出旌旗。',16,'全唐诗/poet.song.222000.json','["兩表蜀天開日月，三軍漢地出旌旗。"]'),
