('7edd7273-9ade-4810-b07f-876abb514b22','句  其一一五','諶祜','宋','宋诗','song-poetry','','[]','笳鼓宮商塞外歸，似此殊勛古難匹。',32,'全唐诗/poet.song.222000.json','["笳鼓宮商塞外歸，似此殊勛古難匹。", "後來渭上朝正月，尚憶祁連冢中骨。"]'),
('7901f103-1549-4471-a70e-b8a1a843b840','句  其一一六','諶祜','宋','宋诗','song-poetry','','[]','後無關險無中士，大夜宜春狐晝舞。',32,'全唐诗/poet.song.222000.json','["後無關險無中士，大夜宜春狐晝舞。", "萬戶千門草綠深，蘆葉捲吹紅日暮。"]'),
('94ee66de-2bbd-4496-8520-576fd8ed07a5','句  其一一七','諶祜','宋','宋诗','song-poetry','','[]','莫將黷武議前朝，今日人思此奇絕。',16,'全唐诗/poet.song.222000.json','["莫將黷武議前朝，今日人思此奇絕。"]'),
('94c68a99-9305-4f2b-abe1-72d6d0b283ea','句  其一一八','諶祜','宋','宋诗','song-poetry','','[]','失道原不在陰陵，放逐義帝知亡形。',32,'全唐诗/poet.song.222000.json','["失道原不在陰陵，放逐義帝知亡形。", "西風所過皆殘滅，不據關險都彭城。"]'),
('bb36beb0-74dd-4fe1-9375-75cfbaeb5ea5','句  其一一九','諶祜','宋','宋诗','song-poetry','','[]','霓裳風秋舞天半，舞到玉花飛石棧。',48,'全唐诗/poet.song.222000.json','["霓裳風秋舞天半，舞到玉花飛石棧。", "三台四輔繞星垣，只一曲中知後患。", "風流天子悟轉圜，不見蜀山橫翠面。"]'),
('67ca6e38-60f2-474d-b7f0-0a43e6059d34','句  其一二○','諶祜','宋','宋诗','song-poetry','','[]','梨園曲譜韶音祕，響入馬嵬花委地。',32,'全唐诗/poet.song.222000.json','["梨園曲譜韶音祕，響入馬嵬花委地。", "開元不再宮不花，天街草綠西風起。"]'),
('2737ff5b-28b1-4037-a8f1-2facd6c62532','道愛堂','姚正子','宋','宋诗','song-poetry','','[]','官稱文母儼如臨，冰鑑何須清白箴。',64,'全唐诗/poet.song.222000.json','["官稱文母儼如臨，冰鑑何須清白箴。", "學道正傳蘧瑗脈，愛人默契武城心。", "簾垂永晝流疏影，琴入薰風奏雅音。", "芹泮未爲無子羽，從知善教入人深。"]'),
('136a2cd6-4842-4e24-91ce-63427597e303','天基節當筵致語口號','方蒙仲','宋','宋诗','song-poetry','','[]','曉日金門氣鬰葱，人間萬里總祥風。',64,'全唐诗/poet.song.222000.json','["曉日金門氣鬰葱，人間萬里總祥風。", "再登况遇三登盛，獨樂何如衆樂同。", "行有玉觴陪邇列，豈無金鑑洞遺忠。", "天恩年壽何分別，盡在簪花舞蹈中。"]'),
('81630f1a-16eb-478f-bd59-55f6577274b5','手種芙蓉入秋盛開  其一','方蒙仲','宋','宋诗','song-poetry','','[]','天然富貴又風流，簇簇湘妃起聚頭。',32,'全唐诗/poet.song.222000.json','["天然富貴又風流，簇簇湘妃起聚頭。", "喚做牡丹何不可，高他一著見深秋。"]'),
('92017e51-6225-45bf-8254-b737da5d5a43','手種芙蓉入秋盛開  其二','方蒙仲','宋','宋诗','song-poetry','','[]','空山寂寂朋游少，爲愛風姿手自栽。',32,'全唐诗/poet.song.222000.json','["空山寂寂朋游少，爲愛風姿手自栽。", "九十日秋猶暖熱，一枝謝又一枝開。"]'),
('4e217635-d8a4-40bd-a4a2-1c948ceb794c','手種芙蓉入秋盛開  其三','方蒙仲','宋','宋诗','song-poetry','','[]','留侯美好婦人然，楚漢功成更得仙。',32,'全唐诗/poet.song.222000.json','["留侯美好婦人然，楚漢功成更得仙。", "疑與拒霜同品格，生來質弱節高堅。"]'),
('ed8a6f0b-031d-4a00-9101-b10e79f568aa','手種芙蓉入秋盛開  其四','方蒙仲','宋','宋诗','song-poetry','','[]','閙藍政自亦不惡，冷局由來未易知。',32,'全唐诗/poet.song.222000.json','["閙藍政自亦不惡，冷局由來未易知。", "開又爭他桃李分，何緣同得芷蘭時。"]'),
('76835584-11d6-4252-a594-eec39bd61e4b','早梅','方蒙仲','宋','宋诗','song-poetry','','[]','尚居闌菊殿，豈占杏桃先。',24,'全唐诗/poet.song.222000.json','["尚居闌菊殿，豈占杏桃先。", "梅自傷遲暮，人猶作早看。"]'),
('a705e0d7-7226-444e-a632-8b665ce7adb1','紅梅','方蒙仲','宋','宋诗','song-poetry','','[]','不但色穠華，更覺香幽迥。',24,'全唐诗/poet.song.222000.json','["不但色穠華，更覺香幽迥。", "笑殺海棠仙，死抱淵材恨。"]'),
('c6c9595a-8860-4283-ad4d-9b018edc2322','消梅','方蒙仲','宋','宋诗','song-poetry','','[]','四月沙河市，青盆雪色鹽。',24,'全唐诗/poet.song.222000.json','["四月沙河市，青盆雪色鹽。", "吳兒甘美飫，可是喜酸鹹。"]'),
('a7b7766b-9a20-411e-a22f-cdd659dcee21','綠蕚梅','方蒙仲','宋','宋诗','song-poetry','','[]','楚楚碧霞裳，輕輕青玉履。',24,'全唐诗/poet.song.222000.json','["楚楚碧霞裳，輕輕青玉履。", "三千一太真，道粧侍天子。"]'),
('92e1186e-9190-428d-94f5-1a2000f60e79','鴛鴦梅','方蒙仲','宋','宋诗','song-poetry','','[]','夜半長生殿，金釵恨最長。',24,'全唐诗/poet.song.222000.json','["夜半長生殿，金釵恨最長。", "分明後身是，環子伴三郎。"]'),
('8c602edd-4d6b-4aeb-9ff2-c9bfafd407b9','層梅','方蒙仲','宋','宋诗','song-poetry','','[]','化工真是巧，玉蘂更層層。',24,'全唐诗/poet.song.222000.json','["化工真是巧，玉蘂更層層。", "若使□□刻，千年猶未成。"]'),
('0d5659e5-8f16-49ec-9095-b8eff14c0111','黄香梅','方蒙仲','宋','宋诗','song-poetry','','[]','香清還耐久，粲粲鏤金葩。',24,'全唐诗/poet.song.222000.json','["香清還耐久，粲粲鏤金葩。", "想見蜂爲蠟，單方採此花。"]'),
('53fb9caf-25f3-4362-91b9-0465b4db5ad5','黄梅','方蒙仲','宋','宋诗','song-poetry','','[]','雙雀啅餘芳，長記來時路。',24,'全唐诗/poet.song.222000.json','["雙雀啅餘芳，長記來時路。", "瞥見金彈丸，相呼遠飛去。"]'),
('4230dbda-60c8-44e4-bf8c-400f55af7476','青梅如豆','方蒙仲','宋','宋诗','song-poetry','','[]','春去雨霏霏，青梅未接時。',24,'全唐诗/poet.song.222000.json','["春去雨霏霏，青梅未接時。", "青青幾萬斛，可惜不充饑。"]'),
('26dc291e-4e50-49c3-a164-f4a6524c4234','鹽梅','方蒙仲','宋','宋诗','song-poetry','','[]','衆口一酸調，佳處在味外。',24,'全唐诗/poet.song.222000.json','["衆口一酸調，佳處在味外。", "忽使水火爭，誰令居鼎鼐。"]'),
('831d65c1-6b9d-4bf4-ab5d-7e64a593eb47','墨梅','方蒙仲','宋','宋诗','song-poetry','','[]','補之敕謚村，簡齋致公輔。',24,'全唐诗/poet.song.222000.json','["補之敕謚村，簡齋致公輔。", "未必畫慚詩，只爲遇不遇。"]'),
('41996c44-24db-44fc-a66d-b6f76eea0c27','兼山會食','方蒙仲','宋','宋诗','song-poetry','','[]','慣從客裏換春秋，愧見平生馬少游。',64,'全唐诗/poet.song.222000.json','["慣從客裏換春秋，愧見平生馬少游。", "懷去僅贏一黄勅，傳呼能得幾蒼頭。", "浮沉冷宦存吾拙，夢寐清言寫我憂。", "屢欲相從奏咸夏，怕驚俚耳又休休。"]'),
('d380e39e-391d-464f-bcfd-3b815ce8b7c3','木犀','方蒙仲','宋','宋诗','song-poetry','','[]','靈根久向月中栽，不信天香墜下來。',32,'全唐诗/poet.song.222000.json','["靈根久向月中栽，不信天香墜下來。", "自是人間與天上，一般種子一齊開。"]'),
('66057ca5-670a-4d4a-a52e-66cc0dfffd49','旋開梅','方蒙仲','宋','宋诗','song-poetry','','[]','鄰笛不須吹，驚噴枝頭雪。',24,'全唐诗/poet.song.222000.json','["鄰笛不須吹，驚噴枝頭雪。", "主人日日來，長見開時節。"]'),
('b0ec5121-bed6-49f0-84c0-6423a6f76088','半開梅','方蒙仲','宋','宋诗','song-poetry','','[]','含情笑不言，政是多情處。',24,'全唐诗/poet.song.222000.json','["含情笑不言，政是多情處。", "參得個中禪，此事嘗分付。"]'),
('c9506986-fdca-4344-8654-d8e90f231f4e','盛開梅  其一','方蒙仲','宋','宋诗','song-poetry','','[]','爛熳不須憐，摇落尤佳致。',24,'全唐诗/poet.song.222000.json','["爛熳不須憐，摇落尤佳致。", "身卧積蘚中，受事天富貴。"]'),
('cd55fb83-38ac-44c6-8194-f9698a26b51f','盛開梅  其二','方蒙仲','宋','宋诗','song-poetry','','[]','十分香色十分清，摇落都從盛處生。',32,'全唐诗/poet.song.222000.json','["十分香色十分清，摇落都從盛處生。", "物理盈虛例如此，世間何事不浮榮。"]'),
('e867cf3a-4c88-472b-ba5a-d61a344965b0','和劉後村梅花百詠  其一','方蒙仲','宋','宋诗','song-poetry','','[]','從來芳事無時歇，雨灑風飄且莫悲。',32,'全唐诗/poet.song.222000.json','["從來芳事無時歇，雨灑風飄且莫悲。", "收拾蒼苔成艾紬，茶山後有放翁詩。"]'),
('8c6e97ab-6ba6-4f31-9ecc-7754ddb662f1','和劉後村梅花百詠  其二','方蒙仲','宋','宋诗','song-poetry','','[]','莫恃千芳勝一蕕，蘭漸芝滫便休休。',32,'全唐诗/poet.song.222000.json','["莫恃千芳勝一蕕，蘭漸芝滫便休休。", "年來蕭艾吁堪怕，賸拾天香置寶篝。"]'),
('730963f8-144d-4a6e-95af-82aba48ae739','和劉後村梅花百詠  其三','方蒙仲','宋','宋诗','song-poetry','','[]','紫府仙人水月英，絕嫌臭穢溷真清。',32,'全唐诗/poet.song.222000.json','["紫府仙人水月英，絕嫌臭穢溷真清。", "玉塵月賦三千斛，一洗人間死鬼兄。"]'),
('44a175f2-5ad9-4ac8-a517-3b2fa7227b2f','和劉後村梅花百詠  其四','方蒙仲','宋','宋诗','song-poetry','','[]','兒時兩頷已生髭，一飽皇皇亟失時。',32,'全唐诗/poet.song.222000.json','["兒時兩頷已生髭，一飽皇皇亟失時。", "索性斷它烟火氣，餐英汲潤當朝炊。"]'),
('ef782109-3cdc-4828-b30f-35987bb18a6a','和劉後村梅花百詠  其五','方蒙仲','宋','宋诗','song-poetry','','[]','參橫月落夢何從，且領清香入盞中。',32,'全唐诗/poet.song.222000.json','["參橫月落夢何從，且領清香入盞中。", "一歲見梅須一醉，梅前有幾百年翁。"]'),
('acfeece1-12eb-4b58-9335-781a9c53798f','和劉後村梅花百詠  其六','方蒙仲','宋','宋诗','song-poetry','','[]','拾遺當日醉於詩，江路尋梅兀似癡。',32,'全唐诗/poet.song.222000.json','["拾遺當日醉於詩，江路尋梅兀似癡。", "花底柳邊真夢事，居然短褐鬢如絲。"]'),
('69ea4428-d93a-41d4-a42a-efa03c8fd78f','和劉後村梅花百詠  其七','方蒙仲','宋','宋诗','song-poetry','','[]','歲歲年年花狀頭，瑶璫瓊佩瑞光浮。',32,'全唐诗/poet.song.222000.json','["歲歲年年花狀頭，瑶璫瓊佩瑞光浮。", "玉螭賞遍三千界，不識珠簾十二樓。"]'),
('60599d5f-9be2-4ad3-8f8a-ccbac71b9fd8','和劉後村梅花百詠  其八','方蒙仲','宋','宋诗','song-poetry','','[]','惆悵庭前三樹株，十年依舊一錐無。',32,'全唐诗/poet.song.222000.json','["惆悵庭前三樹株，十年依舊一錐無。", "從今只作梅生活，底用江頭千木奴。"]'),
('a390dbec-b0d6-4037-a6c0-c9b2bc6c6653','和劉後村梅花百詠  其九','方蒙仲','宋','宋诗','song-poetry','','[]','百萬瑶妃傳粉酥，詩翁列屋世間無。',32,'全唐诗/poet.song.222000.json','["百萬瑶妃傳粉酥，詩翁列屋世間無。", "江南窮相韓熙載，有甚歌姬畫作圖。"]'),
('dd954c2c-d7ba-425a-812c-82990e64ca98','和劉後村梅花百詠  其一○','方蒙仲','宋','宋诗','song-poetry','','[]','凜凜冰清巖壑氣，亭亭玉立廟廊身。',32,'全唐诗/poet.song.222000.json','["凜凜冰清巖壑氣，亭亭玉立廟廊身。", "從前誤把瑶姬比，雌了梅花俗了人。"]'),
('37a7c05a-ab26-4467-a807-9fb42d46906f','和劉後村梅花百詠  其一一','方蒙仲','宋','宋诗','song-poetry','','[]','少陵前僅陸君詩，騷裏居多摭茝蘺。',32,'全唐诗/poet.song.222000.json','["少陵前僅陸君詩，騷裏居多摭茝蘺。", "未必梅花非有待，不妨敲琢古人遺。"]'),
('c815affe-47f6-4d01-891b-f0a787016c58','和劉後村梅花百詠  其一二','方蒙仲','宋','宋诗','song-poetry','','[]','短籬疎竹自周遮，官舍過如野老家。',32,'全唐诗/poet.song.222000.json','["短籬疎竹自周遮，官舍過如野老家。", "不是陋儒太孤絕，自看梅後覺無花。"]'),
('761ee494-95c6-4973-9d94-7ab6879d7b79','和劉後村梅花百詠  其一三','方蒙仲','宋','宋诗','song-poetry','','[]','三年朝露借恩光，賸種江梅作洞房。',32,'全唐诗/poet.song.222000.json','["三年朝露借恩光，賸種江梅作洞房。", "待得百年俱玉雪，冷官亦自有甘棠。"]'),
('b134966e-fe22-4278-ace0-b2f135505e6d','和劉後村梅花百詠  其一四','方蒙仲','宋','宋诗','song-poetry','','[]','一生夢不識愁臺，口吻悲鳴有底哀。',32,'全唐诗/poet.song.222000.json','["一生夢不識愁臺，口吻悲鳴有底哀。", "樹上玉人應冷笑，從今不敢送愁來。"]'),
('3918befc-c4eb-4079-8913-fabf164962d6','和劉後村梅花百詠  其一五','方蒙仲','宋','宋诗','song-poetry','','[]','倚樹靜看成入定，巡簷對語似談空。',32,'全唐诗/poet.song.222000.json','["倚樹靜看成入定，巡簷對語似談空。", "是花是雪都休問，但覺清香滿袖風。"]'),
('2002213c-2016-4d60-bd38-857b2e305aa5','和劉後村梅花百詠  其一六','方蒙仲','宋','宋诗','song-poetry','','[]','青子成時殊苦淡，玉英嚼處更清酸。',32,'全唐诗/poet.song.222000.json','["青子成時殊苦淡，玉英嚼處更清酸。", "自緣芳潔盈腔裏，安肯甘甜轉舌間。"]'),
('b30ea286-4f04-40db-8780-d87852f09557','和劉後村梅花百詠  其一七','方蒙仲','宋','宋诗','song-poetry','','[]','從知枯淡芬芳遠，自古榮華朽腐多。',32,'全唐诗/poet.song.222000.json','["從知枯淡芬芳遠，自古榮華朽腐多。", "且作從容廊廟看，一丘一壑覺如何。"]'),
('94a177e9-37db-4c97-82e0-512874507a0c','和劉後村梅花百詠  其一八','方蒙仲','宋','宋诗','song-poetry','','[]','無人可共倚雕欄，折得橫枝獨自看。',32,'全唐诗/poet.song.222000.json','["無人可共倚雕欄，折得橫枝獨自看。", "梅癖難醫君信否，東陽瘦損少陵酸。"]'),
('41d2e6d2-5afd-4cbf-a8b9-a40647651cd8','和劉後村梅花百詠  其一九','方蒙仲','宋','宋诗','song-poetry','','[]','簾圍玉館愁吟盡，錦藉瑶瓶怕摘殘。',32,'全唐诗/poet.song.222000.json','["簾圍玉館愁吟盡，錦藉瑶瓶怕摘殘。", "姑息梅花詎須爾，山家何處有朱欄。"]'),
('c2867a09-dd9d-47e8-a988-05534b50b239','和劉後村梅花百詠  其二○','方蒙仲','宋','宋诗','song-poetry','','[]','雨霰瀟瀟天地寬，相看島瘦與郊寒。',32,'全唐诗/poet.song.222000.json','["雨霰瀟瀟天地寬，相看島瘦與郊寒。", "埋腰立雪心良苦，擁鼻吟風事大難。"]'),
('4b557102-d2fd-40b0-9c03-bab3bada2674','和劉後村梅花百詠  其二一','方蒙仲','宋','宋诗','song-poetry','','[]','吟人寫物例浮夸，未易形容是此花。',32,'全唐诗/poet.song.222000.json','["吟人寫物例浮夸，未易形容是此花。", "好事休刊和靖集，一聯已足自成家。"]'),
('c5c09902-92e2-45de-ba9b-94c1e18ecb95','和劉後村梅花百詠  其二二','方蒙仲','宋','宋诗','song-poetry','','[]','一氣居然分冷暖，南枝開早北枝遲。',32,'全唐诗/poet.song.222000.json','["一氣居然分冷暖，南枝開早北枝遲。", "都城巧力真堪羨，競買梅花八月時。"]'),
('475c8f8a-d785-4d14-be17-dd937560f250','和劉後村梅花百詠  其二三','方蒙仲','宋','宋诗','song-poetry','','[]','玉羽江蓮美莫當，酴醿縞袂雪爲裳。',32,'全唐诗/poet.song.222000.json','["玉羽江蓮美莫當，酴醿縞袂雪爲裳。", "白之謂白何分別，畢竟還梅是當行。"]'),
('c8b35404-8283-450a-bd50-484d4360b912','和劉後村梅花百詠  其二四','方蒙仲','宋','宋诗','song-poetry','','[]','自是不容加染涴，看來良亦富才情。',32,'全唐诗/poet.song.222000.json','["自是不容加染涴，看來良亦富才情。", "落羌女管聲聲怨，點壽陽粧片片輕。"]'),
('e6452238-f8b2-476e-a10a-da244ffc98fc','和劉後村梅花百詠  其二五','方蒙仲','宋','宋诗','song-poetry','','[]','不把山林換市朝，鮮明自是一時標。',32,'全唐诗/poet.song.222000.json','["不把山林換市朝，鮮明自是一時標。", "便令大冶安能鑄，儻有小山差可招。"]'),
('f820138d-f185-46f7-8ea8-4ba408860fda','和劉後村梅花百詠  其二六','方蒙仲','宋','宋诗','song-poetry','','[]','腸斷當年古吹臺，酒酣欲叫謫仙回。',32,'全唐诗/poet.song.222000.json','["腸斷當年古吹臺，酒酣欲叫謫仙回。", "夜深落月照顔色，端的宮袍入夢來。"]'),
('bc48d1dd-d346-407f-85f8-619a95a46b47','和劉後村梅花百詠  其二七','方蒙仲','宋','宋诗','song-poetry','','[]','智瓊久已乘龍去，留得人間十二枝。',32,'全唐诗/poet.song.222000.json','["智瓊久已乘龍去，留得人間十二枝。", "插向瓦瓶伴孤枕，別無玉骨與冰肌。"]'),
('75824d57-1d2d-4071-b5a4-190a6d02dad6','和劉後村梅花百詠  其二八','方蒙仲','宋','宋诗','song-poetry','','[]','託根豈解媚中璫，採蕨祇當慕首陽。',32,'全唐诗/poet.song.222000.json','["託根豈解媚中璫，採蕨祇當慕首陽。", "未必木天無穢史，豈其枌省盡清郎。"]'),
('2f5b1ccb-0fc4-419f-8861-8ee1dcdc2df4','和劉後村梅花百詠  其二九','方蒙仲','宋','宋诗','song-poetry','','[]','雪兒按瑟侯門妬，玉女偷花帝座嗔。',32,'全唐诗/poet.song.222000.json','["雪兒按瑟侯門妬，玉女偷花帝座嗔。", "彼美人兮笑林薄，風流別是一家春。"]'),
('7c7dbf14-72da-4018-bd6b-2de100fb1397','和劉後村梅花百詠  其三○','方蒙仲','宋','宋诗','song-poetry','','["\u897f\u6e56"]','綵葉如雲觀瑒蘂，金盆照日品桃花。',32,'全唐诗/poet.song.222000.json','["綵葉如雲觀瑒蘂，金盆照日品桃花。", "安知尤物真瓌特，落在西湖處士家。"]'),
('43583c38-bb79-4d55-b019-d0318d4d6e8c','和劉後村梅花百詠  其三一','方蒙仲','宋','宋诗','song-poetry','','[]','煮木石餐多藥竈，斷葷羶氣獨茶鐺。',32,'全唐诗/poet.song.222000.json','["煮木石餐多藥竈，斷葷羶氣獨茶鐺。", "詩人自合長年瘦，底事梅花更瘦生。"]'),
('893885e9-78e0-431c-82b2-aaf2162800b1','和劉後村梅花百詠  其三二','方蒙仲','宋','宋诗','song-poetry','','[]','刻玉琱瓊費盡工，待看佳實綠陰中。',32,'全唐诗/poet.song.222000.json','["刻玉琱瓊費盡工，待看佳實綠陰中。", "早推花作羣芳首，誰道梨爲百果宗。"]'),
('4228935c-fafe-4d4d-af8c-034340284d19','和劉後村梅花百詠  其三三','方蒙仲','宋','宋诗','song-poetry','','[]','梅嘆知音少曠夔，政須我輩與伸眉。',32,'全唐诗/poet.song.222000.json','["梅嘆知音少曠夔，政須我輩與伸眉。", "逋仙詩勝多多許，咀嚼無令一字遺。"]'),
('aa229a75-19ad-49b4-b7be-3e15a314848d','和劉後村梅花百詠  其三四','方蒙仲','宋','宋诗','song-poetry','','[]','行吟坐想午忘饑，剔盡青燈睡失時。',32,'全唐诗/poet.song.222000.json','["行吟坐想午忘饑，剔盡青燈睡失時。", "唐宋以來多作者，姑爲漢魏補梅詩。"]'),
('66021145-e9c8-48a0-8a7a-87bde040312f','和劉後村梅花百詠  其三五','方蒙仲','宋','宋诗','song-poetry','','[]','驛處徘徊磴處緣，任教人喚作梅顛。',32,'全唐诗/poet.song.222000.json','["驛處徘徊磴處緣，任教人喚作梅顛。", "賒它陸凱二十字，喚起杜陵三百年。"]'),
('fb3093af-0df0-491e-a5bb-721849733fa5','和劉後村梅花百詠  其三六','方蒙仲','宋','宋诗','song-poetry','','[]','純是沉檀和乳麝，許多珠瓅間金塊。',32,'全唐诗/poet.song.222000.json','["純是沉檀和乳麝，許多珠瓅間金塊。", "素娥親擣攤成片，玉帝閑遊撒下來。"]'),
('5d9bcb50-f9ef-4476-8f91-c83a676cc100','和劉後村梅花百詠  其三七','方蒙仲','宋','宋诗','song-poetry','','[]','十分正色白爲難，眼底紅黄總熱瞞。',32,'全唐诗/poet.song.222000.json','["十分正色白爲難，眼底紅黄總熱瞞。", "安得雲英揮玉杵，臈餘爲合返魂丹。"]'),
('acba4674-467b-4ff2-95ba-85cf4fcd2ac2','和劉後村梅花百詠  其三八','方蒙仲','宋','宋诗','song-poetry','','[]','雪破白時驚臈早，雨肥紅處已春歸。',32,'全唐诗/poet.song.222000.json','["雪破白時驚臈早，雨肥紅處已春歸。", "到頭不識東皇面，看盡蜂黄蝶粉飛。"]'),
('516ef491-289b-48a1-91a4-5e170d035d38','和劉後村梅花百詠  其三九','方蒙仲','宋','宋诗','song-poetry','','[]','最堪避世有牆東，細別薰蕕鼻觀中。',32,'全唐诗/poet.song.222000.json','["最堪避世有牆東，細別薰蕕鼻觀中。", "商皓芝香真可老，陶朱銅臭敢稱公。"]'),
('8a984b40-8b46-48dc-b1a5-d0f4064b206d','和劉後村梅花百詠  其四○','方蒙仲','宋','宋诗','song-poetry','','[]','儼然盛服對嚴賓，肯向花中作素臣。',32,'全唐诗/poet.song.222000.json','["儼然盛服對嚴賓，肯向花中作素臣。", "映徹九泉明一世，清言須讓晉諸人。"]'),
('cd774383-554f-4d3f-a7af-c3aa3b9d6f10','和劉後村梅花百詠  其四一','方蒙仲','宋','宋诗','song-poetry','','[]','夜色朝光兩莫知，樹間但見白差差。',32,'全唐诗/poet.song.222000.json','["夜色朝光兩莫知，樹間但見白差差。", "江南到處名姝少，一律前村雪裏詞。"]'),
('31921d18-c22c-4504-bade-9272caedc15f','和劉後村梅花百詠  其四二','方蒙仲','宋','宋诗','song-poetry','','[]','百年老樹半邊枯，衆卉難攀覺太孤。',32,'全唐诗/poet.song.222000.json','["百年老樹半邊枯，衆卉難攀覺太孤。", "欲進素馨交茉莉，柰渠浪蘂欠根株。"]'),
('ce024d09-3f14-4b5a-9f25-45b15630896a','和劉後村梅花百詠  其四三','方蒙仲','宋','宋诗','song-poetry','','[]','鷗社同盟交最久，兔園授簡事堪悲。',32,'全唐诗/poet.song.222000.json','["鷗社同盟交最久，兔園授簡事堪悲。", "開元才子多佳句，借向宮人笛裏吹。"]'),
('a480e214-a95a-4909-bcc2-ec214d3d90d8','和劉後村梅花百詠  其四四','方蒙仲','宋','宋诗','song-poetry','','[]','童黄安足名天下，太白常疑在世間。',32,'全唐诗/poet.song.222000.json','["童黄安足名天下，太白常疑在世間。", "生縱不陪振鷺列，死猶可葬伯鸞山。"]'),
('6f0fefb1-f371-4935-9b37-04fd84df3a25','和劉後村梅花百詠  其四五','方蒙仲','宋','宋诗','song-poetry','','[]','方見橫斜忽亂飛，噫其造物未昌時。',32,'全唐诗/poet.song.222000.json','["方見橫斜忽亂飛，噫其造物未昌時。", "點衣片片皆詩料，愛惜移時不敢吹。"]'),
('a32a5b2a-6bac-4291-89c6-97bc57b2b6d7','和劉後村梅花百詠  其四六','方蒙仲','宋','宋诗','song-poetry','','[]','後村畫卷四方來，輸與先生作襪材。',32,'全唐诗/poet.song.222000.json','["後村畫卷四方來，輸與先生作襪材。", "貌就寒林差易事，玉堂雲霧欠人裁。"]'),
('4b4e48a8-72cc-4605-93fe-afaede81669e','和劉後村梅花百詠  其四七','方蒙仲','宋','宋诗','song-poetry','','[]','香臭難逃萬古評，白黄安得一般清。',32,'全唐诗/poet.song.222000.json','["香臭難逃萬古評，白黄安得一般清。", "好看玉樹臨風立，羞殺金蓮帖地行。"]'),
('85ac2c91-7254-4f48-b7f5-bcbf0c13479c','和劉後村梅花百詠  其四八','方蒙仲','宋','宋诗','song-poetry','','[]','此花清絕畏人知，間許吟人嚥入脾。',32,'全唐诗/poet.song.222000.json','["此花清絕畏人知，間許吟人嚥入脾。", "嚥去居然佳句少，誰云臭腐可神奇。"]'),
('4b6b87e0-3125-4ed7-b092-46fc050eaf22','和劉後村梅花百詠  其四九','方蒙仲','宋','宋诗','song-poetry','','[]','含章遺跡杳難詳，漢苑唐都更可傷。',32,'全唐诗/poet.song.222000.json','["含章遺跡杳難詳，漢苑唐都更可傷。", "說與詩人莫嘲詠，梅花眼見幾興亡。"]'),
('8a4826a2-129a-46c6-8256-d397ff597393','和劉後村梅花百詠  其五○','方蒙仲','宋','宋诗','song-poetry','','[]','癡兒安得妄評彈，剛道空花用處難。',32,'全唐诗/poet.song.222000.json','["癡兒安得妄評彈，剛道空花用處難。", "最是香能蠲客醉，更如玉可滅人瘢。"]'),
('0699a778-3eef-49ec-9926-8c88597cd25e','和劉後村梅花百詠  其五一','方蒙仲','宋','宋诗','song-poetry','','[]','香奩陋體實堪哀，慙謝諸公費輓推。',32,'全唐诗/poet.song.222000.json','["香奩陋體實堪哀，慙謝諸公費輓推。", "鐵石心腸元作賦，浮華詎足定人才。"]'),
('a12afb58-0d1a-4195-a043-05af7fbc629a','和劉後村梅花百詠  其五二','方蒙仲','宋','宋诗','song-poetry','','[]','惜花心固凄凉矣，遶樹身猶矍鑠哉。',32,'全唐诗/poet.song.222000.json','["惜花心固凄凉矣，遶樹身猶矍鑠哉。", "且莫怨嗟難可口，和羹事只係時來。"]'),
('d40f7860-4ffc-4cbf-b792-5279c33e5c26','和劉後村梅花百詠  其五三','方蒙仲','宋','宋诗','song-poetry','','[]','老天機軸無停手，忙織千葩染萬紅。',32,'全唐诗/poet.song.222000.json','["老天機軸無停手，忙織千葩染萬紅。", "惟有一冬閑歲月，梅花專局不分功。"]'),
('9af88e8e-75cf-448d-97a0-39f03a1f23c2','和劉後村梅花百詠  其五四','方蒙仲','宋','宋诗','song-poetry','','[]','窗明不寐夜寥寥，恍惚珠幢跨玉橋。',32,'全唐诗/poet.song.222000.json','["窗明不寐夜寥寥，恍惚珠幢跨玉橋。", "冷掾久嚴紅妓禁，綵鸞莫誤喚文簫。"]'),
('ee424fa3-e81e-46c6-963c-1ce8ff689353','和劉後村梅花百詠  其五五','方蒙仲','宋','宋诗','song-poetry','','[]','樂事賞心誰不有，可人勝士古來難。',32,'全唐诗/poet.song.222000.json','["樂事賞心誰不有，可人勝士古來難。", "樽前莫怪同游少，恐被梅花白眼看。"]'),
('c13f6e75-e7d4-46b0-bd2e-38b09958075a','和劉後村梅花百詠  其五六','方蒙仲','宋','宋诗','song-poetry','','[]','千頃瓊田徒手得，連雲綵閣一朝成。',32,'全唐诗/poet.song.222000.json','["千頃瓊田徒手得，連雲綵閣一朝成。", "平生富貴梅時健，肯作窮人凍餓聲。"]'),
('e670bdb7-07e2-4de9-b735-2ae66fea7fab','和劉後村梅花百詠  其五七','方蒙仲','宋','宋诗','song-poetry','','[]','禹錫當年出省臺，玄都花謝轉生哀。',32,'全唐诗/poet.song.222000.json','["禹錫當年出省臺，玄都花謝轉生哀。", "梅花不涉春風事，看取先生幾度來。"]'),
('cf731d57-5916-4dd6-915c-c2e108c1b529','和劉後村梅花百詠  其五八','方蒙仲','宋','宋诗','song-poetry','','[]','一生不信有金芝，今歲庭前碧玉枝。',32,'全唐诗/poet.song.222000.json','["一生不信有金芝，今歲庭前碧玉枝。", "只恨相看無一語，怳如月下對桓伊。"]'),
('08b49176-df36-4eee-a6bb-cf8f651560b6','和劉後村梅花百詠  其五九','方蒙仲','宋','宋诗','song-poetry','','[]','沸鼎乾坤塵未消，椒菌雜襲少高標。',32,'全唐诗/poet.song.222000.json','["沸鼎乾坤塵未消，椒菌雜襲少高標。", "君王曾夢商巖否，此物差堪與燮調。"]'),
('41418540-597f-4351-9064-bd684371eb4c','和劉後村梅花百詠  其六○','方蒙仲','宋','宋诗','song-poetry','','[]','簡齋絕句天爲笑，旋到調羹鼎伴來。',32,'全唐诗/poet.song.222000.json','["簡齋絕句天爲笑，旋到調羹鼎伴來。", "只合拜梅爲座主，畫梅且爾况真梅。"]'),
('109bc380-24c3-452c-b1d7-f254b56f0b60','和劉後村梅花百詠  其六一','方蒙仲','宋','宋诗','song-poetry','','[]','少豪放出旅枯槎，歸橐垂垂返海涯。',32,'全唐诗/poet.song.222000.json','["少豪放出旅枯槎，歸橐垂垂返海涯。", "叔子諸公自佳耳，關人心事只梅花。"]'),
('15549660-2d5b-4846-9940-218a8595bcfb','和劉後村梅花百詠  其六二','方蒙仲','宋','宋诗','song-poetry','','[]','溪北溪南雪跨懸，瓊樓玉宇照庭前。',32,'全唐诗/poet.song.222000.json','["溪北溪南雪跨懸，瓊樓玉宇照庭前。", "萸坪竹館辛夷塢，肯與王維賭輞川。"]'),
('5ed248a8-aae4-4e1f-85e4-8c170b28fb87','和劉後村梅花百詠  其六三','方蒙仲','宋','宋诗','song-poetry','','[]','披衣徙倚天方曙，秉燭吟哦夜忽中。',32,'全唐诗/poet.song.222000.json','["披衣徙倚天方曙，秉燭吟哦夜忽中。", "不是被他驅使得，愛他意政與人同。"]'),
('14619f1d-c2af-4993-9201-a69389328afd','和劉後村梅花百詠  其六四','方蒙仲','宋','宋诗','song-poetry','','[]','心事芬芬流品勝，一生清友是梅臞。',32,'全唐诗/poet.song.222000.json','["心事芬芬流品勝，一生清友是梅臞。", "可憐介甫交游盡，歲晚鍾山進二俞。"]'),
('68393bde-3c18-4f5e-98cd-373709ef027f','和劉後村梅花百詠  其六五','方蒙仲','宋','宋诗','song-poetry','','[]','懷中黄敕墨猶新，曾尾羣賢步玉津。',32,'全唐诗/poet.song.222000.json','["懷中黄敕墨猶新，曾尾羣賢步玉津。", "惆悵看花成昨夢，大輸今歲賞梅人。"]'),
