('c5999c1d-73cf-41bf-927d-860ff1e2edf4','見梅','方蒙仲','宋','宋诗','song-poetry','','[]','平生空四海，紅紫委如塵。',24,'全唐诗/poet.song.222000.json','["平生空四海，紅紫委如塵。", "梅處生新敬，寧非具限人。"]'),
('f9a3dc85-4521-4fe2-a678-a91249093f23','愛梅','方蒙仲','宋','宋诗','song-poetry','','[]','謾言同一嗜，世盡愛梅人。',24,'全唐诗/poet.song.222000.json','["謾言同一嗜，世盡愛梅人。", "亦有行歌者，腰鐮采作薪。"]'),
('7884dbe2-0bf6-48d6-8ff9-6586067705c6','笑坐金鞍歌落梅','方蒙仲','宋','宋诗','song-poetry','','[]','謫仙豪放甚，小妾伴金鞍。',24,'全唐诗/poet.song.222000.json','["謫仙豪放甚，小妾伴金鞍。", "未可將窮相，詩人一例看。"]'),
('4f393499-0502-4c40-928a-aa28d9d6e840','問梅','方蒙仲','宋','宋诗','song-poetry','','[]','夜月玉堂前，春風紫蓋邊。',24,'全唐诗/poet.song.222000.json','["夜月玉堂前，春風紫蓋邊。", "想君都看破，寧與我周旋。"]'),
('aac9cd59-c1fe-47fa-b510-087ff5fc3ef0','梅答','方蒙仲','宋','宋诗','song-poetry','','[]','人言是金屋，我見即柴門。',24,'全唐诗/poet.song.222000.json','["人言是金屋，我見即柴門。", "但認安身處，區區何足論。"]'),
('3fae4d3c-cb18-4357-aa0f-aa388bd75ba3','折梅','方蒙仲','宋','宋诗','song-poetry','','[]','看梅如看畫，由我不由他。',24,'全唐诗/poet.song.222000.json','["看梅如看畫，由我不由他。", "千樹江頭少，一枝瓶裏多。"]'),
('74d3b13d-e7ee-4802-ac0d-ccae478ffa9f','此君室  其一','方蒙仲','宋','宋诗','song-poetry','','[]','人兮吾與游，竹兮吾與俱。',24,'全唐诗/poet.song.222000.json','["人兮吾與游，竹兮吾與俱。", "世濁此獨清，室小自有餘。"]'),
('aa817df2-dec2-4ee1-8eb9-0fb402a4b2b3','此君室  其二','方蒙仲','宋','宋诗','song-poetry','','[]','環堵未可輕，足稽天下事。',24,'全唐诗/poet.song.222000.json','["環堵未可輕，足稽天下事。", "何必晉諸賢，自是周二子。"]'),
('ee2d77fa-622a-4234-83b3-8bf61967f352','此君室  其三','方蒙仲','宋','宋诗','song-poetry','','[]','爲嫌太孤高，邂逅松梅友。',24,'全唐诗/poet.song.222000.json','["爲嫌太孤高，邂逅松梅友。", "忽與竹同評，是遇知音不。"]'),
('c76b4f0b-790f-4c9b-884c-3af4cf3d9af7','此君室  其四','方蒙仲','宋','宋诗','song-poetry','','[]','清福造物慳，數竿自超俗。',24,'全唐诗/poet.song.222000.json','["清福造物慳，數竿自超俗。", "苦覓渭濱封，萬此豈有足。"]'),
('b4076bbb-6687-4120-a8a6-ea40ee64cc20','此君室  其五','方蒙仲','宋','宋诗','song-poetry','','[]','輩行有後先，志節無今古。',24,'全唐诗/poet.song.222000.json','["輩行有後先，志節無今古。", "君看錦䙀兒，楚楚已可數。"]'),
('f64b627a-c7b7-460b-ada3-a114496602e2','此君室  其六','方蒙仲','宋','宋诗','song-poetry','','[]','不入閙園林，雅媚佳山水。',24,'全唐诗/poet.song.222000.json','["不入閙園林，雅媚佳山水。", "君子亦黨乎，賢者後樂此。"]'),
('db8ecf2b-9748-46a7-89f3-7af5776ead95','此君室  其七','方蒙仲','宋','宋诗','song-poetry','','[]','直節立人懦，清標爽吾惛。',24,'全唐诗/poet.song.222000.json','["直節立人懦，清標爽吾惛。", "豈不益友哉，人中田承君。"]'),
('eb83617d-258c-4ce2-8a55-2994e4ff6e99','此君室  其八','方蒙仲','宋','宋诗','song-poetry','','[]','風來聲清圓，月明影婆娑。',24,'全唐诗/poet.song.222000.json','["風來聲清圓，月明影婆娑。", "挺挺巖壑姿，時亦嫵媚何。"]'),
('f94b15e3-9e33-4425-9f6b-eb4387c77478','此君室  其九','方蒙仲','宋','宋诗','song-poetry','','[]','滔滔天地間，非我安知我。',24,'全唐诗/poet.song.222000.json','["滔滔天地間，非我安知我。", "大兒王子猷，小兒文與可。"]'),
('a5583bc5-d6cd-4327-85dc-20545791267b','此君室  其一○','方蒙仲','宋','宋诗','song-poetry','','[]','泛菊秋始佳，愛蓮夏方娛。',24,'全唐诗/poet.song.222000.json','["泛菊秋始佳，愛蓮夏方娛。", "不如交此君，清興無時無。"]'),
('5a445ce2-1cfc-466b-9132-589ca76a0042','此君室  其一一','方蒙仲','宋','宋诗','song-poetry','','[]','僕也環堵人，公也鈞天居。',24,'全唐诗/poet.song.222000.json','["僕也環堵人，公也鈞天居。", "本出元子下，豈必竹馬餘。"]'),
('61820add-471e-41f7-b41e-b622afbddcb0','此君室  其一二','方蒙仲','宋','宋诗','song-poetry','','[]','先生嘯諾餘，嘗欲訪青士。',24,'全唐诗/poet.song.222000.json','["先生嘯諾餘，嘗欲訪青士。", "門生可舉輿，不必命兒子。"]'),
('56801001-aebf-486b-a766-626d5293b7be','此君室  其一三','方蒙仲','宋','宋诗','song-poetry','','[]','此士黨有挾，則不與之友。',24,'全唐诗/poet.song.222000.json','["此士黨有挾，則不與之友。", "持此問秋崖，一笑見頷不。"]'),
('ecd84690-9384-488f-9478-30ae5200fe3f','此君室  其一四','方蒙仲','宋','宋诗','song-poetry','','[]','橫厨先玉盤，羶葷鄙哉俗。',24,'全唐诗/poet.song.222000.json','["橫厨先玉盤，羶葷鄙哉俗。", "竹謂高將軍，汝手汙吾足。"]'),
('62d871f6-5bea-44e2-826d-92016ade1fb3','此君室  其一五','方蒙仲','宋','宋诗','song-poetry','','[]','矯矯不可羈，一節足千古。',24,'全唐诗/poet.song.222000.json','["矯矯不可羈，一節足千古。", "桃李閙漫山，歲寒誰汝數。"]'),
('d889e649-57f0-4b2e-b8ea-5f6a509184a7','此君室  其一六','方蒙仲','宋','宋诗','song-poetry','','[]','千載蘭亭人，所樂在山水。',24,'全唐诗/poet.song.222000.json','["千載蘭亭人，所樂在山水。", "等閑一笑間，風度乃如此。"]'),
('5d161630-f0f4-4c5b-a168-40dec4bd3f26','此君室  其一七','方蒙仲','宋','宋诗','song-poetry','','[]','柳以柔故重，棗以弱故惛。',24,'全唐诗/poet.song.222000.json','["柳以柔故重，棗以弱故惛。", "凜凜首陽人，何頼東皇君。"]'),
('bc6bae8e-a25e-4281-89fc-c4298d1cf143','此君室  其一八','方蒙仲','宋','宋诗','song-poetry','','[]','不因排根人，安得茲婆娑。',24,'全唐诗/poet.song.222000.json','["不因排根人，安得茲婆娑。", "請賦淇奧詩，但恐居亡何。"]'),
('789553f1-e779-440c-94e2-bfb444797203','此君室  其一九','方蒙仲','宋','宋诗','song-poetry','','[]','問卿自用卿，爲我寧作我。',24,'全唐诗/poet.song.222000.json','["問卿自用卿，爲我寧作我。", "道莫强項爲，本見折腰可。"]'),
('5ba053fc-d963-4d43-b610-4eda72709432','此君室  其二○','方蒙仲','宋','宋诗','song-poetry','','[]','風簷誦新句，絕勝絲竹娛。',24,'全唐诗/poet.song.222000.json','["風簷誦新句，絕勝絲竹娛。", "此竹古來有，此詩今時無。"]'),
('d32f631e-7c0e-4d95-af3c-7905fc2f0535','采芹亭  其一','方蒙仲','宋','宋诗','song-poetry','','[]','百年亭子一朝新，三舍先生遇拂塵。',32,'全唐诗/poet.song.222000.json','["百年亭子一朝新，三舍先生遇拂塵。", "城裏看花多處所，此中只待采芹人。"]'),
('180de9b4-2899-4676-82bf-b710732eb379','采芹亭  其二','方蒙仲','宋','宋诗','song-poetry','','["\u897f\u6e56"]','歎息西湖湖上峯，幾人看得少從容。',32,'全唐诗/poet.song.222000.json','["歎息西湖湖上峯，幾人看得少從容。", "任他萬馬羣中走，還我閑身伴雨龍。"]'),
('82440c60-6eb3-4b3e-b2ab-1b22a113c83b','采芹亭  其三','方蒙仲','宋','宋诗','song-poetry','','[]','宜月宜風還宜雪，煙雨冥濛景更宜。',32,'全唐诗/poet.song.222000.json','["宜月宜風還宜雪，煙雨冥濛景更宜。", "說與客來休剝啄，先生長是倚闌時。"]'),
('5bfc0f84-eca0-4360-9080-0b49dcf45856','采芹亭  其四','方蒙仲','宋','宋诗','song-poetry','','[]','便好時時具小槎，徧遊水北水南涯。',32,'全唐诗/poet.song.222000.json','["便好時時具小槎，徧遊水北水南涯。", "游時要揀山深處，恐有山人處士家。"]'),
('e24b6fe6-7e6d-4a74-bdc0-ccd4d65fafcb','采芹亭  其五','方蒙仲','宋','宋诗','song-poetry','','[]','年時桂子例先開，新歲芙蓉手自栽。',32,'全唐诗/poet.song.222000.json','["年時桂子例先開，新歲芙蓉手自栽。", "不惜一春風雨過，許多好事待秋來。"]'),
('8aa8aae6-2705-40c0-98cd-90e579faa7c4','采芹亭  其六','方蒙仲','宋','宋诗','song-poetry','','[]','短帽輕衫亦復家，前村後陌柳初花。',32,'全唐诗/poet.song.222000.json','["短帽輕衫亦復家，前村後陌柳初花。", "不須多學舞雩興，隨分春光管領些。"]'),
('2039b063-3fd9-41ad-8a92-78abe16f2b30','采芹亭  其七','方蒙仲','宋','宋诗','song-poetry','','[]','洲墅樓前眼界新，杜園池館更迴縈。',32,'全唐诗/poet.song.222000.json','["洲墅樓前眼界新，杜園池館更迴縈。", "是中一景偏真率，覺得溪山却渾成。"]'),
('2c5a2eea-ed83-44fa-9820-c713f6ae1125','采芹亭  其八','方蒙仲','宋','宋诗','song-poetry','','[]','側畔頹垣且莫支，也須別相草堂基。',32,'全唐诗/poet.song.222000.json','["側畔頹垣且莫支，也須別相草堂基。", "要知風月無邊處，不著亭臺更自奇。"]'),
('a6481d64-fffc-4306-97f3-39c5060bcc69','采芹亭  其九','方蒙仲','宋','宋诗','song-poetry','','[]','老山代出買山錢，更貼前頭碧玉環。',32,'全唐诗/poet.song.222000.json','["老山代出買山錢，更貼前頭碧玉環。", "報答風光無一句，不知更看幾州山。"]'),
('62962747-73ea-410d-bebd-3b35e3ad10bb','采芹亭  其一○','方蒙仲','宋','宋诗','song-poetry','','[]','眼中光景幾回新，無限英雄一窖塵。',32,'全唐诗/poet.song.222000.json','["眼中光景幾回新，無限英雄一窖塵。", "但說百年亭已老，不知曾有百年人。"]'),
('9582362d-431c-4a15-84d7-093efd36fceb','采芹亭  其一一','方蒙仲','宋','宋诗','song-poetry','','[]','人道西南三數峯，雖云峭拔欠雍容。',32,'全唐诗/poet.song.222000.json','["人道西南三數峯，雖云峭拔欠雍容。", "嗟哉偃孌要何用，却學爲蛇羞作龍。"]'),
('72410202-6022-4584-ac3e-7065b3d8d82c','采芹亭  其一二','方蒙仲','宋','宋诗','song-poetry','','[]','野性於人投合少，惟山差與意中宜。',32,'全唐诗/poet.song.222000.json','["野性於人投合少，惟山差與意中宜。", "專留一榻爲渠下，絕似陳蕃見穉時。"]'),
('9dea7e01-4844-4e18-8c3a-4172677811ac','采芹亭  其一三','方蒙仲','宋','宋诗','song-poetry','','[]','武夷山頂足仙槎，欲徃從之天一涯。',32,'全唐诗/poet.song.222000.json','["武夷山頂足仙槎，欲徃從之天一涯。", "具喚小舟酹三諫，向來我祖是通家。"]'),
('d8a71896-2846-4977-8d16-72c4cd738e38','采芹亭  其一四','方蒙仲','宋','宋诗','song-poetry','','[]','屈指夫容次第開，典衣去買海棠栽。',32,'全唐诗/poet.song.222000.json','["屈指夫容次第開，典衣去買海棠栽。", "溪邊堪插荷花否，便可四時携酒來。"]'),
('b5d3e61d-f36b-44db-a9f3-91297e0b479e','采芹亭  其一五','方蒙仲','宋','宋诗','song-poetry','','["\u897f\u6e56"]','此中小住自爲佳，無柰看山眼欲花。',32,'全唐诗/poet.song.222000.json','["此中小住自爲佳，無柰看山眼欲花。", "把作西湖風物看，不爭多否也爭些。"]'),
('fe6bf8a1-3f6a-470c-9ab1-f202c54bfb7a','采芹亭  其一六','方蒙仲','宋','宋诗','song-poetry','','["\u897f\u6e56"]','見說西湖又一新，小樓高閣巧相縈。',32,'全唐诗/poet.song.222000.json','["見說西湖又一新，小樓高閣巧相縈。", "江山何待人粧點，堪笑吳兒不老成。"]'),
('89270e3b-cc9d-4038-8008-b7ce83f0252e','采芹亭  其一七','方蒙仲','宋','宋诗','song-poetry','','[]','屋老知非一木支，待時勝似有鎡基。',32,'全唐诗/poet.song.222000.json','["屋老知非一木支，待時勝似有鎡基。", "安知好事無來者，幻出新亭愈崛奇。"]'),
('ce8547fe-02c6-4fe2-8680-faf6e4ce51a3','采芹亭  其一八','方蒙仲','宋','宋诗','song-poetry','','[]','覓得廣文沽酒錢，便須歸隠四山環。',32,'全唐诗/poet.song.222000.json','["覓得廣文沽酒錢，便須歸隠四山環。", "豈無半幅鵝溪絹，貌取亭前一带山。"]'),
('2d03197e-07e4-43ef-b09a-1a69634d4619','采芹亭  其一九','方蒙仲','宋','宋诗','song-poetry','','[]','佳處知音若不多，似將俚耳聽雲和。',32,'全唐诗/poet.song.222000.json','["佳處知音若不多，似將俚耳聽雲和。", "溪山無自不掛眼，亭乎亭乎如汝何。"]'),
('55c02438-1e2c-43a2-88ab-6b4a56d20b39','學廳桃符  其一','方蒙仲','宋','宋诗','song-poetry','','[]','頭臚如此可何官，習氣居然簡冊間。',64,'全唐诗/poet.song.222000.json','["頭臚如此可何官，習氣居然簡冊間。", "似有宿緣吾士友，差强人意此溪山。", "青衿笑語非爲冷，黄卷工夫可得閑。", "珍重相期進明德，莫教具素有慚顔。"]'),
('428844e8-7291-47fd-b676-28d7a5cd648a','學廳桃符  其二','方蒙仲','宋','宋诗','song-poetry','','[]','非民非吏一閑身，倏忽空山又見春。',64,'全唐诗/poet.song.222000.json','["非民非吏一閑身，倏忽空山又見春。", "明月清風終歲有，浮雲蒼物幾番新。", "不知世有彈冠事，但願門多挾冊人。", "疇昔東嘉子徐子，勉旃儻可嗣芳塵。"]'),
('c119273f-4dde-4dc0-98ba-6b169b32852b','學廳桃符  其三','方蒙仲','宋','宋诗','song-poetry','','[]','而立之年不啻過，十分減盡少年豪。',64,'全唐诗/poet.song.222000.json','["而立之年不啻過，十分減盡少年豪。", "喫它官飯如何穩，着了朝衫說甚高。", "勤向溪山供日課，賸栽花木足年勞。", "客來不周嗟無肉，菜本新添數百窠。"]'),
('929ca38c-cf47-4d5c-aa99-baab5efb53e6','壽徐意一參政  其一','方蒙仲','宋','宋诗','song-poetry','','[]','紅雲朵裏紫霞杯，敕使今朝四度來。',32,'全唐诗/poet.song.222000.json','["紅雲朵裏紫霞杯，敕使今朝四度來。", "意一堂中開九袠，太微星裏現三台。"]'),
('c0231151-20e8-463f-bc33-9f611ec56ef7','壽徐意一參政  其二','方蒙仲','宋','宋诗','song-poetry','','[]','呂氏早皆期正獻，范家晚竟相忠宣。',32,'全唐诗/poet.song.222000.json','["呂氏早皆期正獻，范家晚竟相忠宣。", "不成二十年聲望，久坐難兄一舊氈。"]'),
('842fb15c-239e-438d-b52b-677d1eaf493f','壽徐意一參政  其三','方蒙仲','宋','宋诗','song-poetry','','[]','衆芳摇落此何時，爭看江梅拆一枝。',32,'全唐诗/poet.song.222000.json','["衆芳摇落此何時，爭看江梅拆一枝。", "相去小春纔四日，調羹消息不應遲。"]'),
('9af59ba0-fef7-4efd-90d6-fdac54263e0a','壽徐意一參政  其四','方蒙仲','宋','宋诗','song-poetry','','[]','黄花晚節香愈勁，老圃秋容景更奇。',32,'全唐诗/poet.song.222000.json','["黄花晚節香愈勁，老圃秋容景更奇。", "欲侑瓣香無好語，且偷忠獻一聯詩。"]'),
('1c08617f-2e29-4fa8-ba5e-f365e41a3f05','熙春朝陽','方蒙仲','宋','宋诗','song-poetry','','[]','山占樵城最上頭，眼前歷歷記曾遊。',64,'全唐诗/poet.song.222000.json','["山占樵城最上頭，眼前歷歷記曾遊。", "古來不少二千石，海內今誰第一流。", "小隊未妨需隙暇，大書已覺振巖幽。", "於今幸際豐登日，滿泛松觥賸句酬。"]'),
('5a3a1fe3-5284-495f-b595-537810d061c2','信筆','方蒙仲','宋','宋诗','song-poetry','','[]','筆床茶竈答蛩吟，摇落秋風萬里心。',32,'全唐诗/poet.song.222000.json','["筆床茶竈答蛩吟，摇落秋風萬里心。", "白髮蕭蕭酒初醒，一龕鐙火四更深。"]'),
('d7a094ce-4e61-4f19-87e7-b8ef0f81e39f','贈點易婁君復','王義山','宋','宋诗','song-poetry','','[]','伏羲先天易，其初一太極。',96,'全唐诗/poet.song.222000.json','["伏羲先天易，其初一太極。", "太極生陰陽，陰陽各有畫。", "濂溪何所傳，妙得於太極。", "極上作一圈，一圈只是白。", "伏羲已爲贅，大小圈更十。", "不知果何意，多是祖河圖。", "所以負笭者，敢於嗤吾徒。", "願與易相忘，圈點畫皆無。"]'),
('3229f6fe-7432-44bd-9f6a-8e14562505ec','郊壇奏告禮成口號','王義山','宋','宋诗','song-poetry','','[]','夜半宮中響珮環，小臣髣彿見天顔。',64,'全唐诗/poet.song.222000.json','["夜半宮中響珮環，小臣髣彿見天顔。", "月星明穊齋壇上，穹昊鑒臨方寸間。", "五色雲祥開景運，兩行露立綴仙班。", "皇心自與天心合，萬姓歡呼法駕還。"]'),
('0fd94c25-df06-4a5b-b442-4335a3d50317','挽度宗  其一','王義山','宋','宋诗','song-poetry','','[]','道隆兼德厚，民庶樂難名。',48,'全唐诗/poet.song.222000.json','["道隆兼德厚，民庶樂難名。", "宮合府中一，身修天下平。", "有條皆快活，無事不清明。", "長樂天將晚，如聞問寢聲。"]'),
('48d469b5-2989-448e-92c2-e9ebc18331a3','挽度宗  其二','王義山','宋','宋诗','song-poetry','','[]','建隆成帝業，肇造宋乾坤。',48,'全唐诗/poet.song.222000.json','["建隆成帝業，肇造宋乾坤。", "永穆昔傳子，慈元今抱孫。", "羹牆有堯在，謨訓即湯存。", "血染攀髯淚，哀纏徹九閽。"]'),
('db979a27-0896-49cb-8af0-587c0b088928','挽遂初陳尚書','王義山','宋','宋诗','song-poetry','','[]','到得咸淳國步艱，幾回抗疏動天顔。',64,'全唐诗/poet.song.222000.json','["到得咸淳國步艱，幾回抗疏動天顔。", "丈夫那肯死牖下，餘子從教活草間。", "有分珠厓終着去，無心白髮望生還。", "故人目斷暮雲處，霧雨濛濛山外山。"]'),
('f178b5d1-855b-44c3-9105-0bc74ac479df','寄題黄靜齋','王義山','宋','宋诗','song-poetry','','[]','靜中樂處是琴書，此樂輸君二美俱。',64,'全唐诗/poet.song.222000.json','["靜中樂處是琴書，此樂輸君二美俱。", "明鏡無塵佛關捩，內丹養火夜工夫。", "梅花窗下參同契，翠草庭前太極圖。", "探得黄庭真訣了，不須更看養生符。"]'),
('59673283-b023-48a4-b428-c1f64b817c73','題僧南浦詩卷','王義山','宋','宋诗','song-poetry','','[]','齊己諸人殻已蟬，不傳詩印又多年。',64,'全唐诗/poet.song.222000.json','["齊己諸人殻已蟬，不傳詩印又多年。", "水萍粘瓦終無用，風絮沾泥不是禪。", "誰識鹹酸居味外，要追風雅到刪前。", "讀師句法真家數，拂拂松陰響澗泉。"]'),
('d14bc714-f6d4-4f9a-9d1f-f34d54c27997','齋居雜興  其一','王義山','宋','宋诗','song-poetry','','[]','道理須從妙處尋，靜中觀物了吾心。',64,'全唐诗/poet.song.222000.json','["道理須從妙處尋，靜中觀物了吾心。", "一時俯仰成朝暮，萬變紛紜幾古今。", "蠖屈蛇伸非矯揉，鳶飛魚躍自升沉。", "莫隨名利相牽引，方寸膠舟泥寸涔。"]'),
('1ed259cc-2f8c-46ef-a67a-f96b5ece8fb5','齋居雜興  其二','王義山','宋','宋诗','song-poetry','','[]','一身自有一乾坤，拍拍陽和稟得淳。',64,'全唐诗/poet.song.222000.json','["一身自有一乾坤，拍拍陽和稟得淳。", "詩思已隨春意動，夜衾不怕曉寒新。", "未應雲谷成遼邈，常把滄洲入想因。", "覓句看書無箇事，清泉可飲便非貧。"]'),
('bfb8172a-079e-46b8-8815-5aa8b4b27964','齋居雜興  其三','王義山','宋','宋诗','song-poetry','','[]','山水之中足可娛，田園數畝任荒蕪。',64,'全唐诗/poet.song.222000.json','["山水之中足可娛，田園數畝任荒蕪。", "論交惟有詩知己，把酒相忘月與吾。", "秀石漱泉清可硯，孤峯掛日景堪圖。", "可憐直節如松勁，剛被秦封作大夫。"]'),
('d56c2924-8d84-4f60-ab35-d8b973a57c9f','齋居雜興  其四','王義山','宋','宋诗','song-poetry','','[]','木曳斜暉抹淡紅，薄窗微惹一簾風。',64,'全唐诗/poet.song.222000.json','["木曳斜暉抹淡紅，薄窗微惹一簾風。", "水如銀樣浸新月，山聳翠標撐碧穹。", "天爲騷人開眼界，酒尋好句入杯中。", "興來點檢江山罷，頃刻陰晴笑化工。"]'),
('1a5c6afa-51ad-4972-b060-534b0ccb6649','齋居雜興  其五','王義山','宋','宋诗','song-poetry','','[]','天根分上下，月窟幾晴陰。',48,'全唐诗/poet.song.222000.json','["天根分上下，月窟幾晴陰。", "老樹吹來古，流芳直到今。", "四時花不斷，一本理尤深。", "記得南軒說，要觀生物心。"]'),
('0ed5bfe5-0767-4e54-bcc2-d5af378a5561','西湖即席和冷泉亭韻','王義山','宋','宋诗','song-poetry','','["\u897f\u6e56"]','石溜寒泉山色陰，我來本不爲花尋。',64,'全唐诗/poet.song.222000.json','["石溜寒泉山色陰，我來本不爲花尋。", "願分一滴清泉水，盡滌平生塵垢心。", "虛洞迂風橋畔過，急灘瀉月水痕深。", "襟期難與凡人道，好和滄浪濯足吟。"]'),
('d0a1b2a8-f4ff-4afd-849c-200fb76849da','書永嘉嘉禾驛','王義山','宋','宋诗','song-poetry','','[]','老來倦躋攀，悠悠憩山側。',144,'全唐诗/poet.song.222000.json','["老來倦躋攀，悠悠憩山側。", "層嵐軼穹霓，紆縈困行客。", "崖傾覺嶮巇，徑曲盤險迫。", "石老枕雲根，橋橫界野色。", "海嶠吞暝暉，松標掛辰極。", "殘煙罩成幄，長波曳如帛。", "天際鳥知還，溪澗魚自適。", "幾忘物無我，慮淡意常寂。", "泛觀穹壤間，天亦局於迹。", "榮華忽彫枯，俯仰逃今昔。", "傾羲倏再旦，急軌等寄驛。", "愚公果何爲，老且欲移石。"]'),
('82e98711-8265-4a8e-bb64-766dfb470387','題鄭氏義門','王義山','宋','宋诗','song-poetry','','[]','說到義時須割截，如何氣象得渾全。',64,'全唐诗/poet.song.222000.json','["說到義時須割截，如何氣象得渾全。", "合非真合皆人者，生與俱生有性焉。", "友是弟兄常底事，仁於父子本然天。", "大書忍字果何意，便覺流於矯揉偏。"]'),
('b6afa217-071f-459f-b6f0-3aeb2f5219c0','讀晚唐詩有感','王義山','宋','宋诗','song-poetry','','[]','學詩莫學晚唐詩，學得晚唐非盛時。',32,'全唐诗/poet.song.222000.json','["學詩莫學晚唐詩，學得晚唐非盛時。", "願把鳧鷖和既醉，翻騰韻語作今詩。"]'),
('ba125f70-1b99-41f8-b217-2b64516fc2f6','觀海潮','王義山','宋','宋诗','song-poetry','','[]','憑誰撼得海門開，疑是神兵著力推。',64,'全唐诗/poet.song.222000.json','["憑誰撼得海門開，疑是神兵著力推。", "霎地起來銀一線，駕山卷起雪千堆。", "列江畫舫浮天去，幾片紅旗逐浪回。", "畢竟神京鍾王氣，海神豈爲子胥來。"]'),
('ce5e892d-117b-4d3d-b721-e3ff53db0ee0','題嚴子陵釣臺','王義山','宋','宋诗','song-poetry','','[]','吹起炎劉已冷灰，先生功不上雲臺。',32,'全唐诗/poet.song.222000.json','["吹起炎劉已冷灰，先生功不上雲臺。", "當初同學還何事，畢竟曾經講較來。"]'),
('27621748-7f4f-452e-933c-d40dfd482288','挽賈平章生母  其一','王義山','宋','宋诗','song-poetry','','[]','有子萬事足，相與樂湖山。',48,'全唐诗/poet.song.222000.json','["有子萬事足，相與樂湖山。", "花逕板輿穩，萱庭衮服斑。", "軻親榮鼎養，魯國忽喪還。", "元氣極之母，生賢奠兩間。"]'),
('6dc2beea-f676-49e3-ac15-67839b2a54da','挽賈平章生母  其二','王義山','宋','宋诗','song-poetry','','[]','修齡踰八袠，五福萃諸身。',48,'全唐诗/poet.song.222000.json','["修齡踰八袠，五福萃諸身。", "翟服儀容舊，鸞綾謚誥新。", "艱難共淮楚，褒表建齊秦。", "曾聽呼兒道，仲華能笑人。"]');
